 40→const TOOL_RESULT_COMPACTION_RATIO_PERCENT: usize = 75;
 41→const PREEMPTIVE_OVERFLOW_RATIO_PERCENT: usize = 90;
 42→const TOOL_RESULT_COMPACTION_PLACEHOLDER: &str =
 43→    "[tool result compacted to preserve context budget]";
 44→const TOOL_RESULT_COMPACTION_MIN_BYTES: usize = 200;
