 98→impl UsageAccumulator {
 99→    pub(crate) fn record_request(&mut self, usage: Usage) {
100→        self.total.saturating_add_assign(&usage);
101→        self.request = usage;
102→    }
103→
104→    pub(crate) fn total(&self) -> Usage {
105→        self.total.clone()
106→    }
107→
108→    pub(crate) fn request(&self) -> Usage {
109→        self.request.clone()
110→    }
111→}
