116→/// Events emitted during the agent run.
117→#[derive(Debug, Clone)]
118→pub enum RunnerEvent {
119→    /// LLM is processing (show a "thinking" indicator).
120→    Thinking,
121→    /// LLM finished thinking (hide the indicator).
122→    ThinkingDone,
123→    ToolCallStart {
124→        id: String,
125→        name: String,
126→        arguments: serde_json::Value,
127→    },
128→    ToolCallEnd {
129→        id: String,
130→        name: String,
131→        success: bool,
132→        error: Option<String>,
133→        result: Option<serde_json::Value>,
134→    },
135→    /// LLM returned reasoning/status text alongside tool calls.
136→    ThinkingText(String),
137→    TextDelta(String),
138→    Iteration(usize),
139→    SubAgentStart {
140→        task: String,
141→        model: String,
142→        depth: u64,
143→    },
144→    SubAgentEnd {
145→        task: String,
146→        model: String,
147→        depth: u64,
148→        iterations: usize,
149→        tool_calls_made: usize,
150→    },
151→    /// A transient LLM error occurred and the runner will retry.
152→    RetryingAfterError {
153→        error: String,
154→        delay_ms: u64,
155→    },
156→    /// The model stopped without tool calls but iteration budget remains;
157→    /// the runner is automatically re-prompting.
158→    AutoContinue {
159→        iteration: usize,
160→        max_iterations: usize,
161→    },
162→    /// A tool call was rejected by pre-dispatch schema validation before the
163→    /// tool's `execute` method ran. Used in place of the usual
164→    /// `ToolCallStart`/`ToolCallEnd` pair for rejected calls so the UI does
165→    /// not render a misleading "executing" status for a call that never
166→    /// actually executed.
167→    ToolCallRejected {
168→        id: String,
169→        name: String,
170→        arguments: serde_json::Value,
171→        error: String,
172→    },
173→    /// The loop detector fired after observing repeated identical tool-call
174→    /// failures. `stage` is 1 for the nudge/directive intervention and 2 for
175→    /// the stronger tool-stripping escalation (see issue #658).
176→    LoopInterventionFired {
177→        stage: u8,
178→        tool_name: String,
179→    },
180→}
