316→fn legacy_public_tool_alias(name: &str) -> Option<&str> {
317→    name.strip_suffix("_wasm").filter(|base| !base.is_empty())
318→}
319→
320→fn resolve_tool_lookup<'a>(
321→    tools: &crate::tool_registry::ToolRegistry,
322→    name: &'a str,
323→) -> (
324→    Option<std::sync::Arc<dyn crate::tool_registry::AgentTool>>,
325→    Cow<'a, str>,
326→) {
327→    if let Some(alias) = legacy_public_tool_alias(name)
328→        && let Some(tool) = tools.get(alias)
329→    {
330→        return (Some(tool), Cow::Owned(alias.to_string()));
331→    }
332→
333→    (tools.get(name), Cow::Borrowed(name))
334→}
