412→fn streaming_tool_call_message_content(
413→    last_answer_text: &mut String,
414→    accumulated_text: &str,
415→    accumulated_reasoning: &str,
416→) -> Option<String> {
417→    if !accumulated_reasoning.is_empty() {
418→        Some(accumulated_reasoning.to_string())
419→    } else if !accumulated_text.is_empty() {
420→        last_answer_text.clear();
421→        last_answer_text.push_str(accumulated_text);
422→        Some(accumulated_text.to_string())
423→    } else {
424→        None
425→    }
426→}
