428→#[must_use]
429→fn estimate_prompt_text_tokens(text: &str) -> usize {
430→    let trimmed = text.trim();
431→    if trimmed.is_empty() {
432→        return 0;
433→    }
434→    trimmed.len().div_ceil(4).max(1)
435→}
436→
437→#[must_use]
438→fn estimate_message_tokens(message: &ChatMessage) -> usize {
439→    estimate_prompt_text_tokens(&message.to_openai_value().to_string())
440→}
441→
442→#[must_use]
443→fn estimate_prompt_tokens(messages: &[ChatMessage], tool_schemas: &[serde_json::Value]) -> usize {
444→    let message_tokens: usize = messages.iter().map(estimate_message_tokens).sum();
445→    let tool_tokens: usize = tool_schemas
446→        .iter()
447→        .map(|schema| estimate_prompt_text_tokens(&schema.to_string()))
448→        .sum();
449→    message_tokens.saturating_add(tool_tokens)
450→}
451→
452→#[must_use]
453→fn has_tool_result_messages(messages: &[ChatMessage]) -> bool {
454→    messages
455→        .iter()
456→        .any(|message| matches!(message, ChatMessage::Tool { .. }))
457→}
458→
459→fn compact_tool_results_newest_first_in_place(
460→    messages: &mut [ChatMessage],
461→    tokens_needed: usize,
462→) -> usize {
463→    if tokens_needed == 0 {
464→        return 0;
465→    }
466→
467→    let mut reduced = 0;
468→    for message in messages.iter_mut().rev() {
469→        if reduced >= tokens_needed {
470→            break;
471→        }
472→
473→        let ChatMessage::Tool {
474→            tool_call_id,
475→            content,
476→        } = message
477→        else {
478→            continue;
479→        };
480→        if content == TOOL_RESULT_COMPACTION_PLACEHOLDER
481→            || content.len() < TOOL_RESULT_COMPACTION_MIN_BYTES
482→        {
483→            continue;
484→        }
485→
486→        let tool_call_id = tool_call_id.clone();
487→        let original = content.clone();
488→        let before = estimate_message_tokens(&ChatMessage::tool(&tool_call_id, &original));
489→        *content = TOOL_RESULT_COMPACTION_PLACEHOLDER.to_string();
490→        let after = estimate_message_tokens(&ChatMessage::tool(
491→            &tool_call_id,
492→            TOOL_RESULT_COMPACTION_PLACEHOLDER,
493→        ));
494→        let saved = before.saturating_sub(after);
495→        if saved == 0 {
496→            *content = original;
497→            continue;
498→        }
499→
500→        reduced = reduced.saturating_add(saved);
501→    }
502→
503→    reduced
504→}
505→
506→fn enforce_tool_result_context_budget(
507→    messages: &mut [ChatMessage],
508→    tool_schemas: &[serde_json::Value],
509→    context_window: u32,
510→) -> Result<(), AgentRunError> {
511→    let context_window = context_window as usize;
512→    if context_window == 0 || !has_tool_result_messages(messages) {
513→        return Ok(());
514→    }
515→
516→    let compaction_budget =
517→        context_window.saturating_mul(TOOL_RESULT_COMPACTION_RATIO_PERCENT) / 100;
518→    let overflow_budget = context_window.saturating_mul(PREEMPTIVE_OVERFLOW_RATIO_PERCENT) / 100;
519→    let current_tokens = estimate_prompt_tokens(messages, tool_schemas);
520→
521→    if current_tokens > compaction_budget {
522→        let needed = current_tokens.saturating_sub(compaction_budget);
523→        let reduced = compact_tool_results_newest_first_in_place(messages, needed);
524→        tracing::debug!(
525→            current_tokens,
526→            compaction_budget,
527→            overflow_budget,
528→            needed,
529→            reduced,
530→            "compacted newest tool results to preserve prompt budget"
531→        );
532→    }
533→
534→    let post_compaction_tokens = estimate_prompt_tokens(messages, tool_schemas);
535→    if post_compaction_tokens > overflow_budget {
536→        return Err(AgentRunError::ContextWindowExceeded(format!(
537→            "preemptive context overflow: estimated prompt size {post_compaction_tokens} tokens exceeds {overflow_budget} token budget after tool-result compaction"
538→        )));
539→    }
540→
541→    Ok(())
542→}
