544→fn channel_binding_from_tool_context(
545→    session_key: &str,
546→    tool_context: Option<&serde_json::Value>,
547→) -> Option<ChannelBinding> {
548→    let channel_value = tool_context.and_then(|ctx| ctx.get("_channel"))?;
549→    match serde_json::from_value(channel_value.clone()) {
550→        Ok(binding) => Some(binding),
551→        Err(error) => {
552→            warn!(
553→                error = %error,
554→                session = %session_key,
555→                "failed to parse _channel tool context for hooks; ignoring channel provenance"
556→            );
557→            None
558→        },
559→    }
560→}
