391→    async fn resolve_session_key_for_run(
392→        active_runs_by_session: &Arc<RwLock<HashMap<String, String>>>,
393→        run_id: Option<&str>,
394→        session_key: Option<&str>,
395→    ) -> Option<String> {
396→        if let Some(key) = session_key {
397→            return Some(key.to_string());
398→        }
399→        let target_run_id = run_id?;
400→        active_runs_by_session
401→            .read()
402→            .await
403→            .iter()
404→            .find_map(|(key, active_run_id)| (active_run_id == target_run_id).then(|| key.clone()))
405→    }
