429→    async fn persist_partial_assistant_on_abort(
430→        &self,
431→        session_key: &str,
432→    ) -> Option<(Value, Option<u32>)> {
433→        let partial = self
434→            .active_partial_assistant
435→            .write()
436→            .await
437→            .remove(session_key)?;
438→        if !partial.has_visible_content() {
439→            return None;
440→        }
441→
442→        let partial_message = partial.to_persisted_message();
443→        let partial_value = partial_message.to_value();
444→        let mut message_index = None;
445→
446→        if let Err(e) = self.session_store.append(session_key, &partial_value).await {
447→            warn!(session = %session_key, error = %e, "failed to persist aborted partial assistant message");
448→            return Some((partial_value, None));
449→        }
450→
451→        match self.session_store.count(session_key).await {
452→            Ok(count) => {
453→                self.session_metadata.touch(session_key, count).await;
454→                message_index = Some(count.saturating_sub(1));
455→            },
456→            Err(e) => {
457→                warn!(session = %session_key, error = %e, "failed to count session after persisting aborted partial assistant message");
458→            },
459→        }
460→
461→        Some((partial_value, message_index))
462→    }
463→
464→    /// Resolve a provider from session metadata, history, or first registered.
465→    async fn resolve_provider(
466→        &self,
467→        session_key: &str,
468→        history: &[Value],
469→    ) -> error::Result<Arc<dyn moltis_agents::model::LlmProvider>> {
470→        let reg = self.providers.read().await;
471→        let session_model = self
472→            .session_metadata
473→            .get(session_key)
474→            .await
475→            .and_then(|e| e.model.clone());
476→        let history_model = history
477→            .iter()
478→            .rev()
479→            .find_map(|m| m.get("model").and_then(|v| v.as_str()).map(String::from));
480→        let model_id = session_model.or(history_model);
481→
482→        model_id
483→            .and_then(|id| reg.get(&id))
484→            .or_else(|| reg.first())
485→            .ok_or_else(|| error::Error::message("no LLM providers configured"))
486→    }
487→
488→    /// Resolve the active session key for a connection.
489→    async fn session_key_for(&self, conn_id: Option<&str>) -> String {
490→        if let Some(cid) = conn_id
491→            && let Some(key) = self.state.active_session_key(cid).await
492→        {
493→            return key;
494→        }
495→        "main".to_string()
496→    }
497→
498→    /// Resolve the effective session key for chat operations.
499→    ///
500→    /// Precedence is:
501→    /// 1. Internal `_session_key` overrides used by runtime-owned callers.
502→    /// 2. Public `sessionKey` / `session_key` request parameters.
503→    /// 3. Connection-scoped active session derived from `_conn_id`.
504→    /// 4. The default `"main"` session.
505→    async fn resolve_session_key_from_params(&self, params: &Value) -> String {
506→        if let Some(session_key) = params
507→            .get("_session_key")
508→            .and_then(|v| v.as_str())
509→            .filter(|v| !v.is_empty())
510→        {
511→            return session_key.to_string();
512→        }
513→        if let Some(session_key) = params
514→            .get("sessionKey")
515→            .or_else(|| params.get("session_key"))
516→            .and_then(|v| v.as_str())
517→            .filter(|v| !v.is_empty())
518→        {
519→            return session_key.to_string();
520→        }
521→        let conn_id = params.get("_conn_id").and_then(|v| v.as_str());
522→        self.session_key_for(conn_id).await
523→    }
524→
525→    /// Resolve the project context prompt section for a session.
526→    async fn resolve_project_context(
527→        &self,
528→        session_key: &str,
529→        conn_id: Option<&str>,
530→    ) -> Option<String> {
531→        let project_id = if let Some(cid) = conn_id {
532→            self.state.active_project_id(cid).await
533→        } else {
534→            None
535→        };
536→        // Also check session metadata for project binding (async path).
537→        let project_id = match project_id {
538→            Some(pid) => Some(pid),
539→            None => self
540→                .session_metadata
541→                .get(session_key)
542→                .await
543→                .and_then(|e| e.project_id),
544→        };
545→
546→        let pid = project_id?;
547→        let val = self
548→            .state
549→            .project_service()
550→            .get(serde_json::json!({"id": pid}))
551→            .await
552→            .ok()?;
553→        let dir = val.get("directory").and_then(|v| v.as_str())?;
554→        let files = match moltis_projects::context::load_context_files(Path::new(dir)) {
555→            Ok(f) => f,
556→            Err(e) => {
557→                warn!("failed to load project context: {e}");
558→                return None;
559→            },
560→        };
561→        let project: moltis_projects::Project = serde_json::from_value(val.clone()).ok()?;
562→        let worktree_dir = self
563→            .session_metadata
564→            .get(session_key)
565→            .await
566→            .and_then(|e| e.worktree_branch)
567→            .and_then(|_| {
568→                let wt_path = Path::new(dir).join(".moltis-worktrees").join(session_key);
569→                if wt_path.exists() {
570→                    Some(wt_path)
571→                } else {
572→                    None
573→                }
574→            });
575→        let ctx = moltis_projects::ProjectContext {
576→            project,
577→            context_files: files,
578→            worktree_dir,
579→        };
580→        Some(ctx.to_prompt_section())
581→    }
582→}
