28→/// Extract the `Services` bundle from a GraphQL resolver context.
29→///
30→/// Usage: `let s = services!(ctx);`
31→/// Then call methods directly: `s.session.list().await`
32→#[macro_export]
33→macro_rules! services {
34→    ($ctx:expr) => {{
35→        &$ctx
36→            .data::<std::sync::Arc<$crate::context::GqlContext>>()?
37→            .services
38→    }};
39→}
