110→    /// Config change events.
111→    async fn config_changed(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
112→        event_stream(ctx, "config").await
113→    }
114→
115→    /// System presence change events.
116→    async fn presence_changed(
117→        &self,
118→        ctx: &Context<'_>,
119→    ) -> Result<impl Stream<Item = GenericEvent>> {
120→        event_stream(ctx, "presence").await
121→    }
122→
123→    /// Metrics update events.
124→    async fn metrics_update(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
125→        event_stream(ctx, "metrics.update").await
126→    }
127→
128→    /// Update availability events.
129→    async fn update_available(
130→        &self,
131→        ctx: &Context<'_>,
132→    ) -> Result<impl Stream<Item = GenericEvent>> {
133→        event_stream(ctx, "update.available").await
134→    }
135→
136→    /// Voice config changed events.
137→    async fn voice_config_changed(
138→        &self,
139→        ctx: &Context<'_>,
140→    ) -> Result<impl Stream<Item = GenericEvent>> {
141→        event_stream(ctx, "voice.config.changed").await
142→    }
143→
144→    /// Skills install progress events.
145→    async fn skills_install_progress(
146→        &self,
147→        ctx: &Context<'_>,
148→    ) -> Result<impl Stream<Item = GenericEvent>> {
149→        event_stream(ctx, "skills.install.progress").await
150→    }
151→
152→    /// All events (unfiltered, for debugging).
153→    async fn all_events(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
154→        let c = ctx.data::<Arc<GqlContext>>()?;
155→        let mut rx = c.subscribe();
156→        Ok(async_stream::stream! {
157→            while let Ok((_event_name, payload)) = rx.recv().await {
158→                yield GenericEvent::from(payload);
159→            }
160→        })
