  1→//! Bridge between MCP tools and the agent tool registry.
  2→//!
  3→//! Adapts [`McpToolBridge`](moltis_mcp::tool_bridge::McpToolBridge) (mcp crate)
  4→//! to [`AgentTool`] (agents crate) and provides sync logic to register MCP tools
  5→//! into a [`ToolRegistry`].
  6→
  7→use std::sync::Arc;
  8→
  9→use {async_trait::async_trait, tokio::sync::RwLock};
 10→
