 15→    moltis_agents::tool_registry::{AgentTool, ToolRegistry},
 16→    moltis_mcp::tool_bridge::{McpAgentTool, McpToolBridge},
 17→};
 18→
 19→/// Thin adapter that implements `AgentTool` (agents crate) by delegating to
 20→/// `McpToolBridge` which implements `McpAgentTool` (mcp crate).
 21→pub struct McpToolAdapter(pub McpToolBridge);
 22→
 23→#[async_trait]
 24→impl AgentTool for McpToolAdapter {
 25→    fn name(&self) -> &str {
 26→        McpAgentTool::name(&self.0)
 27→    }
 28→
 29→    fn description(&self) -> &str {
 30→        McpAgentTool::description(&self.0)
 31→    }
 32→
 33→    fn parameters_schema(&self) -> serde_json::Value {
 34→        McpAgentTool::parameters_schema(&self.0)
 35→    }
 36→
 37→    async fn execute(&self, params: serde_json::Value) -> anyhow::Result<serde_json::Value> {
 38→        McpAgentTool::execute(&self.0, params)
 39→            .await
 40→            .map_err(anyhow::Error::from)
 41→    }
 42→}
