134→
135→    async fn emit_validation_progress(
136→        &self,
137→        provider: &str,
138→        request_id: Option<&str>,
139→        phase: &str,
140→        mut extra: Map<String, Value>,
141→    ) {
142→        let Some(broadcaster) = self.broadcaster.get() else {
