158→
159→    fn queue_registry_rebuild(&self, provider_name: &str, reason: &'static str) {
160→        let rebuild_seq = self.registry_rebuild_seq.fetch_add(1, Ordering::SeqCst) + 1;
161→        let latest_seq = Arc::clone(&self.registry_rebuild_seq);
162→        let registry = Arc::clone(&self.registry);
163→        let config = Arc::clone(&self.config);
164→        let key_store = self.key_store.clone();
165→        let env_overrides = self.env_overrides.clone();
166→        let provider_name = provider_name.to_string();
167→
168→        tokio::spawn(async move {
169→            let started = std::time::Instant::now();
170→            info!(
171→                provider = %provider_name,
172→                reason,
173→                rebuild_seq,
174→                "provider registry async rebuild started"
175→            );
176→
177→            let effective = {
178→                let base = config.lock().unwrap_or_else(|e| e.into_inner()).clone();
179→                config_with_saved_keys(&base, &key_store, &[])
180→            };
181→
182→            let new_registry = match tokio::task::spawn_blocking(move || {
183→                ProviderRegistry::from_env_with_config_and_overrides(&effective, &env_overrides)
184→            })
185→            .await
186→            {
187→                Ok(registry) => registry,
188→                Err(error) => {
189→                    warn!(
190→                        provider = %provider_name,
191→                        reason,
192→                        rebuild_seq,
193→                        error = %error,
194→                        "provider registry async rebuild worker failed"
195→                    );
196→                    return;
197→                },
198→            };
199→
200→            let current_seq = latest_seq.load(Ordering::Acquire);
201→            if rebuild_seq != current_seq {
202→                info!(
203→                    provider = %provider_name,
204→                    reason,
205→                    rebuild_seq,
206→                    latest_seq = current_seq,
207→                    elapsed_ms = started.elapsed().as_millis(),
208→                    "provider registry async rebuild skipped as stale"
209→                );
210→                return;
211→            }
212→
213→            let provider_summary = new_registry.provider_summary();
214→            let model_count = new_registry.list_models().len();
215→            let mut reg = registry.write().await;
216→            *reg = new_registry;
217→            info!(
218→                provider = %provider_name,
219→                reason,
220→                rebuild_seq,
221→                provider_summary = %provider_summary,
222→                models = model_count,
223→                elapsed_ms = started.elapsed().as_millis(),
224→                "provider registry async rebuild finished"
225→            );
226→        });
227→    }
228→
229→    fn config_snapshot(&self) -> ProvidersConfig {
230→        self.config
231→            .lock()
232→            .unwrap_or_else(|e| e.into_inner())
233→            .clone()
234→    }
235→
236→    fn set_provider_enabled_in_memory(&self, provider: &str, enabled: bool) {
237→        let mut cfg = self.config.lock().unwrap_or_else(|e| e.into_inner());
238→        cfg.providers
239→            .entry(provider.to_string())
240→            .or_default()
241→            .enabled = enabled;
242→    }
243→
244→    fn is_provider_configured(
245→        &self,
246→        provider: &KnownProvider,
247→        active_config: &ProvidersConfig,
248→    ) -> bool {
249→        // Disabled providers (by offered allowlist or explicit enabled=false)
250→        // should not show as configured, except subscription-backed OAuth
251→        // providers with valid local tokens.
252→        if !active_config.is_enabled(provider.name) {
253→            let subscription_with_tokens =
254→                matches!(provider.name, "openai-codex" | "github-copilot")
255→                    && active_config
256→                        .get(provider.name)
257→                        .is_none_or(|entry| entry.enabled)
258→                    && has_oauth_tokens(provider.name, &self.token_store);
259→            if !subscription_with_tokens {
260→                return false;
261→            }
262→        }
263→
264→        // Check if the provider has an API key set via env
265→        if let Some(env_key) = provider.env_key
266→            && env_value_with_overrides(&self.env_overrides, env_key).is_some()
267→        {
268→            return true;
269→        }
270→        if provider.auth_type == AuthType::ApiKey
271→            && moltis_config::generic_provider_api_key_from_env(provider.name, &self.env_overrides)
272→                .is_some()
273→        {
274→            return true;
275→        }
276→        // Check config file
277→        if let Some(entry) = active_config.get(provider.name)
278→            && entry
279→                .api_key
280→                .as_ref()
281→                .is_some_and(|k| !k.expose_secret().is_empty())
282→        {
283→            return true;
284→        }
285→        // Check home/global config file as fallback when using custom config dir.
286→        if home_provider_config()
287→            .as_ref()
288→            .and_then(|(cfg, _)| cfg.get(provider.name))
289→            .and_then(|entry| entry.api_key.as_ref())
290→            .is_some_and(|k| !k.expose_secret().is_empty())
291→        {
292→            return true;
293→        }
294→        // Check persisted key store
295→        if self.key_store.load(provider.name).is_some() {
296→            return true;
297→        }
298→        // Check persisted key store in user-global config dir.
299→        if home_key_store()
300→            .as_ref()
301→            .is_some_and(|(store, _)| store.load(provider.name).is_some())
302→        {
303→            return true;
304→        }
305→        // For OAuth providers, check token store
306→        if provider.auth_type == AuthType::Oauth || provider.name == "kimi-code" {
307→            if self.token_store.load(provider.name).is_some() {
308→                return true;
309→            }
310→            if home_token_store()
311→                .as_ref()
312→                .is_some_and(|(store, _)| store.load(provider.name).is_some())
313→            {
314→                return true;
315→            }
316→            // Match provider-registry behavior: openai-codex may be inferred from
317→            // Codex CLI auth at ~/.codex/auth.json.
318→            if provider.name == "openai-codex"
319→                && crate::oauth::codex_cli_auth_path()
320→                    .as_deref()
321→                    .is_some_and(crate::oauth::codex_cli_auth_has_access_token)
322→            {
323→                return true;
324→            }
325→            return false;
326→        }
327→        // For local providers, check if model is configured in local_llm config
328→        #[cfg(feature = "local-llm")]
329→        if provider.auth_type == AuthType::Local && provider.name == "local-llm" {
330→            // Check if local-llm model config file exists
331→            if let Some(config_dir) = moltis_config::config_dir() {
332→                let config_path = config_dir.join("local-llm.json");
333→                return config_path.exists();
334→            }
335→        }
336→        false
337→    }
338→
339→    /// Build a ProvidersConfig that includes saved keys for registry rebuild.
340→    fn effective_config(&self) -> ProvidersConfig {
341→        let base = self.config_snapshot();
342→        config_with_saved_keys(&base, &self.key_store, &[])
343→    }
344→
345→    fn build_registry(&self, config: &ProvidersConfig) -> ProviderRegistry {
346→        ProviderRegistry::from_env_with_config_and_overrides(config, &self.env_overrides)
347→    }
348→}
