 88→/// Local GGUF LLM provider.
 89→pub struct LocalGgufProvider {
 90→    backend: Arc<SendSyncBackend>,
 91→    model: Arc<Mutex<LlamaModel>>,
 92→    model_id: String,
 93→    model_def: Option<&'static GgufModelDef>,
 94→    context_size: u32,
 95→    temperature: f32,
