386→#[async_trait]
387→impl LlmProvider for LocalGgufProvider {
388→    fn name(&self) -> &str {
389→        "local-llm"
390→    }
391→
392→    fn id(&self) -> &str {
393→        &self.model_id
394→    }
395→
396→    fn context_window(&self) -> u32 {
397→        self.context_size
398→    }
399→
400→    fn supports_tools(&self) -> bool {
401→        true
402→    }
403→
404→    async fn complete(
405→        &self,
406→        messages: &[ChatMessage],
407→        tools: &[serde_json::Value],
408→    ) -> Result<CompletionResponse> {
409→        let prompt = format_messages(messages, self.chat_template());
410→        let max_tokens = 4096u32;
411→
412→        // Extract tool names for grammar constraint.
413→        let tool_names: Vec<String> = tools
414→            .iter()
415→            .filter_map(|t| t["name"].as_str().map(String::from))
416→            .collect();
417→
418→        // Clone what we need for the blocking task
419→        let backend = Arc::clone(&self.backend);
420→        let model = Arc::clone(&self.model);
421→        let context_size = self.context_size;
422→        let temperature = self.temperature;
423→        let model_id = self.model_id.clone();
424→        let model_def = self.model_def;
425→
426→        // Run generation in blocking context
427→        let (text, input_tokens, output_tokens) = tokio::task::spawn_blocking(move || {
428→            let tool_name_refs: Vec<&str> = tool_names.iter().map(String::as_str).collect();
429→            let provider = LocalGgufProvider {
430→                backend,
431→                model,
432→                model_id,
433→                model_def,
434→                context_size,
435→                temperature,
436→            };
437→            provider.generate_sync(&prompt, max_tokens, &tool_name_refs)
438→        })
439→        .await
440→        .context("generation task panicked")??;
441→
442→        // Parse tool calls from the generated text.
443→        let (parsed_calls, remaining_text) =
444→            moltis_agents::tool_parsing::parse_tool_calls_from_text(&text);
445→
446→        let tool_calls: Vec<ToolCall> = parsed_calls
447→            .into_iter()
448→            .map(|tc| ToolCall {
449→                id: tc.id,
450→                name: tc.name,
451→                arguments: tc.arguments,
452→            })
453→            .collect();
454→
455→        let display_text = if tool_calls.is_empty() {
456→            Some(text)
457→        } else {
458→            remaining_text.filter(|s| !s.is_empty())
459→        };
460→
461→        Ok(CompletionResponse {
462→            text: display_text,
463→            tool_calls,
464→            usage: Usage {
465→                input_tokens,
466→                output_tokens,
467→                ..Default::default()
468→            },
469→        })
470→    }
471→
472→    fn stream(
473→        &self,
474→        messages: Vec<ChatMessage>,
475→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
476→        let prompt = format_messages(&messages, self.chat_template());
477→        let max_tokens = 4096u32;
478→
479→        let backend = Arc::clone(&self.backend);
480→        let model = Arc::clone(&self.model);
481→        let context_size = self.context_size;
482→        let temperature = self.temperature;
483→
484→        Box::pin(async_stream::stream! {
485→            let (tx, mut rx) = tokio::sync::mpsc::channel::<StreamEvent>(32);
486→
487→            // Spawn blocking generation task
488→            let handle = tokio::task::spawn_blocking(move || {
489→                stream_generate_sync(
490→                    &backend.0,
491→                    &model,
492→                    &prompt,
493→                    max_tokens,
494→                    context_size,
495→                    temperature,
496→                    tx,
497→                )
498→            });
499→
500→            // Yield events from the channel
501→            while let Some(event) = rx.recv().await {
502→                let is_done = matches!(event, StreamEvent::Done(_) | StreamEvent::Error(_));
503→                yield event;
504→                if is_done {
505→                    break;
506→                }
507→            }
508→
509→            // Wait for the blocking task to complete
510→            if let Err(e) = handle.await {
511→                warn!("generation task error: {e}");
512→            }
513→        })
514→    }
515→}
