517→/// Streaming generation in a blocking context.
518→fn stream_generate_sync(
519→    backend: &LlamaBackend,
520→    model: &Mutex<LlamaModel>,
521→    prompt: &str,
522→    max_tokens: u32,
523→    context_size: u32,
524→    temperature: f32,
525→    tx: tokio::sync::mpsc::Sender<StreamEvent>,
526→) {
527→    let generation_start = Instant::now();
528→    // Batch size for processing (default in llama.cpp is 2048, we use 512 for safety)
529→    let batch_size: usize = 512;
530→
531→    let result = (|| -> Result<(u32, u32)> {
532→        let model = model.blocking_lock();
533→
534→        // Create context
535→        let ctx_params = LlamaContextParams::default()
536→            .with_n_ctx(NonZeroU32::new(context_size))
537→            .with_n_batch(batch_size as u32);
538→        let mut ctx = model
539→            .new_context(backend, ctx_params)
540→            .map_err(|e| anyhow::anyhow!("failed to create llama context: {e}"))?;
541→
542→        // Tokenize prompt
543→        let tokens = model
544→            .str_to_token(prompt, llama_cpp_2::model::AddBos::Always)
545→            .map_err(|e| anyhow::anyhow!("tokenization failed: {e}"))?;
546→
547→        let input_tokens = tokens.len() as u32;
548→        debug!(input_tokens, "tokenized prompt for streaming");
549→
550→        if tokens.is_empty() {
551→            bail!("empty token sequence");
552→        }
553→
554→        // Process prompt in batches to avoid exceeding n_batch
555→        let mut batch = LlamaBatch::new(batch_size, 1);
556→        for (chunk_idx, chunk) in tokens.chunks(batch_size).enumerate() {
557→            batch.clear();
558→            let chunk_start = chunk_idx * batch_size;
559→            let is_last_chunk = chunk_start + chunk.len() == tokens.len();
560→
561→            for (i, &token) in chunk.iter().enumerate() {
562→                let pos = (chunk_start + i) as i32;
563→                // Only compute logits for the very last token
564→                let is_last = is_last_chunk && i == chunk.len() - 1;
565→                batch
566→                    .add(token, pos, &[0], is_last)
567→                    .map_err(|e| anyhow::anyhow!("batch add failed: {e}"))?;
568→            }
569→
570→            ctx.decode(&mut batch)
571→                .map_err(|e| anyhow::anyhow!("prompt decode failed: {e}"))?;
572→        }
573→
574→        let prompt_eval_time = generation_start.elapsed();
575→        debug!(
576→            prompt_eval_secs = prompt_eval_time.as_secs_f64(),
577→            "prompt evaluation complete, starting token generation"
578→        );
579→
580→        // Set up sampler chain: temperature -> random distribution
581→        let mut sampler =
582→            LlamaSampler::chain_simple([LlamaSampler::temp(temperature), LlamaSampler::dist(42)]);
583→
584→        // Generate tokens
585→        let token_gen_start = Instant::now();
586→        let mut first_token_time: Option<std::time::Duration> = None;
587→        let mut output_tokens = 0u32;
588→        let mut pos = tokens.len() as i32;
589→        let eos_token = model.token_eos();
590→        let mut decoder = encoding_rs::UTF_8.new_decoder();
591→
592→        for _ in 0..max_tokens {
593→            // Sample from the last position in the batch
594→            let token = sampler.sample(&ctx, batch.n_tokens() - 1);
595→
596→            if token == eos_token {
597→                debug!("reached EOS token");
598→                break;
599→            }
600→
601→            output_tokens += 1;
602→
603→            // Record time to first token
604→            if first_token_time.is_none() {
605→                let ttft = generation_start.elapsed();
606→                first_token_time = Some(ttft);
607→                debug!(ttft_secs = ttft.as_secs_f64(), "time to first token");
608→
609→                #[cfg(feature = "metrics")]
610→                histogram!(llm_metrics::TIME_TO_FIRST_TOKEN_SECONDS).record(ttft.as_secs_f64());
611→            }
612→
613→            sampler.accept(token);
614→
615→            // Detokenize and send
616→            let piece = model
617→                .token_to_piece(token, &mut decoder, true, None)
618→                .map_err(|e| anyhow::anyhow!("detokenization failed: {e}"))?;
619→
620→            if tx.blocking_send(StreamEvent::Delta(piece)).is_err() {
621→                // Receiver dropped, stop generation
622→                debug!("receiver dropped, stopping generation");
623→                break;
624→            }
625→
626→            // Decode next token
627→            batch.clear();
628→            batch
629→                .add(token, pos, &[0], true)
630→                .map_err(|e| anyhow::anyhow!("batch add token failed: {e}"))?;
631→            ctx.decode(&mut batch)
632→                .map_err(|e| anyhow::anyhow!("token decode failed: {e}"))?;
633→
634→            pos += 1;
635→        }
636→
637→        let token_gen_duration = token_gen_start.elapsed();
638→        let total_duration = generation_start.elapsed();
639→
640→        // Calculate and log tokens per second
641→        let tokens_per_sec = if token_gen_duration.as_secs_f64() > 0.0 {
642→            output_tokens as f64 / token_gen_duration.as_secs_f64()
643→        } else {
644→            0.0
645→        };
646→
647→        debug!(
648→            output_tokens,
649→            generation_secs = token_gen_duration.as_secs_f64(),
650→            total_secs = total_duration.as_secs_f64(),
651→            tokens_per_sec = format!("{:.1}", tokens_per_sec),
652→            "streaming generation complete"
653→        );
654→
655→        #[cfg(feature = "metrics")]
656→        if tokens_per_sec > 0.0 {
657→            histogram!(llm_metrics::TOKENS_PER_SECOND).record(tokens_per_sec);
658→        }
659→
660→        Ok((input_tokens, output_tokens))
661→    })();
662→
663→    match result {
664→        Ok((input_tokens, output_tokens)) => {
665→            let _ = tx.blocking_send(StreamEvent::Done(Usage {
666→                input_tokens,
667→                output_tokens,
668→                ..Default::default()
669→            }));
670→        },
671→        Err(e) => {
672→            warn!(error = %e, "streaming generation failed");
673→            let _ = tx.blocking_send(StreamEvent::Error(e.to_string()));
674→        },
675→    }
676→}
