 69→/// Local LLM provider with lazy loading.
 70→///
 71→/// Automatically selects the best backend for the current platform and
 72→/// loads the model on first use.
 73→pub struct LocalLlmProvider {
 74→    config: LocalLlmConfig,
 75→    inner: RwLock<Option<Box<dyn LocalBackend>>>,
 76→    selected_backend: RwLock<Option<BackendType>>,
 77→}
 78→
 79→impl LocalLlmProvider {
 80→    /// Create a new lazy-loading local LLM provider.
 81→    pub fn new(config: LocalLlmConfig) -> Self {
 82→        Self {
 83→            config,
 84→            inner: RwLock::new(None),
 85→            selected_backend: RwLock::new(None),
 86→        }
 87→    }
 88→
 89→    /// Get the backend type that will be (or was) used.
 90→    pub async fn backend_type(&self) -> BackendType {
 91→        if let Some(bt) = *self.selected_backend.read().await {
 92→            return bt;
 93→        }
 94→        self.config
 95→            .backend
 96→            .unwrap_or_else(backend::detect_best_backend)
 97→    }
 98→
 99→    /// Ensure the backend is loaded.
100→    async fn ensure_loaded(&self) -> Result<()> {
101→        // Fast path: check if already loaded
102→        {
103→            let guard = self.inner.read().await;
104→            if guard.is_some() {
105→                return Ok(());
106→            }
107→        }
108→
109→        // Slow path: load the backend
110→        let mut guard = self.inner.write().await;
111→
112→        // Double-check after acquiring write lock
113→        if guard.is_some() {
114→            return Ok(());
115→        }
116→
117→        let backend_type = self
118→            .config
119→            .backend
120→            .unwrap_or_else(|| backend::detect_backend_for_model(&self.config.model_id));
121→        info!(
122→            model = %self.config.model_id,
123→            backend = ?backend_type,
124→            "loading local LLM model"
125→        );
126→
127→        *self.selected_backend.write().await = Some(backend_type);
128→
129→        let backend = backend::create_backend(backend_type, &self.config).await?;
130→        *guard = Some(backend);
131→
132→        Ok(())
133→    }
134→}
135→
136→#[async_trait]
137→impl LlmProvider for LocalLlmProvider {
138→    fn name(&self) -> &str {
139→        "local-llm"
140→    }
141→
142→    fn id(&self) -> &str {
143→        &self.config.model_id
144→    }
145→
146→    fn context_window(&self) -> u32 {
147→        self.config
148→            .context_size
149→            .or_else(|| models::find_model(&self.config.model_id).map(|m| m.context_window))
150→            .unwrap_or(8192)
151→    }
152→
153→    fn supports_tools(&self) -> bool {
154→        true
155→    }
156→
157→    async fn complete(
158→        &self,
159→        messages: &[ChatMessage],
160→        tools: &[serde_json::Value],
161→    ) -> Result<CompletionResponse> {
162→        self.ensure_loaded().await?;
163→
164→        let guard = self.inner.read().await;
165→        let backend = guard
166→            .as_ref()
167→            .ok_or_else(|| anyhow::anyhow!("backend should be loaded after ensure_loaded"))?;
168→        if tools.is_empty() {
169→            backend.complete(messages).await
170→        } else {
171→            backend.complete_with_tools(messages, tools).await
172→        }
173→    }
174→
175→    fn stream(
176→        &self,
177→        messages: Vec<ChatMessage>,
178→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
179→        Box::pin(async_stream::stream! {
180→            if let Err(e) = self.ensure_loaded().await {
181→                yield StreamEvent::Error(format!("failed to load model: {e}"));
182→                return;
183→            }
184→
185→            let guard = self.inner.read().await;
186→            let Some(backend) = guard.as_ref() else {
187→                yield StreamEvent::Error("backend should be loaded after ensure_loaded".into());
188→                return;
189→            };
190→
191→            let mut stream = backend.stream(&messages);
192→            while let Some(event) = futures::StreamExt::next(&mut stream).await {
193→                yield event;
194→            }
195→        })
196→    }
197→}
