 65→fn title_case_chunk(chunk: &str) -> String {
 66→    if chunk.is_empty() {
 67→        return String::new();
 68→    }
 69→    let mut chars = chunk.chars();
 70→    match chars.next() {
 71→        Some(first) => {
 72→            let mut out = String::new();
 73→            out.push(first.to_ascii_uppercase());
 74→            out.push_str(chars.as_str());
 75→            out
 76→        },
 77→        None => String::new(),
 78→    }
 79→}
 80→
 81→fn format_gpt_display_name(model_id: &str) -> String {
 82→    let Some(rest) = model_id.strip_prefix("gpt-") else {
 83→        return model_id.to_string();
 84→    };
 85→    let mut parts = rest.split('-');
 86→    let Some(base) = parts.next() else {
 87→        return "GPT".to_string();
 88→    };
 89→    let mut out = format!("GPT-{base}");
 90→    for part in parts {
 91→        out.push(' ');
 92→        out.push_str(&title_case_chunk(part));
 93→    }
 94→    out
 95→}
 96→
 97→fn format_chatgpt_display_name(model_id: &str) -> String {
 98→    let Some(rest) = model_id.strip_prefix("chatgpt-") else {
 99→        return model_id.to_string();
100→    };
101→    let mut parts = rest.split('-');
102→    let Some(base) = parts.next() else {
103→        return "ChatGPT".to_string();
104→    };
105→    let mut out = format!("ChatGPT-{base}");
106→    for part in parts {
107→        out.push(' ');
108→        out.push_str(&title_case_chunk(part));
109→    }
110→    out
111→}
112→
113→fn formatted_model_name(model_id: &str) -> String {
114→    if model_id.starts_with("gpt-") {
115→        return format_gpt_display_name(model_id);
116→    }
117→    if model_id.starts_with("chatgpt-") {
118→        return format_chatgpt_display_name(model_id);
119→    }
120→    model_id.to_string()
121→}
122→
123→fn normalize_display_name(model_id: &str, display_name: Option<&str>) -> String {
124→    let normalized = display_name
125→        .map(str::trim)
126→        .filter(|s| !s.is_empty())
127→        .unwrap_or(model_id);
128→    if normalized == model_id {
129→        return formatted_model_name(model_id);
130→    }
131→    normalized.to_string()
132→}
133→
134→fn is_likely_model_id(model_id: &str) -> bool {
135→    if model_id.is_empty() || model_id.len() > 160 {
136→        return false;
137→    }
138→    if model_id.chars().any(char::is_whitespace) {
139→        return false;
140→    }
141→    model_id
142→        .chars()
143→        .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.' | ':' | '/'))
144→}
145→
146→/// Delegates to the shared [`super::is_chat_capable_model`] for filtering
147→/// non-chat models during discovery.
148→fn is_chat_capable_model(model_id: &str) -> bool {
149→    super::is_chat_capable_model(model_id)
150→}
151→
152→fn parse_model_entry(entry: &serde_json::Value) -> Option<DiscoveredModel> {
153→    let obj = entry.as_object()?;
154→    let model_id = obj
155→        .get("id")
156→        .or_else(|| obj.get("slug"))
157→        .or_else(|| obj.get("model"))
158→        .and_then(serde_json::Value::as_str)?;
159→
160→    if !is_likely_model_id(model_id) {
161→        return None;
162→    }
163→
164→    let display_name = obj
165→        .get("display_name")
166→        .or_else(|| obj.get("displayName"))
167→        .or_else(|| obj.get("name"))
168→        .or_else(|| obj.get("title"))
169→        .and_then(serde_json::Value::as_str);
170→
171→    let created_at = obj.get("created").and_then(serde_json::Value::as_i64);
172→
173→    let recommended = is_recommended_openai_model(model_id);
174→    Some(
175→        DiscoveredModel::new(model_id, normalize_display_name(model_id, display_name))
176→            .with_created_at(created_at)
177→            .with_recommended(recommended),
178→    )
179→}
180→
181→/// Known OpenAI flagship model IDs (latest generation, no date suffix).
182→/// These are the models most users care about.
183→fn is_recommended_openai_model(model_id: &str) -> bool {
184→    matches!(
185→        model_id,
186→        "gpt-5.4" | "gpt-5.4-mini" | "gpt-5.4-pro" | "o4-mini" | "o3"
187→    )
188→}
189→
190→fn collect_candidate_arrays<'a>(
191→    value: &'a serde_json::Value,
192→    out: &mut Vec<&'a serde_json::Value>,
193→) {
194→    match value {
195→        serde_json::Value::Array(items) => out.extend(items),
196→        serde_json::Value::Object(map) => {
197→            for key in ["models", "data", "items", "results", "available"] {
198→                if let Some(nested) = map.get(key) {
199→                    collect_candidate_arrays(nested, out);
200→                }
201→            }
202→        },
203→        _ => {},
204→    }
205→}
206→
207→fn parse_models_payload(value: &serde_json::Value) -> Vec<DiscoveredModel> {
208→    let mut candidates = Vec::new();
209→    collect_candidate_arrays(value, &mut candidates);
210→
211→    let mut models = Vec::new();
212→    let mut seen = HashSet::new();
213→    for entry in candidates {
214→        if let Some(model) = parse_model_entry(entry)
215→            && is_chat_capable_model(&model.id)
216→            && seen.insert(model.id.clone())
217→        {
218→            models.push(model);
219→        }
220→    }
221→
222→    // Sort by created_at descending (newest first). Models without a
223→    // timestamp are placed after those with one, preserving relative order.
224→    models.sort_by(|a, b| match (a.created_at, b.created_at) {
225→        (Some(a_ts), Some(b_ts)) => b_ts.cmp(&a_ts), // newest first
226→        (Some(_), None) => std::cmp::Ordering::Less, // timestamp before no-timestamp
227→        (None, Some(_)) => std::cmp::Ordering::Greater,
228→        (None, None) => std::cmp::Ordering::Equal,
229→    });
230→
231→    models
232→}
233→
234→fn models_endpoint(base_url: &str) -> String {
235→    format!(
236→        "{}{OPENAI_MODELS_ENDPOINT_PATH}",
237→        base_url.trim_end_matches('/')
238→    )
239→}
