241→/// Fetch available models from the OpenAI-compatible `/models` endpoint.
242→pub async fn fetch_models_from_api(
243→    api_key: secrecy::Secret<String>,
244→    base_url: String,
245→) -> anyhow::Result<Vec<DiscoveredModel>> {
246→    let client = crate::shared_http_client();
247→    let response = client
248→        .get(models_endpoint(&base_url))
249→        .timeout(Duration::from_secs(15))
250→        .header(
251→            "Authorization",
252→            format!("Bearer {}", api_key.expose_secret()),
253→        )
254→        .header("Accept", "application/json")
255→        .send()
256→        .await?;
257→    let status = response.status();
258→    let body = response.text().await?;
259→    if !status.is_success() {
260→        anyhow::bail!("openai models API error HTTP {status}");
261→    }
262→    let payload: serde_json::Value = serde_json::from_str(&body)?;
263→    let models = parse_models_payload(&payload);
264→    if models.is_empty() {
265→        anyhow::bail!("openai models API returned no models");
266→    }
267→    Ok(models)
268→}
269→
270→/// Spawn model discovery in a background thread and return the receiver
271→/// immediately, without blocking. Call `.recv()` later to collect the result.
272→pub fn start_model_discovery(
273→    api_key: secrecy::Secret<String>,
274→    base_url: String,
275→) -> mpsc::Receiver<anyhow::Result<Vec<DiscoveredModel>>> {
276→    let (tx, rx) = mpsc::sync_channel(1);
277→    std::thread::spawn(move || {
278→        let result = tokio::runtime::Builder::new_current_thread()
279→            .enable_all()
280→            .build()
281→            .map_err(anyhow::Error::from)
282→            .and_then(|rt| rt.block_on(fetch_models_from_api(api_key, base_url)));
283→        let _ = tx.send(result);
284→    });
285→    rx
286→}
287→
288→fn fetch_models_blocking(
289→    api_key: secrecy::Secret<String>,
290→    base_url: String,
291→) -> anyhow::Result<Vec<DiscoveredModel>> {
292→    start_model_discovery(api_key, base_url)
293→        .recv()
294→        .map_err(|err| anyhow::anyhow!("openai model discovery worker failed: {err}"))?
295→}
296→
297→pub fn live_models(
298→    api_key: &secrecy::Secret<String>,
299→    base_url: &str,
300→) -> anyhow::Result<Vec<DiscoveredModel>> {
301→    let models = fetch_models_blocking(api_key.clone(), base_url.to_string())?;
302→    debug!(model_count = models.len(), "loaded live models");
303→    Ok(models)
304→}
305→
306→#[must_use]
307→pub fn available_models(api_key: &secrecy::Secret<String>, base_url: &str) -> Vec<DiscoveredModel> {
308→    let fallback = default_model_catalog();
309→    if cfg!(test) {
310→        return fallback;
311→    }
312→
313→    let discovered = match live_models(api_key, base_url) {
314→        Ok(models) => models,
315→        Err(err) => {
316→            warn!(error = %err, base_url = %base_url, "failed to fetch openai models, using fallback catalog");
317→            return fallback;
318→        },
319→    };
320→
321→    let merged = super::merge_discovered_with_fallback_catalog(discovered, fallback);
322→    debug!(model_count = merged.len(), "loaded openai models catalog");
323→    merged
324→}
