  1→use {
  2→    serde::{Deserialize, Serialize},
  3→    serde_json::{Map, Value},
  4→};
  5→
  6→/// Tagged persisted representation for secrets stored inside JSON configs.
  7→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
  8→#[serde(tag = "kind", rename_all = "snake_case")]
  9→pub enum StoredSecret {
 10→    VaultEncrypted { ciphertext: String },
 11→}
 12→
 13→impl StoredSecret {
 14→    fn into_value(self) -> Result<Value, Error> {
 15→        serde_json::to_value(self).map_err(Error::from)
 16→    }
 17→}
 18→
 19→#[derive(Debug, thiserror::Error)]
 20→pub enum Error {
 21→    #[error("secret-bearing config must be a JSON object")]
 22→    ConfigMustBeObject,
 23→
 24→    #[error("stored secret field '{field}' has an unsupported JSON type")]
 25→    InvalidSecretFieldType { field: String },
 26→
 27→    #[error(transparent)]
 28→    SerdeJson(#[from] serde_json::Error),
 29→
 30→    #[cfg(feature = "vault")]
 31→    #[error(transparent)]
 32→    Vault(#[from] moltis_vault::VaultError),
 33→}
 34→
 35→fn object(config: &Value) -> Result<&Map<String, Value>, Error> {
 36→    config.as_object().ok_or(Error::ConfigMustBeObject)
 37→}
 38→
 39→fn object_mut(config: &mut Value) -> Result<&mut Map<String, Value>, Error> {
 40→    config.as_object_mut().ok_or(Error::ConfigMustBeObject)
 41→}
 42→
 43→fn parse_stored_secret(value: &Value) -> Result<Option<StoredSecret>, Error> {
 44→    let Value::Object(map) = value else {
 45→        return Ok(None);
 46→    };
 47→
 48→    if !map.contains_key("kind") {
 49→        return Ok(None);
 50→    }
 51→
 52→    serde_json::from_value(value.clone())
 53→        .map(Some)
 54→        .map_err(Error::from)
 55→}
 56→
 57→fn field_aad(scope: &str, field: &str) -> String {
 58→    format!("{scope}:{field}")
 59→}
 60→
 61→/// Whether any declared secret field is still stored as plaintext.
 62→pub fn has_plaintext_secret_fields(config: &Value, secret_fields: &[&str]) -> Result<bool, Error> {
 63→    let map = object(config)?;
 64→    for field in secret_fields {
 65→        let Some(value) = map.get(*field) else {
 66→            continue;
 67→        };
 68→
 69→        if value.is_string() {
 70→            return Ok(true);
 71→        }
 72→
 73→        if parse_stored_secret(value)?.is_some() {
 74→            continue;
 75→        }
 76→
 77→        if value.is_null() {
 78→            continue;
 79→        }
 80→
 81→        return Err(Error::InvalidSecretFieldType {
 82→            field: (*field).to_string(),
 83→        });
 84→    }
 85→
 86→    Ok(false)
 87→}
 88→
 89→/// Whether any declared secret field is stored as an encrypted tagged object.
 90→pub fn has_encrypted_secret_fields(config: &Value, secret_fields: &[&str]) -> Result<bool, Error> {
 91→    let map = object(config)?;
 92→    for field in secret_fields {
 93→        let Some(value) = map.get(*field) else {
 94→            continue;
 95→        };
 96→
 97→        if parse_stored_secret(value)?.is_some() {
 98→            return Ok(true);
 99→        }
100→
101→        if value.is_string() || value.is_null() {
102→            continue;
103→        }
104→
105→        return Err(Error::InvalidSecretFieldType {
106→            field: (*field).to_string(),
107→        });
108→    }
109→
110→    Ok(false)
111→}
112→
113→#[cfg(feature = "vault")]
114→pub async fn encrypt_secret_fields<C: moltis_vault::Cipher>(
115→    config: &mut Value,
116→    secret_fields: &[&str],
117→    aad_scope: &str,
118→    vault: &moltis_vault::Vault<C>,
119→) -> Result<bool, Error> {
120→    let map = object_mut(config)?;
121→    let mut changed = false;
122→
123→    for field in secret_fields {
124→        let Some(value) = map.get_mut(*field) else {
125→            continue;
126→        };
127→
128→        match value {
129→            Value::String(plaintext) => {
130→                let ciphertext = vault
131→                    .encrypt_string(plaintext, &field_aad(aad_scope, field))
132→                    .await?;
133→                *value = StoredSecret::VaultEncrypted { ciphertext }.into_value()?;
134→                changed = true;
135→            },
136→            Value::Null => {},
137→            _ if parse_stored_secret(value)?.is_some() => {},
138→            _ => {
139→                return Err(Error::InvalidSecretFieldType {
140→                    field: (*field).to_string(),
141→                });
142→            },
143→        }
144→    }
145→
146→    Ok(changed)
147→}
148→
149→#[cfg(feature = "vault")]
150→pub async fn decrypt_secret_fields<C: moltis_vault::Cipher>(
151→    config: &mut Value,
152→    secret_fields: &[&str],
153→    aad_scope: &str,
154→    vault: &moltis_vault::Vault<C>,
155→) -> Result<bool, Error> {
156→    let map = object_mut(config)?;
157→    let mut changed = false;
158→
159→    for field in secret_fields {
160→        let Some(value) = map.get_mut(*field) else {
161→            continue;
162→        };
163→
164→        match parse_stored_secret(value)? {
165→            Some(StoredSecret::VaultEncrypted { ciphertext }) => {
166→                let plaintext = vault
167→                    .decrypt_string(&ciphertext, &field_aad(aad_scope, field))
168→                    .await?;
169→                *value = Value::String(plaintext);
170→                changed = true;
171→            },
172→            None if value.is_string() || value.is_null() => {},
173→            None => {
174→                return Err(Error::InvalidSecretFieldType {
175→                    field: (*field).to_string(),
176→                });
177→            },
178→        }
179→    }
180→
181→    Ok(changed)
182→}
