266→        let ciphertext = vault
267→            .encrypt_string("secret-token", "channel:telegram:bot1:token")
268→            .await
269→            .unwrap();
270→        let mut config = serde_json::json!({
271→            "token": {
272→                "kind": "vault_encrypted",
273→                "ciphertext": ciphertext
274→            }
275→        });
276→
277→        let changed =
278→            encrypt_secret_fields(&mut config, &["token"], "channel:telegram:bot1", &vault)
279→                .await
280→                .unwrap();
281→        assert!(!changed);
282→        assert!(has_encrypted_secret_fields(&config, &["token"]).unwrap());
283→    }
284→}
