 55→impl TelegramOutbound {
 56→    pub(crate) fn get_bot(&self, account_id: &str) -> Result<Bot> {
 57→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
 58→        accounts
 59→            .get(account_id)
 60→            .map(|s| s.bot.clone())
 61→            .ok_or_else(|| ChannelError::unknown_account(account_id))
 62→    }
 63→
 64→    /// Build reply parameters only when `reply_to_message` is enabled for this account.
 65→    pub(crate) fn reply_params(
 66→        &self,
 67→        account_id: &str,
 68→        reply_to: Option<&str>,
 69→    ) -> Option<ReplyParameters> {
 70→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
 71→        let enabled = accounts
 72→            .get(account_id)
 73→            .is_some_and(|s| s.config.reply_to_message);
 74→        if enabled {
 75→            parse_reply_params(reply_to)
 76→        } else {
 77→            None
 78→        }
 79→    }
 80→
 81→    fn stream_send_config(&self, account_id: &str) -> StreamSendConfig {
 82→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
 83→        accounts
 84→            .get(account_id)
 85→            .map(|s| StreamSendConfig {
 86→                edit_throttle_ms: s.config.edit_throttle_ms,
 87→                notify_on_complete: s.config.stream_notify_on_complete,
 88→                min_initial_chars: s.config.stream_min_initial_chars,
 89→            })
 90→            .unwrap_or_default()
 91→    }
 92→}
