 94→/// Parse a platform message ID string into Telegram `ReplyParameters`.
 95→/// Returns `None` if the string is not a valid i32 (Telegram message IDs are i32).
 96→fn parse_reply_params(reply_to: Option<&str>) -> Option<ReplyParameters> {
 97→    reply_to.and_then(|id| id.parse::<i32>().ok()).map(|id| {
 98→        ReplyParameters::new(teloxide::types::MessageId(id)).allow_sending_without_reply()
 99→    })
100→}
