 33→#[derive(Debug, Clone, PartialEq, Eq)]
 34→enum TelegramApiMethod {
 35→    SendMessage,
 36→    SendChatAction,
 37→    GetFile,
 38→    Other(String),
 39→}
 40→
 41→impl TelegramApiMethod {
 42→    fn from_path(path: &str) -> Self {
 43→        let method = path.rsplit('/').next().unwrap_or_default();
 44→        match method {
 45→            "SendMessage" | "sendMessage" => Self::SendMessage,
 46→            "SendChatAction" | "sendChatAction" => Self::SendChatAction,
 47→            "GetFile" | "getFile" => Self::GetFile,
 48→            _ => Self::Other(method.to_string()),
 49→        }
 50→    }
 51→}
 52→
 53→#[derive(Debug, Clone)]
 54→enum CapturedTelegramRequest {
 55→    SendMessage(SendMessageRequest),
 56→    SendChatAction(SendChatActionRequest),
 57→    Other {
 58→        method: TelegramApiMethod,
 59→        raw_body: String,
 60→    },
 61→}
 62→
 63→#[derive(Debug, Clone, Deserialize)]
 64→struct SendMessageRequest {
 65→    chat_id: i64,
 66→    text: String,
 67→    #[serde(default)]
 68→    parse_mode: Option<String>,
 69→}
 70→
 71→#[derive(Debug, Clone, Deserialize)]
 72→struct SendChatActionRequest {
 73→    chat_id: i64,
 74→    action: String,
 75→}
 76→
 77→#[derive(Debug, Serialize)]
 78→struct TelegramApiResponse {
 79→    ok: bool,
 80→    result: TelegramApiResult,
 81→}
 82→
 83→#[derive(Debug, Serialize)]
 84→#[serde(untagged)]
 85→enum TelegramApiResult {
 86→    Message(TelegramMessageResult),
 87→    File(TelegramFileResult),
 88→    Bool(bool),
 89→}
 90→
 91→#[derive(Debug, Serialize)]
 92→struct TelegramFileResult {
 93→    file_id: String,
 94→    file_unique_id: String,
 95→    file_path: String,
 96→}
 97→
 98→#[derive(Debug, Serialize)]
 99→struct TelegramChat {
100→    id: i64,
101→    #[serde(rename = "type")]
102→    chat_type: String,
103→}
104→
105→#[derive(Debug, Serialize)]
106→struct TelegramMessageResult {
107→    message_id: i64,
108→    date: i64,
109→    chat: TelegramChat,
110→    text: String,
111→}
112→
113→#[derive(Clone)]
114→struct MockTelegramApi {
115→    requests: Arc<Mutex<Vec<CapturedTelegramRequest>>>,
116→}
117→
118→async fn telegram_api_handler(
119→    State(state): State<MockTelegramApi>,
120→    uri: Uri,
121→    body: Bytes,
122→) -> Json<TelegramApiResponse> {
123→    let method = TelegramApiMethod::from_path(uri.path());
124→    let raw_body = String::from_utf8_lossy(&body).to_string();
125→
126→    let captured = match method.clone() {
127→        TelegramApiMethod::SendMessage => {
128→            match serde_json::from_slice::<SendMessageRequest>(&body) {
129→                Ok(req) => CapturedTelegramRequest::SendMessage(req),
130→                Err(_) => CapturedTelegramRequest::Other { method, raw_body },
131→            }
132→        },
133→        TelegramApiMethod::SendChatAction => {
134→            match serde_json::from_slice::<SendChatActionRequest>(&body) {
135→                Ok(req) => CapturedTelegramRequest::SendChatAction(req),
136→                Err(_) => CapturedTelegramRequest::Other { method, raw_body },
137→            }
138→        },
139→        TelegramApiMethod::GetFile | TelegramApiMethod::Other(_) => {
140→            CapturedTelegramRequest::Other { method, raw_body }
141→        },
142→    };
143→
144→    state.requests.lock().expect("lock requests").push(captured);
145→
146→    match TelegramApiMethod::from_path(uri.path()) {
147→        TelegramApiMethod::SendMessage => Json(TelegramApiResponse {
148→            ok: true,
149→            result: TelegramApiResult::Message(TelegramMessageResult {
150→                message_id: 1,
151→                date: 0,
152→                chat: TelegramChat {
153→                    id: 42,
154→                    chat_type: "private".to_string(),
155→                },
156→                text: "ok".to_string(),
157→            }),
158→        }),
159→        TelegramApiMethod::GetFile => Json(TelegramApiResponse {
160→            ok: true,
161→            result: TelegramApiResult::File(TelegramFileResult {
162→                file_id: "test-file-id".to_string(),
163→                file_unique_id: "test-unique-id".to_string(),
164→                file_path: "voice/test-voice.ogg".to_string(),
165→            }),
166→        }),
167→        TelegramApiMethod::SendChatAction | TelegramApiMethod::Other(_) => {
168→            Json(TelegramApiResponse {
169→                ok: true,
170→                result: TelegramApiResult::Bool(true),
171→            })
172→        },
173→    }
174→}
