219→    async fn dispatch_to_chat(
220→        &self,
221→        text: &str,
222→        _reply_to: ChannelReplyTarget,
223→        meta: ChannelMessageMeta,
224→    ) {
225→        self.dispatch_calls
226→            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
227→        self.dispatched_texts
228→            .lock()
229→            .expect("lock")
