  1→//! Native filesystem tools: `Read`, `Write`, `Edit`, `MultiEdit`, `Glob`, `Grep`.
  2→//!
  3→//! These are the structured, typed alternative to shell-based file I/O via
  4→//! `exec`. They match Claude Code's tool schemas exactly so LLMs trained on
  5→//! those tools encounter the same shape of parameters and responses.
  6→//!
  7→//! See GH moltis-org/moltis#657 for context.
  8→//!
  9→//! Phase 1 (this module) covers host-path execution only. Sandbox routing
 10→//! arrives in phase 2, UX polish (adaptive paging, edit recovery, re-read
 11→//! detection) in phase 3, and operator-facing `[tools.fs]` config in phase 4.
 12→
 13→pub mod edit;
 14→pub mod glob;
 15→pub mod grep;
 16→pub mod multi_edit;
 17→pub mod read;
 18→pub mod sandbox_bridge;
 19→pub mod shared;
 20→pub mod write;
 21→
 22→pub use {
 23→    edit::EditTool,
 24→    glob::GlobTool,
 25→    grep::GrepTool,
 26→    multi_edit::MultiEditTool,
 27→    read::ReadTool,
 28→    shared::{BinaryPolicy, FsPathPolicy, FsState, new_fs_state},
 29→    write::WriteTool,
 30→};
 31→
 32→use {
 33→    crate::{
 34→        approval::ApprovalManager, checkpoints::CheckpointManager, exec::ApprovalBroadcaster,
 35→        sandbox::SandboxRouter,
 36→    },
 37→    moltis_agents::tool_registry::ToolRegistry,
 38→    std::{path::PathBuf, sync::Arc},
 39→};
 40→
 41→/// Aggregated configuration for fs tool registration.
 42→///
 43→/// Phase 1 shipped with three bare positional parameters; phase 4 keeps
 44→/// adding knobs so the registration signature is migrated to a single
 45→/// context struct.
 46→#[derive(Clone)]
 47→pub struct FsToolsContext {
 48→    /// Default search root for `Glob`/`Grep` when the LLM omits `path`.
 49→    /// Must be absolute. When `None`, calls without explicit `path` error.
 50→    pub workspace_root: Option<PathBuf>,
 51→    /// Shared per-session state for read tracking, loop detection, and
 52→    /// must-read-before-write enforcement. `None` disables all trackers.
 53→    pub fs_state: Option<FsState>,
 54→    /// Allow/deny path policy. Empty policy (`None`) permits everything.
 55→    pub path_policy: Option<FsPathPolicy>,
 56→    /// Binary-file handling strategy for `Read`. Default is `Reject`.
 57→    pub binary_policy: BinaryPolicy,
 58→    /// Whether `Glob`/`Grep` honor `.gitignore` while walking. Default
 59→    /// `true`.
 60→    pub respect_gitignore: bool,
 61→    /// When set, `Write`/`Edit`/`MultiEdit` call `checkpoint_path` on
 62→    /// this manager before mutating. `None` disables checkpoints.
 63→    pub checkpoint_manager: Option<Arc<CheckpointManager>>,
 64→    /// Shared [`SandboxRouter`]. When set, fs tools dispatch through
 65→    /// the [`sandbox_bridge`] for sessions the router marks as
 66→    /// sandboxed; unsandboxed sessions still run on the host.
 67→    pub sandbox_router: Option<Arc<SandboxRouter>>,
 68→    /// Optional approval gate for mutating fs tools. When set,
 69→    /// Write/Edit/MultiEdit pause for explicit approval before
 70→    /// persisting changes.
 71→    pub approval_manager: Option<Arc<ApprovalManager>>,
 72→    /// Optional broadcaster paired with [`approval_manager`] so pending
 73→    /// fs mutation approvals show up in the gateway UI.
 74→    pub broadcaster: Option<Arc<dyn ApprovalBroadcaster>>,
 75→    /// Override for the maximum bytes a single `Read` can return
 76→    /// before a `too_large` typed error. Wired from
 77→    /// `[tools.fs].max_read_bytes`. `None` → `DEFAULT_MAX_READ_BYTES`.
 78→    pub max_read_bytes: Option<u64>,
 79→    /// Model context window in tokens. When set, enables `Read`'s
 80→    /// adaptive byte cap so per-call output scales with the working
 81→    /// set instead of using a fixed 256 KB ceiling.
 82→    pub context_window_tokens: Option<u64>,
 83→}
 84→
 85→impl Default for FsToolsContext {
 86→    fn default() -> Self {
 87→        Self {
 88→            workspace_root: None,
 89→            fs_state: None,
 90→            path_policy: None,
 91→            binary_policy: BinaryPolicy::default(),
 92→            // Follow the upstream default: WalkBuilder respects .gitignore
 93→            // unless explicitly disabled.
 94→            respect_gitignore: true,
 95→            checkpoint_manager: None,
 96→            sandbox_router: None,
 97→            approval_manager: None,
 98→            broadcaster: None,
 99→            max_read_bytes: None,
100→            context_window_tokens: None,
101→        }
102→    }
103→}
104→
105→impl FsToolsContext {
106→    #[must_use]
107→    pub fn new() -> Self {
108→        Self::default()
109→    }
110→}
111→
112→/// Register every native filesystem tool on a [`ToolRegistry`].
113→///
114→/// See [`FsToolsContext`] for the individual knobs. The `tools.policy`
115→/// allow/deny layer (per-tool names, not paths) still gates access
116→/// per-agent; registration is independent of authorization.
117→pub fn register_fs_tools(registry: &mut ToolRegistry, context: FsToolsContext) {
118→    let FsToolsContext {
119→        workspace_root,
120→        fs_state,
121→        path_policy,
122→        binary_policy,
123→        respect_gitignore,
124→        checkpoint_manager,
125→        sandbox_router,
126→        approval_manager,
127→        broadcaster,
128→        max_read_bytes,
129→        context_window_tokens,
130→    } = context;
131→
132→    let mut read = ReadTool::new().with_binary_policy(binary_policy);
133→    if let Some(max) = max_read_bytes {
134→        read = read.with_max_read_bytes(max);
135→    }
136→    if let Some(tokens) = context_window_tokens {
137→        read = read.with_context_window_tokens(tokens);
138→    }
139→    if let Some(ref s) = fs_state {
140→        read = read.with_fs_state(s.clone());
141→    }
142→    if let Some(ref p) = path_policy {
143→        read = read.with_path_policy(p.clone());
144→    }
145→    if let Some(ref r) = sandbox_router {
146→        read = read.with_sandbox_router(r.clone());
147→    }
148→    registry.register(Box::new(read));
149→
