 37→#[serde(rename_all = "lowercase")]
 38→pub enum AudioFormat {
 39→    /// MP3 format (widely compatible).
 40→    #[default]
 41→    Mp3,
 42→    /// Opus in OGG container (good for Telegram voice notes).
 43→    Opus,
 44→    /// AAC format.
 45→    Aac,
 46→    /// PCM (raw audio).
 47→    Pcm,
 48→    /// WebM container (browser MediaRecorder default).
 49→    Webm,
 50→}
 51→
 52→impl AudioFormat {
 53→    /// MIME type for this format.
 54→    #[must_use]
 55→    pub fn mime_type(&self) -> &'static str {
 56→        match self {
 57→            Self::Mp3 => "audio/mpeg",
 58→            Self::Opus => "audio/ogg",
 59→            Self::Aac => "audio/aac",
 60→            Self::Pcm => "audio/pcm",
 61→            Self::Webm => "audio/webm",
 62→        }
 63→    }
 64→
 65→    /// File extension for this format.
 66→    #[must_use]
 67→    pub fn extension(&self) -> &'static str {
 68→        match self {
 69→            Self::Mp3 => "mp3",
 70→            Self::Opus => "ogg",
 71→            Self::Aac => "aac",
 72→            Self::Pcm => "pcm",
 73→            Self::Webm => "webm",
 74→        }
 75→    }
 76→
 77→    /// Parse from a MIME content-type string (e.g. `"audio/webm"`, `"audio/webm;codecs=opus"`).
 78→    #[must_use]
 79→    pub fn from_content_type(ct: &str) -> Option<Self> {
 80→        let base = ct.split(';').next().unwrap_or(ct).trim();
 81→        match base {
 82→            "audio/webm" => Some(Self::Webm),
 83→            "audio/ogg" | "audio/opus" => Some(Self::Opus),
 84→            "audio/mpeg" | "audio/mp3" => Some(Self::Mp3),
 85→            "audio/aac" | "audio/mp4" | "audio/m4a" => Some(Self::Aac),
 86→            "audio/pcm" | "audio/wav" | "audio/x-wav" => Some(Self::Pcm),
 87→            _ => None,
 88→        }
 89→    }
 90→
 91→    /// Parse from a short format name (e.g. `"webm"`, `"opus"`, `"ogg"`, `"mp3"`).
 92→    #[must_use]
 93→    pub fn from_short_name(name: &str) -> Self {
 94→        match name {
 95→            "webm" => Self::Webm,
 96→            "opus" | "ogg" => Self::Opus,
 97→            "aac" | "m4a" => Self::Aac,
 98→            "pcm" | "wav" => Self::Pcm,
 99→            _ => Self::Mp3,
100→        }
101→    }
102→}
