164→/// Check whether text contains SSML tags (currently `<break`).
165→#[must_use]
166→pub fn contains_ssml(text: &str) -> bool {
167→    text.contains("<break")
168→}
169→
170→/// Strip SSML tags (`<break .../>`) so non-SSML providers don't speak them
171→/// literally. Returns the input unchanged (no allocation) when no tags are
172→/// present.
173→#[must_use]
174→pub fn strip_ssml_tags(text: &str) -> Cow<'_, str> {
175→    if !contains_ssml(text) {
176→        return Cow::Borrowed(text);
177→    }
178→
179→    let mut result = String::with_capacity(text.len());
180→    let mut rest = text;
181→
182→    while let Some(start) = rest.find("<break") {
183→        result.push_str(&rest[..start]);
184→        // Find the closing `/>` or `>`
185→        if let Some(end) = rest[start..].find("/>") {
186→            rest = &rest[start + end + 2..];
187→        } else if let Some(end) = rest[start..].find('>') {
188→            rest = &rest[start + end + 1..];
189→        } else {
190→            // Malformed tag — keep the rest as-is
191→            result.push_str(&rest[start..]);
192→            rest = "";
193→            break;
194→        }
195→    }
196→    result.push_str(rest);
197→
198→    Cow::Owned(result)
199→}
200→
201→/// Sanitize LLM output for text-to-speech consumption.
202→///
203→/// Strips markdown formatting, raw URLs, code fences, and other visual syntax
204→/// that TTS engines would read literally. Returns `Cow::Borrowed` when the
205→/// input needs no changes (zero-alloc fast path).
206→///
207→/// Processing order:
208→/// 1. Remove fenced code blocks (``` ... ```)
209→/// 2. Remove URLs (`https?://…`)
210→/// 3. Strip markdown headers (`# `, `## `, etc.)
211→/// 4. Strip bold/italic markers (`**`, `__`, word-boundary `*`/`_`)
212→/// 5. Strip inline code backticks
213→/// 6. Strip bullet/list prefixes (`- `, `* `, `1. `)
214→/// 7. Collapse runs of whitespace / blank lines
215→/// 8. Strip SSML tags (via [`strip_ssml_tags`])
216→#[must_use]
217→pub fn sanitize_text_for_tts(text: &str) -> Cow<'_, str> {
218→    // Fast path: if none of the markers we strip are present, return as-is.
219→    if !needs_sanitization(text) {
220→        return Cow::Borrowed(text);
221→    }
222→
223→    let mut out = String::with_capacity(text.len());
224→
225→    // --- Pass 1: remove fenced code blocks ---
226→    let after_fences = remove_code_fences(text);
227→
228→    // --- Pass 2: remove markdown tables ---
229→    let after_tables = remove_tables(&after_fences);
230→
231→    // --- Process line by line ---
232→    for line in after_tables.lines() {
233→        let mut l: &str = line;
234→
235→        // Strip markdown headers (e.g. "## Title" → "Title")
236→        l = strip_leading_hashes(l);
237→
238→        // Strip bullet/list prefixes ("- ", "* " at line start, "1. " etc.)
239→        l = strip_bullet_prefix(l);
240→
241→        // Strip inline code backticks
242→        let l_owned;
243→        if l.contains('`') {
244→            l_owned = l.replace('`', "");
245→            l = &l_owned;
246→        } else {
247→            l_owned = String::new();
248→            let _ = &l_owned; // suppress unused warning
249→        }
250→
251→        // Remove URLs (http:// or https://)
252→        let after_urls = remove_urls(l);
253→
254→        // Strip bold/italic markers
255→        let after_bold = strip_bold_italic(&after_urls);
256→
257→        // Push the cleaned line
258→        let trimmed = after_bold.trim();
259→        if !trimmed.is_empty() {
260→            if !out.is_empty() {
261→                out.push('\n');
262→            }
263→            out.push_str(trimmed);
264→        }
265→    }
266→
267→    // Collapse any remaining multiple blank lines into one
268→    let collapsed = collapse_whitespace(&out);
269→
270→    // Final pass: strip SSML tags
271→    match strip_ssml_tags(&collapsed) {
272→        Cow::Borrowed(_) => Cow::Owned(collapsed),
273→        Cow::Owned(s) => Cow::Owned(s),
274→    }
275→}
276→
277→/// Quick check for whether the text contains any markers we strip.
278→fn needs_sanitization(text: &str) -> bool {
279→    text.contains("```")
280→        || text.contains("http://")
281→        || text.contains("https://")
282→        || text.contains('#')
283→        || text.contains('*')
284→        || text.contains('_')
285→        || text.contains('`')
286→        || text.contains('|')
287→        || text.contains("\n- ")
288→        || text.starts_with("- ")
289→        || has_ordered_list(text)
290→        || text.contains("<break")
291→}
292→
293→/// Check if the text contains an ordered list pattern (`\n1. `, `\n2. `, etc.).
294→fn has_ordered_list(text: &str) -> bool {
295→    for (i, ch) in text.char_indices() {
296→        if ch == '\n' {
297→            // Check if next chars are digits followed by ". "
298→            let rest = &text[i + 1..];
299→            let digit_len = rest.chars().take_while(|c| c.is_ascii_digit()).count();
300→            if digit_len > 0 && rest[digit_len..].starts_with(". ") {
301→                return true;
302→            }
303→        }
304→    }
305→    // Also check start of text
306→    let digit_len = text.chars().take_while(|c| c.is_ascii_digit()).count();
307→    digit_len > 0 && text[digit_len..].starts_with(". ")
308→}
309→
310→/// Remove fenced code blocks (` ``` ... ``` `).
311→fn remove_code_fences(text: &str) -> String {
312→    let mut result = String::with_capacity(text.len());
313→    let mut in_fence = false;
314→
315→    for line in text.lines() {
316→        let trimmed = line.trim();
317→        if trimmed.starts_with("```") {
318→            in_fence = !in_fence;
319→            continue;
320→        }
321→        if in_fence {
322→            continue;
323→        }
324→        result.push_str(line);
325→        result.push('\n');
326→    }
327→
328→    // Remove trailing newline added by the loop
329→    if result.ends_with('\n') && !text.ends_with('\n') {
330→        result.pop();
331→    }
332→
333→    result
334→}
335→
336→/// Remove markdown table blocks from text. A table block is a run of
337→/// consecutive lines containing pipe (`|`) column separators that includes
338→/// a separator row (`|---|` or `---+---`). Entire tables are removed because
339→/// pipe characters and alignment dashes are meaningless when read aloud.
340→fn remove_tables(text: &str) -> String {
341→    let lines: Vec<&str> = text.lines().collect();
342→    let mut result = String::with_capacity(text.len());
343→    let mut i = 0;
344→
345→    while i < lines.len() {
346→        // Look for the start of a potential table (a line with table-like pipes).
347→        if is_tts_table_line(lines[i]) {
348→            // Gather consecutive table-like lines.
349→            let start = i;
350→            while i < lines.len() && is_tts_table_line(lines[i]) {
351→                i += 1;
352→            }
353→            let block = &lines[start..i];
354→            // Only strip if there's a separator row (confirming it's really a table).
355→            if block.len() >= 2 && block.iter().any(|l| is_tts_separator_row(l)) {
356→                // Skip the entire table block — don't emit anything for it.
357→                continue;
358→            }
359→            // Not a real table, keep the lines.
360→            for line in block {
361→                result.push_str(line);
362→                result.push('\n');
363→            }
364→        } else {
365→            result.push_str(lines[i]);
366→            result.push('\n');
367→            i += 1;
368→        }
369→    }
370→
371→    if result.ends_with('\n') && !text.ends_with('\n') {
372→        result.pop();
373→    }
374→    result
375→}
376→
377→/// Check if a line looks like a table row (contains `|` as column separator).
378→fn is_tts_table_line(line: &str) -> bool {
379→    let trimmed = line.trim();
380→    if trimmed.is_empty() {
381→        return false;
382→    }
383→    // Standard: starts with |
384→    if trimmed.starts_with('|') {
385→        return true;
386→    }
387→    // Non-standard: at least 2 pipe separators
388→    if trimmed.chars().filter(|&c| c == '|').count() >= 2 {
389→        return true;
390→    }
391→    // Separator row with + intersections
392→    is_tts_separator_row(line)
393→}
394→
395→/// Check if a line is a table separator row (`|---|` or `---+---`).
396→fn is_tts_separator_row(line: &str) -> bool {
397→    let trimmed = line.trim();
398→    if trimmed.is_empty() {
399→        return false;
400→    }
401→    // Pipe-separated: |---|---|
402→    let inner = trimmed.strip_prefix('|').unwrap_or(trimmed);
403→    let inner = inner.strip_suffix('|').unwrap_or(inner);
404→    if !inner.is_empty()
405→        && inner.split('|').all(|cell| {
406→            let c = cell.trim();
407→            !c.is_empty() && c.chars().all(|ch| ch == '-' || ch == ':')
408→        })
409→    {
410→        return true;
411→    }
412→    // Plus-separated: ---+---+---
413→    trimmed.contains('+')
414→        && trimmed.split('+').all(|cell| {
415→            let c = cell.trim();
416→            !c.is_empty() && c.chars().all(|ch| ch == '-' || ch == ':')
417→        })
418→}
419→
420→/// Strip leading `#` characters (markdown headers) from a line.
421→fn strip_leading_hashes(line: &str) -> &str {
422→    let trimmed = line.trim_start();
423→    if !trimmed.starts_with('#') {
424→        return line;
425→    }
426→    let after_hashes = trimmed.trim_start_matches('#');
427→    // Only strip if followed by a space (avoids false positives like "#hashtag")
428→    after_hashes.strip_prefix(' ').unwrap_or(line)
429→}
430→
431→/// Strip bullet/list prefixes from a line start.
432→fn strip_bullet_prefix(line: &str) -> &str {
433→    let trimmed = line.trim_start();
434→    // Unordered: "- " or "* "
435→    if let Some(rest) = trimmed.strip_prefix("- ") {
436→        return rest;
437→    }
438→    if let Some(rest) = trimmed.strip_prefix("* ") {
439→        return rest;
440→    }
441→    // Ordered: "1. ", "2. ", etc.
442→    if let Some(pos) = trimmed.find(". ") {
443→        let prefix = &trimmed[..pos];
444→        if !prefix.is_empty() && prefix.chars().all(|c| c.is_ascii_digit()) {
445→            return &trimmed[pos + 2..];
446→        }
447→    }
448→    line
449→}
450→
451→/// Remove URLs matching `https?://\S+`.
452→fn remove_urls(text: &str) -> String {
453→    let mut result = String::with_capacity(text.len());
454→    let mut rest = text;
455→
456→    loop {
457→        // Find the next URL start
458→        let pos = rest.find("https://").or_else(|| rest.find("http://"));
459→
460→        match pos {
461→            Some(start) => {
462→                result.push_str(&rest[..start]);
463→                // Skip the URL (until whitespace or end)
464→                let url_start = &rest[start..];
465→                let url_end = url_start
466→                    .find(|c: char| c.is_whitespace() || c == ')' || c == ']' || c == '>')
467→                    .unwrap_or(url_start.len());
468→                rest = &rest[start + url_end..];
469→            },
470→            None => {
471→                result.push_str(rest);
472→                break;
473→            },
474→        }
475→    }
476→
477→    result
478→}
479→
480→/// Strip bold/italic markers (`**`, `__`, and word-boundary `*`/`_`).
481→///
482→/// Preserves contractions like "don't" by only stripping `_` at word boundaries
483→/// (i.e. preceded/followed by whitespace or at string boundaries).
484→fn strip_bold_italic(text: &str) -> String {
485→    let mut result = String::with_capacity(text.len());
486→    let chars: Vec<char> = text.chars().collect();
487→    let len = chars.len();
488→    let mut i = 0;
489→
490→    while i < len {
491→        // Double markers: ** or __
492→        if i + 1 < len && chars[i] == chars[i + 1] && (chars[i] == '*' || chars[i] == '_') {
493→            i += 2;
494→            continue;
495→        }
496→
497→        // Single * is always a markdown marker (less common in prose)
498→        if chars[i] == '*' {
499→            i += 1;
500→            continue;
501→        }
502→
503→        // Single _ only at word boundaries to preserve contractions
504→        if chars[i] == '_' {
505→            let at_start = i == 0 || chars[i - 1].is_whitespace();
506→            let at_end = i + 1 >= len || chars[i + 1].is_whitespace();
507→            if at_start || at_end {
508→                i += 1;
509→                continue;
510→            }
511→        }
512→
513→        result.push(chars[i]);
514→        i += 1;
515→    }
516→
517→    result
518→}
519→
520→/// Collapse runs of multiple blank lines into a single newline.
521→fn collapse_whitespace(text: &str) -> String {
522→    let mut result = String::with_capacity(text.len());
523→    let mut prev_was_newline = false;
524→
525→    for ch in text.chars() {
526→        if ch == '\n' {
527→            if !prev_was_newline {
528→                result.push('\n');
529→            }
530→            prev_was_newline = true;
531→        } else {
532→            prev_was_newline = false;
533→            result.push(ch);
534→        }
535→    }
536→
537→    result.trim().to_string()
538→}
