 32→    }
 33→
 34→    fn description() -> String {
 35→        "Evaluate arithmetic expressions safely. Supports +, -, *, /, %, ^, unary +/- and parentheses. \
 36→         No variables, functions, or assignments."
 37→            .to_string()
 38→    }
 39→
 40→    fn parameters_schema() -> String {
 41→        json!({
 42→            "type": "object",
 43→            "required": ["expression"],
 44→            "properties": {
 45→                "expression": {
 46→                    "type": "string",
 47→                    "description": "Arithmetic expression to evaluate (for example: (2 + 3) * 4, 15%4, 2^8)"
 48→                },
 49→                "expr": {
 50→                    "type": "string",
 51→                    "description": "Alias for expression"
 52→                }
 53→            }
 54→        })
 55→        .to_string()
 56→    }
 57→
 58→    fn execute(params_json: String) -> ToolResult {
 59→        match execute_impl(&params_json) {
 60→            Ok(value) => ToolResult::Ok(ToolValue::Json(value.to_string())),
 61→            Err(error) => ToolResult::Err(ToolError {
 62→                code: "invalid_input".to_string(),
 63→                message: error.to_string(),
 64→            }),
 65→        }
 66→    }
 67→}
 68→
 69→fn execute_impl(params_json: &str) -> Result<Value> {
 70→    let params: Value = serde_json::from_str(params_json)?;
 71→    let expression = params
 72→        .get("expression")
 73→        .or_else(|| params.get("expr"))
 74→        .and_then(Value::as_str)
 75→        .ok_or_else(|| anyhow::anyhow!("missing 'expression' parameter"))?;
 76→
 77→    let (result, normalized_expr) = evaluate_expression(expression)?;
 78→    Ok(json!({
 79→        "result": result_to_json(result)?,
 80→        "normalized_expr": normalized_expr
 81→    }))
 82→}
