 84→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 85→enum Operator {
 86→    Add,
 87→    Subtract,
 88→    Multiply,
 89→    Divide,
 90→    Modulo,
 91→    Power,
 92→}
 93→
 94→impl Operator {
 95→    fn precedence(self) -> u8 {
 96→        match self {
 97→            Self::Add | Self::Subtract => 10,
 98→            Self::Multiply | Self::Divide | Self::Modulo => 20,
 99→            Self::Power => 30,
100→        }
101→    }
102→
103→    fn is_right_associative(self) -> bool {
104→        matches!(self, Self::Power)
105→    }
106→
107→    fn symbol(self) -> &'static str {
108→        match self {
109→            Self::Add => "+",
110→            Self::Subtract => "-",
111→            Self::Multiply => "*",
112→            Self::Divide => "/",
113→            Self::Modulo => "%",
114→            Self::Power => "^",
115→        }
116→    }
117→}
118→
119→#[derive(Debug, Clone, PartialEq)]
120→enum Token {
121→    Number { value: f64, repr: String },
122→    Plus,
123→    Minus,
124→    Star,
125→    Slash,
126→    Percent,
127→    Caret,
128→    LParen,
129→    RParen,
130→}
131→
132→impl Token {
133→    fn repr(&self) -> String {
134→        match self {
135→            Self::Number { repr, .. } => repr.clone(),
136→            Self::Plus => "+".to_string(),
137→            Self::Minus => "-".to_string(),
138→            Self::Star => "*".to_string(),
139→            Self::Slash => "/".to_string(),
140→            Self::Percent => "%".to_string(),
141→            Self::Caret => "^".to_string(),
142→            Self::LParen => "(".to_string(),
143→            Self::RParen => ")".to_string(),
144→        }
145→    }
146→}
147→
148→fn normalize_negative_zero(value: f64) -> f64 {
149→    if value.classify() == std::num::FpCategory::Zero {
150→        0.0
151→    } else {
152→        value
153→    }
154→}
155→
156→fn is_zero(value: f64) -> bool {
157→    value.classify() == std::num::FpCategory::Zero
158→}
159→
160→fn ensure_finite(value: f64, context: &str) -> Result<f64> {
161→    if !value.is_finite() || value.abs() > MAX_ABS_RESULT {
162→        bail!("{context} produced a non-finite result");
163→    }
164→    Ok(normalize_negative_zero(value))
165→}
166→
167→fn parse_number_token(expression: &str, start: usize) -> Result<(Token, usize)> {
168→    let bytes = expression.as_bytes();
169→    let mut i = start;
170→    let mut saw_digit = false;
171→
172→    if bytes.get(i) == Some(&b'.') {
173→        i += 1;
174→        while bytes.get(i).is_some_and(u8::is_ascii_digit) {
175→            saw_digit = true;
176→            i += 1;
177→        }
178→        if !saw_digit {
179→            bail!("invalid number literal at byte {start}");
180→        }
181→    } else {
182→        while bytes.get(i).is_some_and(u8::is_ascii_digit) {
183→            saw_digit = true;
184→            i += 1;
185→        }
186→        if bytes.get(i) == Some(&b'.') {
187→            i += 1;
188→            while bytes.get(i).is_some_and(u8::is_ascii_digit) {
189→                saw_digit = true;
190→                i += 1;
191→            }
192→        }
193→    }
194→
195→    if !saw_digit {
196→        bail!("invalid number literal at byte {start}");
197→    }
198→
199→    if matches!(bytes.get(i), Some(b'e' | b'E')) {
200→        let exponent_marker = i;
201→        i += 1;
202→        if matches!(bytes.get(i), Some(b'+' | b'-')) {
203→            i += 1;
204→        }
205→        let exponent_start = i;
206→        while bytes.get(i).is_some_and(u8::is_ascii_digit) {
207→            i += 1;
208→        }
209→        if exponent_start == i {
210→            bail!("invalid exponent in number literal at byte {exponent_marker}");
211→        }
212→    }
213→
214→    let repr = expression[start..i].to_string();
215→    let value = repr
216→        .parse::<f64>()
217→        .map_err(|_| anyhow::anyhow!("invalid number literal `{repr}`"))?;
218→    let value = ensure_finite(value, "number literal")?;
219→
220→    Ok((Token::Number { value, repr }, i))
221→}
222→
223→fn tokenize(expression: &str) -> Result<Vec<Token>> {
224→    let bytes = expression.as_bytes();
225→    let mut i = 0usize;
226→    let mut tokens = Vec::new();
227→
228→    while i < bytes.len() {
229→        match bytes[i] {
230→            b' ' | b'\t' | b'\n' | b'\r' => {
231→                i += 1;
232→            },
233→            b'0'..=b'9' | b'.' => {
234→                let (token, next) = parse_number_token(expression, i)?;
235→                tokens.push(token);
236→                i = next;
237→            },
238→            b'+' => {
239→                tokens.push(Token::Plus);
240→                i += 1;
241→            },
242→            b'-' => {
243→                tokens.push(Token::Minus);
244→                i += 1;
245→            },
246→            b'*' => {
247→                tokens.push(Token::Star);
248→                i += 1;
249→            },
250→            b'/' => {
251→                tokens.push(Token::Slash);
252→                i += 1;
253→            },
254→            b'%' => {
255→                tokens.push(Token::Percent);
256→                i += 1;
257→            },
258→            b'^' => {
259→                tokens.push(Token::Caret);
260→                i += 1;
261→            },
262→            b'(' => {
263→                tokens.push(Token::LParen);
264→                i += 1;
265→            },
266→            b')' => {
267→                tokens.push(Token::RParen);
268→                i += 1;
269→            },
270→            other => bail!("unsupported character `{}` at byte {}", other as char, i),
271→        }
272→    }
273→
274→    if tokens.is_empty() {
275→        bail!("expression is empty");
276→    }
277→    if tokens.len() > MAX_TOKENS {
278→        bail!("expression is too complex (maximum {MAX_TOKENS} tokens)");
279→    }
280→    Ok(tokens)
281→}
282→
283→fn normalize_expression(tokens: &[Token]) -> String {
284→    tokens.iter().map(Token::repr).collect::<Vec<_>>().join("")
285→}
286→
287→#[derive(Debug, Clone)]
288→enum Expr {
289→    Number(f64),
290→    Unary {
291→        op: Operator,
292→        expr: Box<Expr>,
293→    },
294→    Binary {
295→        left: Box<Expr>,
296→        op: Operator,
297→        right: Box<Expr>,
298→    },
299→}
300→
301→struct Parser<'a> {
302→    tokens: &'a [Token],
303→    position: usize,
304→    operations: usize,
305→}
306→
307→impl<'a> Parser<'a> {
308→    fn new(tokens: &'a [Token]) -> Self {
309→        Self {
310→            tokens,
311→            position: 0,
312→            operations: 0,
313→        }
314→    }
315→
316→    fn parse(mut self) -> Result<Expr> {
317→        let expr = self.parse_expression(0, 0)?;
318→        if self.position != self.tokens.len() {
319→            bail!(
320→                "unexpected token `{}` at position {}",
321→                self.tokens[self.position].repr(),
322→                self.position
323→            );
324→        }
325→        Ok(expr)
326→    }
327→
328→    fn parse_expression(&mut self, min_prec: u8, depth: usize) -> Result<Expr> {
329→        if depth > MAX_AST_DEPTH {
330→            bail!("expression nesting is too deep (maximum {MAX_AST_DEPTH})");
331→        }
332→
333→        let mut lhs = self.parse_prefix(depth)?;
334→
335→        while let Some(op) = self.peek_binary_operator() {
336→            if op.precedence() < min_prec {
337→                break;
338→            }
339→            self.bump_operation_count()?;
340→            self.position += 1;
341→            let next_min = if op.is_right_associative() {
342→                op.precedence()
343→            } else {
344→                op.precedence().saturating_add(1)
345→            };
346→            let rhs = self.parse_expression(next_min, depth + 1)?;
347→            lhs = Expr::Binary {
348→                left: Box::new(lhs),
349→                op,
350→                right: Box::new(rhs),
351→            };
352→        }
353→
354→        Ok(lhs)
355→    }
356→
357→    fn parse_prefix(&mut self, depth: usize) -> Result<Expr> {
358→        let token = self
359→            .tokens
360→            .get(self.position)
361→            .ok_or_else(|| anyhow::anyhow!("unexpected end of expression"))?;
362→
363→        match token {
364→            Token::Number { value, .. } => {
365→                self.position += 1;
366→                Ok(Expr::Number(*value))
367→            },
368→            Token::Minus => {
369→                self.bump_operation_count()?;
370→                self.position += 1;
371→                let expr = self.parse_expression(Operator::Power.precedence(), depth + 1)?;
372→                Ok(Expr::Unary {
373→                    op: Operator::Subtract,
374→                    expr: Box::new(expr),
375→                })
376→            },
377→            Token::Plus => {
378→                self.bump_operation_count()?;
379→                self.position += 1;
380→                let expr = self.parse_expression(Operator::Power.precedence(), depth + 1)?;
381→                Ok(Expr::Unary {
382→                    op: Operator::Add,
383→                    expr: Box::new(expr),
384→                })
385→            },
386→            Token::LParen => {
387→                self.position += 1;
388→                let expr = self.parse_expression(0, depth + 1)?;
389→                match self.tokens.get(self.position) {
390→                    Some(Token::RParen) => {
391→                        self.position += 1;
392→                        Ok(expr)
393→                    },
394→                    _ => bail!("missing closing ')' for parenthesized expression"),
395→                }
396→            },
397→            _ => bail!(
398→                "unexpected token `{}` at position {}",
399→                token.repr(),
400→                self.position
401→            ),
402→        }
403→    }
404→
405→    fn peek_binary_operator(&self) -> Option<Operator> {
406→        match self.tokens.get(self.position) {
407→            Some(Token::Plus) => Some(Operator::Add),
408→            Some(Token::Minus) => Some(Operator::Subtract),
409→            Some(Token::Star) => Some(Operator::Multiply),
410→            Some(Token::Slash) => Some(Operator::Divide),
411→            Some(Token::Percent) => Some(Operator::Modulo),
412→            Some(Token::Caret) => Some(Operator::Power),
413→            _ => None,
414→        }
415→    }
416→
417→    fn bump_operation_count(&mut self) -> Result<()> {
418→        self.operations = self.operations.saturating_add(1);
419→        if self.operations > MAX_OPERATIONS {
420→            bail!("expression is too complex (maximum {MAX_OPERATIONS} operations)");
421→        }
422→        Ok(())
423→    }
424→}
425→
426→struct Evaluator<'a> {
427→    tokens: &'a [Token],
428→}
429→
430→impl<'a> Evaluator<'a> {
431→    fn new(tokens: &'a [Token]) -> Self {
432→        Self { tokens }
433→    }
434→
435→    fn evaluate(&self) -> Result<f64> {
436→        let ast = Parser::new(self.tokens).parse()?;
437→        self.evaluate_expr(&ast)
438→    }
439→
440→    fn evaluate_expr(&self, expr: &Expr) -> Result<f64> {
441→        match expr {
442→            Expr::Number(value) => Ok(*value),
443→            Expr::Unary { op, expr } => {
444→                let value = self.evaluate_expr(expr)?;
445→                match op {
446→                    Operator::Add => ensure_finite(value, "unary plus"),
447→                    Operator::Subtract => ensure_finite(-value, "unary minus"),
448→                    _ => bail!("unsupported unary operator `{}`", op.symbol()),
449→                }
450→            },
451→            Expr::Binary { left, op, right } => {
452→                let left = self.evaluate_expr(left)?;
453→                let right = self.evaluate_expr(right)?;
454→                match op {
455→                    Operator::Add => ensure_finite(left + right, "addition"),
456→                    Operator::Subtract => ensure_finite(left - right, "subtraction"),
457→                    Operator::Multiply => ensure_finite(left * right, "multiplication"),
458→                    Operator::Divide => {
459→                        if is_zero(right) {
460→                            bail!("division by zero");
461→                        }
462→                        ensure_finite(left / right, "division")
463→                    },
464→                    Operator::Modulo => {
465→                        if is_zero(right) {
466→                            bail!("modulo by zero");
467→                        }
468→                        ensure_finite(left % right, "modulo")
469→                    },
470→                    Operator::Power => {
471→                        if right.abs() > MAX_ABS_EXPONENT {
472→                            bail!(
473→                                "exponent out of allowed range (max absolute exponent: {MAX_ABS_EXPONENT})"
474→                            );
475→                        }
476→                        ensure_finite(left.powf(right), "power")
477→                    },
478→                }
479→            },
480→        }
481→    }
482→}
483→
484→fn result_to_json(value: f64) -> Result<Value> {
485→    let normalized = normalize_negative_zero(value);
486→    if normalized.fract() == 0.0 && normalized >= i64::MIN as f64 && normalized <= i64::MAX as f64 {
487→        return Ok(json!(normalized as i64));
488→    }
489→
490→    let number = serde_json::Number::from_f64(normalized)
491→        .ok_or_else(|| anyhow::anyhow!("result is not a finite JSON number"))?;
492→    Ok(Value::Number(number))
493→}
494→
495→fn evaluate_expression(expression: &str) -> Result<(f64, String)> {
496→    if expression.len() > MAX_EXPRESSION_CHARS {
497→        bail!("expression is too long (maximum {MAX_EXPRESSION_CHARS} characters)");
498→    }
499→
500→    let tokens = tokenize(expression)?;
501→    let normalized = normalize_expression(&tokens);
502→    let result = Evaluator::new(&tokens).evaluate()?;
503→    Ok((result, normalized))
504→}
