 20→
 21→const DEFAULT_MAX_CHARS: usize = 50_000;
 22→const DEFAULT_MAX_REDIRECTS: u8 = 5;
 23→const DEFAULT_TIMEOUT_MS: u32 = 10_000;
 24→const DEFAULT_MAX_RESPONSE_BYTES: u64 = 2_000_000;
 25→
 26→#[cfg(target_arch = "wasm32")]
 27→struct WebFetchWasm;
 28→
 29→#[cfg(target_arch = "wasm32")]
