 70→#[cfg(target_arch = "wasm32")]
 71→fn execute_impl(params_json: &str) -> Result<Value, ToolError> {
 72→    let params: Value = serde_json::from_str(params_json).map_err(|error| ToolError {
 73→        code: "invalid_params_json".to_string(),
 74→        message: error.to_string(),
 75→    })?;
 76→
 77→    let url_input = params
 78→        .get("url")
 79→        .and_then(Value::as_str)
 80→        .ok_or_else(|| ToolError {
 81→            code: "missing_url".to_string(),
 82→            message: "missing 'url' parameter".to_string(),
 83→        })?;
 84→
 85→    let extract_mode = params
 86→        .get("extract_mode")
 87→        .and_then(Value::as_str)
 88→        .unwrap_or("markdown");
 89→    let max_chars = params
 90→        .get("max_chars")
 91→        .and_then(Value::as_u64)
 92→        .and_then(|value| usize::try_from(value).ok())
 93→        .unwrap_or(DEFAULT_MAX_CHARS);
 94→    let accept_language = params.get("_accept_language").and_then(Value::as_str);
 95→
 96→    fetch_with_redirects(url_input, extract_mode, max_chars, accept_language)
 97→}
