 99→#[cfg(target_arch = "wasm32")]
100→fn fetch_with_redirects(
101→    url_input: &str,
102→    extract_mode: &str,
103→    max_chars: usize,
104→    accept_language: Option<&str>,
105→) -> Result<Value, ToolError> {
106→    let mut current_url = Url::parse(url_input).map_err(|error| ToolError {
107→        code: "invalid_url".to_string(),
108→        message: error.to_string(),
109→    })?;
110→    if !matches!(current_url.scheme(), "http" | "https") {
111→        return Err(ToolError {
112→            code: "unsupported_scheme".to_string(),
113→            message: format!("unsupported URL scheme: {}", current_url.scheme()),
114→        });
115→    }
116→
117→    let mut visited = vec![current_url.to_string()];
118→    let mut hops = 0_u8;
119→
120→    loop {
121→        let mut headers = Vec::new();
122→        if let Some(lang) = accept_language {
123→            headers.push(("Accept-Language".to_string(), lang.to_string()));
124→        }
125→        let request = HttpRequest {
126→            method: "GET".to_string(),
127→            url: current_url.to_string(),
128→            headers,
129→            body: None,
130→            timeout_ms: Some(DEFAULT_TIMEOUT_MS),
131→            max_response_bytes: Some(DEFAULT_MAX_RESPONSE_BYTES),
132→        };
133→
134→        let response = outgoing_handler::handle(&request).map_err(map_http_error)?;
135→        if (300..400).contains(&response.status) {
136→            if hops >= DEFAULT_MAX_REDIRECTS {
137→                return Err(ToolError {
138→                    code: "too_many_redirects".to_string(),
139→                    message: format!("too many redirects (max {DEFAULT_MAX_REDIRECTS})"),
140→                });
141→            }
142→            let location =
143→                header_value(&response.headers, "location").ok_or_else(|| ToolError {
144→                    code: "redirect_missing_location".to_string(),
145→                    message: "redirect without Location header".to_string(),
146→                })?;
147→            let next = current_url.join(&location).map_err(|error| ToolError {
148→                code: "redirect_invalid_location".to_string(),
149→                message: error.to_string(),
150→            })?;
151→            let next_s = next.to_string();
152→            if visited.iter().any(|seen| seen == &next_s) {
153→                return Err(ToolError {
154→                    code: "redirect_loop".to_string(),
155→                    message: format!("redirect loop detected at {next_s}"),
156→                });
157→            }
158→            visited.push(next_s);
159→            current_url = next;
160→            hops = hops.saturating_add(1);
161→            continue;
162→        }
163→
164→        if !(200..300).contains(&response.status) {
165→            return Ok(json!({
166→                "error": format!("HTTP {}", response.status),
167→                "url": current_url.to_string(),
168→            }));
169→        }
170→
171→        let content_type = response.content_type.unwrap_or_default();
172→        let body = String::from_utf8_lossy(&response.body).into_owned();
173→        let (content, detected_mode) = extract_content(&body, &content_type, extract_mode);
174→        let truncated = content.len() > max_chars;
175→        let content = if truncated {
176→            truncate_at_char_boundary(&content, max_chars)
177→        } else {
178→            content
179→        };
180→        return Ok(json!({
181→            "url": current_url.to_string(),
182→            "content_type": content_type,
183→            "extract_mode": detected_mode,
184→            "content": content,
185→            "truncated": truncated,
186→            "original_length": body.len(),
187→        }));
188→    }
189→}
