192→fn map_http_error(error: HttpError) -> ToolError {
193→    match error {
194→        HttpError::InvalidUrl(message) => ToolError {
195→            code: "invalid_url".to_string(),
196→            message,
197→        },
198→        HttpError::BlockedUrl(message) => ToolError {
199→            code: "blocked_url".to_string(),
200→            message,
201→        },
202→        HttpError::Timeout(message) => ToolError {
203→            code: "timeout".to_string(),
204→            message,
205→        },
206→        HttpError::Network(message) => ToolError {
207→            code: "network".to_string(),
208→            message,
209→        },
210→        HttpError::Status(status) => ToolError {
211→            code: "http_status".to_string(),
212→            message: format!("HTTP {status}"),
213→        },
214→        HttpError::TooLarge(size) => ToolError {
215→            code: "too_large".to_string(),
216→            message: format!("response exceeded {size} bytes"),
217→        },
218→        HttpError::Other(message) => ToolError {
219→            code: "http_error".to_string(),
220→            message,
221→        },
222→    }
223→}
