225→fn header_value(headers: &[(String, String)], name: &str) -> Option<String> {
226→    headers
227→        .iter()
228→        .find(|(header_name, _)| header_name.eq_ignore_ascii_case(name))
229→        .map(|(_, value)| value.clone())
230→}
231→
232→fn extract_content(body: &str, content_type: &str, requested_mode: &str) -> (String, String) {
233→    let ct_lower = content_type.to_ascii_lowercase();
234→    if ct_lower.contains("json") {
235→        if let Ok(parsed) = serde_json::from_str::<Value>(body) {
236→            let pretty = serde_json::to_string_pretty(&parsed).unwrap_or_else(|_| body.to_string());
237→            return (pretty, "json".to_string());
238→        }
239→        return (body.to_string(), "text".to_string());
240→    }
241→    if ct_lower.contains("text/plain") || !ct_lower.contains("html") {
242→        return (body.to_string(), "text".to_string());
243→    }
244→    if requested_mode == "markdown" || requested_mode.is_empty() {
245→        return (html_to_text(body), "markdown".to_string());
246→    }
247→    (html_to_text(body), "text".to_string())
248→}
249→
250→fn html_to_text(html: &str) -> String {
251→    let mut result = String::with_capacity(html.len() / 2);
252→    let mut in_tag = false;
253→    let mut in_script = false;
254→    let mut in_style = false;
255→    let mut last_was_space = false;
256→    let html_lower = html.to_ascii_lowercase();
257→    let bytes = html.as_bytes();
258→    let lower_bytes = html_lower.as_bytes();
259→
260→    let mut index = 0_usize;
261→    while index < bytes.len() {
262→        if bytes[index] == b'<' {
263→            if index + 7 < lower_bytes.len() && &lower_bytes[index..index + 7] == b"<script" {
264→                in_script = true;
265→            }
266→            if index + 9 < lower_bytes.len() && &lower_bytes[index..index + 9] == b"</script>" {
267→                in_script = false;
268→            }
269→            if index + 6 < lower_bytes.len() && &lower_bytes[index..index + 6] == b"<style" {
270→                in_style = true;
271→            }
272→            if index + 8 < lower_bytes.len() && &lower_bytes[index..index + 8] == b"</style>" {
273→                in_style = false;
274→            }
275→            in_tag = true;
276→            index += 1;
277→            continue;
278→        }
279→
280→        if bytes[index] == b'>' {
281→            in_tag = false;
282→            index += 1;
283→            continue;
284→        }
285→
286→        if in_tag || in_script || in_style {
287→            index += 1;
288→            continue;
289→        }
290→
291→        let ch = bytes[index] as char;
292→        if ch.is_ascii_whitespace() {
293→            if !last_was_space {
294→                result.push(' ');
295→                last_was_space = true;
296→            }
297→        } else {
298→            result.push(ch);
299→            last_was_space = false;
300→        }
301→        index += 1;
302→    }
303→
304→    result.trim().to_string()
305→}
306→
307→fn truncate_at_char_boundary(s: &str, max: usize) -> String {
308→    if s.len() <= max {
309→        return s.to_string();
310→    }
311→    let mut end = max;
312→    while end > 0 && !s.is_char_boundary(end) {
313→        end -= 1;
314→    }
315→    s[..end].to_string()
316→}
