 80→fn execute_impl(params_json: &str) -> Result<Value, ToolError> {
 81→    let params: Value = serde_json::from_str(params_json).map_err(|error| ToolError {
 82→        code: "invalid_params_json".to_string(),
 83→        message: error.to_string(),
 84→    })?;
 85→    let query = params
 86→        .get("query")
 87→        .and_then(Value::as_str)
 88→        .ok_or_else(|| ToolError {
 89→            code: "missing_query".to_string(),
 90→            message: "missing 'query' parameter".to_string(),
 91→        })?;
 92→    let count = params
 93→        .get("count")
 94→        .and_then(Value::as_u64)
 95→        .map(|n| n.clamp(1, 10))
 96→        .and_then(|n| u8::try_from(n).ok())
 97→        .unwrap_or(DEFAULT_RESULT_COUNT);
 98→    let accept_language = params.get("_accept_language").and_then(Value::as_str);
 99→
100→    let mut url = format!(
101→        "https://api.search.brave.com/res/v1/web/search?q={}&count={count}",
102→        url_encode(query)
103→    );
104→    if let Some(country) = params.get("country").and_then(Value::as_str) {
105→        url.push_str(&format!("&country={country}"));
106→    }
107→    if let Some(search_lang) = params.get("search_lang").and_then(Value::as_str) {
108→        url.push_str(&format!("&search_lang={search_lang}"));
109→    }
110→    if let Some(ui_lang) = params.get("ui_lang").and_then(Value::as_str) {
111→        url.push_str(&format!("&ui_lang={ui_lang}"));
112→    }
113→    if let Some(freshness) = params.get("freshness").and_then(Value::as_str) {
114→        url.push_str(&format!("&freshness={freshness}"));
115→    }
116→
117→    let mut headers = vec![("Accept".to_string(), "application/json".to_string())];
118→    if let Some(lang) = accept_language {
119→        headers.push(("Accept-Language".to_string(), lang.to_string()));
120→    }
121→    let request = HttpRequest {
122→        method: "GET".to_string(),
123→        url,
124→        headers,
125→        body: None,
126→        timeout_ms: Some(DEFAULT_TIMEOUT_MS),
127→        max_response_bytes: Some(DEFAULT_MAX_RESPONSE_BYTES),
128→    };
129→
130→    let response = outgoing_handler::handle(&request).map_err(map_http_error)?;
131→    if !(200..300).contains(&response.status) {
132→        return Ok(json!({
133→            "error": format!("HTTP {}", response.status),
134→            "query": query,
135→        }));
136→    }
137→    let body_text = String::from_utf8_lossy(&response.body).into_owned();
138→    let body_json: Value = serde_json::from_str(&body_text).map_err(|error| ToolError {
139→        code: "invalid_brave_json".to_string(),
140→        message: error.to_string(),
141→    })?;
142→    let results = parse_brave_results(&body_json);
143→
144→    Ok(json!({
145→        "provider": "brave",
146→        "query": query,
147→        "results": results,
148→    }))
149→}
