151→fn parse_brave_results(body: &Value) -> Vec<Value> {
152→    body.get("web")
153→        .and_then(|web| web.get("results"))
154→        .and_then(Value::as_array)
155→        .map(|results| {
156→            results
157→                .iter()
158→                .filter_map(|result| {
159→                    let title = result
160→                        .get("title")
161→                        .and_then(Value::as_str)
162→                        .map(str::trim)
163→                        .unwrap_or("");
164→                    let url = result
165→                        .get("url")
166→                        .and_then(Value::as_str)
167→                        .map(str::trim)
168→                        .unwrap_or("");
169→                    if title.is_empty() || url.is_empty() {
170→                        return None;
171→                    }
172→                    let description = result
173→                        .get("description")
174→                        .and_then(Value::as_str)
175→                        .unwrap_or("");
176→                    Some(json!({
177→                        "title": title,
178→                        "url": url,
179→                        "description": description,
180→                    }))
181→                })
182→                .collect()
183→        })
184→        .unwrap_or_default()
185→}
