188→fn map_http_error(error: HttpError) -> ToolError {
189→    match error {
190→        HttpError::InvalidUrl(message) => ToolError {
191→            code: "invalid_url".to_string(),
192→            message,
193→        },
194→        HttpError::BlockedUrl(message) => ToolError {
195→            code: "blocked_url".to_string(),
196→            message,
197→        },
198→        HttpError::Timeout(message) => ToolError {
199→            code: "timeout".to_string(),
200→            message,
201→        },
202→        HttpError::Network(message) => ToolError {
203→            code: "network".to_string(),
204→            message,
205→        },
206→        HttpError::Status(status) => ToolError {
207→            code: "http_status".to_string(),
208→            message: format!("HTTP {status}"),
209→        },
210→        HttpError::TooLarge(size) => ToolError {
211→            code: "too_large".to_string(),
212→            message: format!("response exceeded {size} bytes"),
213→        },
214→        HttpError::Other(message) => ToolError {
215→            code: "http_error".to_string(),
216→            message,
217→        },
218→    }
219→}
