221→fn url_encode(s: &str) -> String {
222→    let mut out = String::with_capacity(s.len());
223→    for byte in s.bytes() {
224→        match byte {
225→            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
226→                out.push(byte as char);
227→            },
228→            _ => {
229→                out.push_str(&format!("%{byte:02X}"));
230→            },
231→        }
232→    }
233→    out
234→}
