24→pub async fn run_migrations(pool: &sqlx::SqlitePool) -> Result<()> {
25→    // Foreign key enforcement (for ON DELETE CASCADE) is enabled via
26→    // `.foreign_keys(true)` on the pool's SqliteConnectOptions, which
27→    // applies to every connection — not per-query PRAGMA.
28→    sqlx::migrate!("./migrations")
29→        .set_ignore_missing(true)
30→        .run(pool)
31→        .await?;
32→    Ok(())
