use {
    serde::{Deserialize, Serialize},
    serde_json::{Map, Value},
};

/// Tagged persisted representation for secrets stored inside JSON configs.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum StoredSecret {
    VaultEncrypted { ciphertext: String },
}

impl StoredSecret {
    fn into_value(self) -> Result<Value, Error> {
        serde_json::to_value(self).map_err(Error::from)
    }
}

#[derive(Debug, thiserror::Error)]
pub enum Error {
    #[error("secret-bearing config must be a JSON object")]
    ConfigMustBeObject,

    #[error("stored secret field '{field}' has an unsupported JSON type")]
    InvalidSecretFieldType { field: String },

    #[error(transparent)]
    SerdeJson(#[from] serde_json::Error),

    #[cfg(feature = "vault")]
    #[error(transparent)]
    Vault(#[from] moltis_vault::VaultError),
}

fn object(config: &Value) -> Result<&Map<String, Value>, Error> {
    config.as_object().ok_or(Error::ConfigMustBeObject)
}

fn object_mut(config: &mut Value) -> Result<&mut Map<String, Value>, Error> {
    config.as_object_mut().ok_or(Error::ConfigMustBeObject)
}

fn parse_stored_secret(value: &Value) -> Result<Option<StoredSecret>, Error> {
    let Value::Object(map) = value else {
        return Ok(None);
    };

    if !map.contains_key("kind") {
        return Ok(None);
    }

    serde_json::from_value(value.clone())
        .map(Some)
        .map_err(Error::from)
}

fn field_aad(scope: &str, field: &str) -> String {
    format!("{scope}:{field}")
}

/// Whether any declared secret field is still stored as plaintext.
pub fn has_plaintext_secret_fields(config: &Value, secret_fields: &[&str]) -> Result<bool, Error> {
    let map = object(config)?;
    for field in secret_fields {
        let Some(value) = map.get(*field) else {
            continue;
        };

        if value.is_string() {
            return Ok(true);
        }

        if parse_stored_secret(value)?.is_some() {
            continue;
        }

        if value.is_null() {
            continue;
        }

        return Err(Error::InvalidSecretFieldType {
            field: (*field).to_string(),
        });
    }

    Ok(false)
}

/// Whether any declared secret field is stored as an encrypted tagged object.
pub fn has_encrypted_secret_fields(config: &Value, secret_fields: &[&str]) -> Result<bool, Error> {
    let map = object(config)?;
    for field in secret_fields {
        let Some(value) = map.get(*field) else {
            continue;
        };

        if parse_stored_secret(value)?.is_some() {
            return Ok(true);
        }

        if value.is_string() || value.is_null() {
            continue;
        }

        return Err(Error::InvalidSecretFieldType {
            field: (*field).to_string(),
        });
    }

    Ok(false)
}

#[cfg(feature = "vault")]
pub async fn encrypt_secret_fields<C: moltis_vault::Cipher>(
    config: &mut Value,
    secret_fields: &[&str],
    aad_scope: &str,
    vault: &moltis_vault::Vault<C>,
) -> Result<bool, Error> {
    let map = object_mut(config)?;
    let mut changed = false;

    for field in secret_fields {
        let Some(value) = map.get_mut(*field) else {
            continue;
        };

        match value {
            Value::String(plaintext) => {
                let ciphertext = vault
                    .encrypt_string(plaintext, &field_aad(aad_scope, field))
                    .await?;
                *value = StoredSecret::VaultEncrypted { ciphertext }.into_value()?;
                changed = true;
            },
            Value::Null => {},
            _ if parse_stored_secret(value)?.is_some() => {},
            _ => {
                return Err(Error::InvalidSecretFieldType {
                    field: (*field).to_string(),
                });
            },
        }
    }

    Ok(changed)
}

#[cfg(feature = "vault")]
pub async fn decrypt_secret_fields<C: moltis_vault::Cipher>(
    config: &mut Value,
    secret_fields: &[&str],
    aad_scope: &str,
    vault: &moltis_vault::Vault<C>,
) -> Result<bool, Error> {
    let map = object_mut(config)?;
    let mut changed = false;

    for field in secret_fields {
        let Some(value) = map.get_mut(*field) else {
            continue;
        };

        match parse_stored_secret(value)? {
            Some(StoredSecret::VaultEncrypted { ciphertext }) => {
                let plaintext = vault
                    .decrypt_string(&ciphertext, &field_aad(aad_scope, field))
                    .await?;
                *value = Value::String(plaintext);
                changed = true;
            },
            None if value.is_string() || value.is_null() => {},
            None => {
                return Err(Error::InvalidSecretFieldType {
                    field: (*field).to_string(),
                });
            },
        }
    }

    Ok(changed)
}

#[cfg(test)]
#[allow(clippy::unwrap_used, clippy::expect_used)]
mod tests {
    use super::*;

    #[cfg(feature = "vault")]
    async fn test_vault() -> moltis_vault::Vault<moltis_vault::XChaCha20Poly1305Cipher> {
        let pool = sqlx::SqlitePool::connect("sqlite::memory:").await.unwrap();
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS vault_metadata (
                id                   INTEGER PRIMARY KEY CHECK (id = 1),
                version              INTEGER NOT NULL DEFAULT 1,
                kdf_salt             TEXT NOT NULL,
                kdf_params           TEXT NOT NULL,
                wrapped_dek          TEXT NOT NULL,
                recovery_wrapped_dek TEXT,
                recovery_key_hash    TEXT,
                created_at           TEXT NOT NULL DEFAULT (datetime('now')),
                updated_at           TEXT NOT NULL DEFAULT (datetime('now'))
            )",
        )
        .execute(&pool)
        .await
        .unwrap();

        let vault = moltis_vault::Vault::with_cipher(pool, moltis_vault::XChaCha20Poly1305Cipher)
            .await
            .unwrap();
        vault.initialize("test-password").await.unwrap();
        vault
    }

    #[test]
    fn plaintext_detection_accepts_legacy_strings() {
        let config = serde_json::json!({
            "token": "secret-token",
            "room_policy": "allowlist"
        });

        assert!(has_plaintext_secret_fields(&config, &["token"]).unwrap());
        assert!(!has_encrypted_secret_fields(&config, &["token"]).unwrap());
    }

    #[cfg(feature = "vault")]
    #[tokio::test]
    async fn encrypt_and_decrypt_round_trip_secret_fields() {
        let vault = test_vault().await;
        let mut config = serde_json::json!({
            "token": "secret-token",
            "password": "hunter2",
            "room_policy": "allowlist"
        });

        let encrypted = encrypt_secret_fields(
            &mut config,
            &["token", "password"],
            "channel:matrix:test",
            &vault,
        )
        .await
        .unwrap();
        assert!(encrypted);
        assert!(has_encrypted_secret_fields(&config, &["token", "password"]).unwrap());
        assert_eq!(config["room_policy"], "allowlist");

        let decrypted = decrypt_secret_fields(
            &mut config,
            &["token", "password"],
            "channel:matrix:test",
            &vault,
        )
        .await
        .unwrap();
        assert!(decrypted);
        assert_eq!(config["token"], "secret-token");
        assert_eq!(config["password"], "hunter2");
    }

    #[cfg(feature = "vault")]
    #[tokio::test]
    async fn encrypt_skips_already_tagged_fields() {
        let vault = test_vault().await;
        let ciphertext = vault
            .encrypt_string("secret-token", "channel:telegram:bot1:token")
            .await
            .unwrap();
        let mut config = serde_json::json!({
            "token": {
                "kind": "vault_encrypted",
                "ciphertext": ciphertext
            }
        });

        let changed =
            encrypt_secret_fields(&mut config, &["token"], "channel:telegram:bot1", &vault)
                .await
                .unwrap();
        assert!(!changed);
        assert!(has_encrypted_secret_fields(&config, &["token"]).unwrap());
    }
}

//! Gateway WebSocket/RPC protocol definitions.
//!
//! Protocol version 4 (backward-compatible with v3). All communication uses JSON frames over WebSocket.
//!
//! Frame types:
//! - `RequestFrame`  — client → gateway RPC call (also server → client in v4)
//! - `ResponseFrame` — gateway → client RPC result (also client → server in v4)
//! - `EventFrame`    — gateway → client server-push

use std::collections::HashMap;

use serde::{Deserialize, Serialize};

// ── Constants ────────────────────────────────────────────────────────────────

pub const PROTOCOL_VERSION: u32 = 4;
pub const MAX_PAYLOAD_BYTES: usize = 524_288; // 512 KB
pub const MAX_BUFFERED_BYTES: usize = 1_572_864; // 1.5 MB
pub const TICK_INTERVAL_MS: u64 = 30_000; // 30s
pub const HANDSHAKE_TIMEOUT_MS: u64 = 10_000; // 10s
pub const DEDUPE_TTL_MS: u64 = 300_000; // 5 min
pub const DEDUPE_MAX_ENTRIES: usize = 1_000;

// ── Subscriptions ────────────────────────────────────────────────────────────

pub mod subscriptions {
    /// Wildcard subscription: receive all events.
    pub const WILDCARD: &str = "*";
}

// ── Error codes ──────────────────────────────────────────────────────────────

pub mod error_codes {
    // v3 backward-compat codes
    pub const NOT_LINKED: &str = "NOT_LINKED";
    pub const NOT_PAIRED: &str = "NOT_PAIRED";
    pub const AGENT_TIMEOUT: &str = "AGENT_TIMEOUT";
    pub const INVALID_REQUEST: &str = "INVALID_REQUEST";
    pub const UNAVAILABLE: &str = "UNAVAILABLE";

    // v4 standardized codes
    pub const UNKNOWN_METHOD: &str = "UNKNOWN_METHOD";
    pub const UNAUTHORIZED: &str = "UNAUTHORIZED";
    pub const FORBIDDEN: &str = "FORBIDDEN";
    pub const NOT_FOUND: &str = "NOT_FOUND";
    pub const CONFLICT: &str = "CONFLICT";
    pub const RATE_LIMITED: &str = "RATE_LIMITED";
    pub const TIMEOUT: &str = "TIMEOUT";
    pub const INTERNAL: &str = "INTERNAL";
    pub const PROTOCOL_ERROR: &str = "PROTOCOL_ERROR";
    pub const PAYLOAD_TOO_LARGE: &str = "PAYLOAD_TOO_LARGE";
}

// ── Error shape ──────────────────────────────────────────────────────────────

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ErrorShape {
    pub code: String,
    pub message: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub details: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub retryable: Option<bool>,
    #[serde(rename = "retryAfterMs", skip_serializing_if = "Option::is_none")]
    pub retry_after_ms: Option<u64>,
}

impl ErrorShape {
    pub fn new(code: impl Into<String>, message: impl Into<String>) -> Self {
        Self {
            code: code.into(),
            message: message.into(),
            details: None,
            retryable: None,
            retry_after_ms: None,
        }
    }
}

// ── Frames ───────────────────────────────────────────────────────────────────

/// Client → gateway RPC request. Also used server → client in v4 bidirectional RPC.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RequestFrame {
    pub r#type: String, // always "req"
    pub id: String,
    pub method: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub params: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub channel: Option<String>,
}

/// Gateway → client RPC response. Also client → server in v4 bidirectional RPC.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ResponseFrame {
    pub r#type: String, // always "res"
    pub id: String,
    pub ok: bool,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub payload: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error: Option<ErrorShape>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub channel: Option<String>,
}

impl ResponseFrame {
    pub fn ok(id: impl Into<String>, payload: serde_json::Value) -> Self {
        Self {
            r#type: "res".into(),
            id: id.into(),
            ok: true,
            payload: Some(payload),
            error: None,
            channel: None,
        }
    }

    pub fn err(id: impl Into<String>, error: ErrorShape) -> Self {
        Self {
            r#type: "res".into(),
            id: id.into(),
            ok: false,
            payload: None,
            error: Some(error),
            channel: None,
        }
    }
}

/// Gateway → client server-push event.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EventFrame {
    pub r#type: String, // always "event"
    pub event: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub payload: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub seq: Option<u64>,
    #[serde(rename = "stateVersion", skip_serializing_if = "Option::is_none")]
    pub state_version: Option<StateVersion>,
    /// Stream group ID for chunked delivery (v4).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub stream: Option<String>,
    /// End-of-stream marker (v4).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub done: Option<bool>,
    /// Logical channel for multiplexing (v4).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub channel: Option<String>,
}

impl EventFrame {
    pub fn new(event: impl Into<String>, payload: serde_json::Value, seq: u64) -> Self {
        Self {
            r#type: "event".into(),
            event: event.into(),
            payload: Some(payload),
            seq: Some(seq),
            state_version: None,
            stream: None,
            done: None,
            channel: None,
        }
    }

    /// Create an event frame with stream metadata.
    pub fn streamed(
        event: impl Into<String>,
        payload: serde_json::Value,
        seq: u64,
        stream_id: String,
        done: bool,
    ) -> Self {
        Self {
            r#type: "event".into(),
            event: event.into(),
            payload: Some(payload),
            seq: Some(seq),
            state_version: None,
            stream: Some(stream_id),
            done: Some(done),
            channel: None,
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct StateVersion {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub presence: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub health: Option<u64>,
}

/// Discriminated union of all frame types.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type")]
pub enum GatewayFrame {
    #[serde(rename = "req")]
    Request(RequestFrameInner),
    #[serde(rename = "res")]
    Response(ResponseFrameInner),
    #[serde(rename = "event")]
    Event(EventFrameInner),
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RequestFrameInner {
    pub id: String,
    pub method: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub params: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub channel: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ResponseFrameInner {
    pub id: String,
    pub ok: bool,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub payload: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error: Option<ErrorShape>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub channel: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EventFrameInner {
    pub event: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub payload: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub seq: Option<u64>,
    #[serde(rename = "stateVersion", skip_serializing_if = "Option::is_none")]
    pub state_version: Option<StateVersion>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub stream: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub done: Option<bool>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub channel: Option<String>,
}

// ── Extensions ───────────────────────────────────────────────────────────────

/// Namespaced extension data for protocol-agnostic transport.
pub type Extensions = HashMap<String, serde_json::Value>;

// ── Connect handshake ────────────────────────────────────────────────────────

/// Protocol version range for v4 negotiation.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProtocolRange {
    pub min: u32,
    pub max: u32,
}

/// v4 connect parameters: flat core + namespaced extensions.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ConnectParamsV4 {
    pub protocol: ProtocolRange,
    pub client: ClientInfo,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub role: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub scopes: Option<Vec<String>>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub auth: Option<ConnectAuth>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub locale: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub timezone: Option<String>,
    #[serde(default, skip_serializing_if = "HashMap::is_empty")]
    pub extensions: Extensions,
}

impl ConnectParamsV4 {
    /// Convert to v3-compatible `ConnectParams` for internal processing.
    pub fn into_connect_params(self) -> ConnectParams {
        // Extract Moltis-specific fields from extensions.
        let moltis = self.extensions.get("moltis");
        let caps = moltis
            .and_then(|v| v.get("caps"))
            .and_then(|v| serde_json::from_value(v.clone()).ok());
        let commands = moltis
            .and_then(|v| v.get("commands"))
            .and_then(|v| serde_json::from_value(v.clone()).ok());
        let permissions = moltis
            .and_then(|v| v.get("permissions"))
            .and_then(|v| v.as_object().cloned());
        let path_env = moltis
            .and_then(|v| v.get("pathEnv"))
            .and_then(|v| v.as_str())
            .map(String::from);
        let device = moltis
            .and_then(|v| v.get("device"))
            .and_then(|v| serde_json::from_value(v.clone()).ok());
        let user_agent = moltis
            .and_then(|v| v.get("userAgent"))
            .and_then(|v| v.as_str())
            .map(String::from);

        ConnectParams {
            min_protocol: self.protocol.min,
            max_protocol: self.protocol.max,
            client: self.client,
            caps,
            commands,
            permissions,
            path_env,
            role: self.role,
            scopes: self.scopes,
            device,
            auth: self.auth,
            locale: self.locale,
            user_agent,
            timezone: self.timezone,
        }
    }
}

