  1→//! Tailscale Serve/Funnel integration.
  2→//!
  3→//! Shells out to the `tailscale` CLI to manage HTTPS proxying:
  4→//! - **Serve**: exposes the gateway over HTTPS within the tailnet.
  5→//! - **Funnel**: exposes the gateway to the public internet via Tailscale.
  6→
  7→pub mod error;
  8→
  9→pub use error::{Error, Result};
 10→
 11→use std::net::IpAddr;
 12→
 13→use {
 14→    async_trait::async_trait,
 15→    serde::{Deserialize, Serialize},
 16→    tracing::{info, warn},
 17→};
 18→
 19→// ── Types ────────────────────────────────────────────────────────────────────
 20→
 21→/// Tailscale operating mode.
 22→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 23→#[serde(rename_all = "lowercase")]
 24→pub enum TailscaleMode {
 25→    Off,
 26→    Serve,
 27→    Funnel,
 28→}
 29→
 30→impl TailscaleMode {
 31→    pub fn as_str(&self) -> &'static str {
 32→        match self {
 33→            Self::Off => "off",
 34→            Self::Serve => "serve",
 35→            Self::Funnel => "funnel",
 36→        }
 37→    }
 38→}
 39→
 40→impl std::fmt::Display for TailscaleMode {
 41→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 42→        f.write_str(self.as_str())
 43→    }
 44→}
 45→
 46→impl std::str::FromStr for TailscaleMode {
 47→    type Err = Error;
 48→
 49→    fn from_str(s: &str) -> std::result::Result<Self, Self::Err> {
 50→        match s.to_lowercase().as_str() {
 51→            "off" => Ok(Self::Off),
 52→            "serve" => Ok(Self::Serve),
 53→            "funnel" => Ok(Self::Funnel),
 54→            other => Err(Error::message(format!(
 55→                "unknown tailscale mode: '{other}' (expected off, serve, or funnel)"
 56→            ))),
 57→        }
 58→    }
 59→}
 60→
 61→/// Current tailscale status.
 62→#[derive(Debug, Clone, Serialize)]
 63→pub struct TailscaleStatus {
 64→    pub mode: TailscaleMode,
 65→    pub hostname: Option<String>,
 66→    pub url: Option<String>,
 67→    pub tailscale_up: bool,
 68→    pub installed: bool,
 69→    pub tailnet: Option<String>,
 70→    pub version: Option<String>,
 71→    pub login_name: Option<String>,
 72→    pub tailscale_ip: Option<String>,
 73→}
 74→
 75→// ── Trait ─────────────────────────────────────────────────────────────────────
 76→
 77→#[async_trait]
 78→pub trait TailscaleManager: Send + Sync {
 79→    /// Get current tailscale status.
 80→    async fn status(&self) -> Result<TailscaleStatus>;
 81→    /// Enable tailscale serve proxying to the given port.
 82→    /// When `tls` is true, uses `https+insecure://` to connect to a local TLS server.
 83→    async fn enable_serve(&self, port: u16, tls: bool) -> Result<()>;
 84→    /// Enable tailscale funnel proxying to the given port.
 85→    /// When `tls` is true, uses `https+insecure://` to connect to a local TLS server.
 86→    async fn enable_funnel(&self, port: u16, tls: bool) -> Result<()>;
 87→    /// Disable serve/funnel (reset).
 88→    async fn disable(&self) -> Result<()>;
 89→    /// Get the tailscale hostname for this machine.
 90→    async fn hostname(&self) -> Result<Option<String>>;
 91→}
 92→
 93→// ── CLI-based implementation ─────────────────────────────────────────────────
 94→
 95→/// Implementation that shells out to the `tailscale` CLI binary.
 96→#[derive(Default)]
 97→pub struct CliTailscaleManager;
 98→
 99→impl CliTailscaleManager {
100→    pub fn new() -> Self {
101→        Self
102→    }
103→
104→    async fn run_command(args: &[&str]) -> Result<std::process::Output> {
105→        Self::run_command_timeout(args, std::time::Duration::from_secs(10)).await
106→    }
107→
108→    async fn run_command_timeout(
109→        args: &[&str],
110→        timeout: std::time::Duration,
111→    ) -> Result<std::process::Output> {
112→        use tokio::io::AsyncReadExt;
113→
114→        let cmd_str = format!("tailscale {}", args.join(" "));
115→        tracing::debug!(cmd = %cmd_str, "running tailscale command");
116→
117→        let mut child = tokio::process::Command::new("tailscale")
118→            .args(args)
119→            .stdout(std::process::Stdio::piped())
120→            .stderr(std::process::Stdio::piped())
121→            .spawn()
122→            .map_err(|e| Error::message(format!("failed to run tailscale CLI: {e}")))?;
123→
124→        let mut stdout_handle = child
125→            .stdout
126→            .take()
127→            .ok_or_else(|| Error::message("failed to capture tailscale stdout"))?;
128→        let mut stderr_handle = child
129→            .stderr
130→            .take()
131→            .ok_or_else(|| Error::message("failed to capture tailscale stderr"))?;
132→
133→        let mut stdout_buf = Vec::new();
134→        let mut stderr_buf = Vec::new();
135→        let mut stdout_tmp = [0u8; 4096];
136→        let mut stderr_tmp = [0u8; 4096];
137→
138→        let deadline = tokio::time::Instant::now() + timeout;
139→
140→        // Read output incrementally. If the process produces output but doesn't
141→        // exit within 2s after the last read, treat it as hanging.
142→        loop {
143→            tokio::select! {
144→                status = child.wait() => {
145→                    // Process exited — drain remaining output.
146→                    let _ = stdout_handle.read_to_end(&mut stdout_buf).await;
147→                    let _ = stderr_handle.read_to_end(&mut stderr_buf).await;
148→                    let status = status
149→                        .map_err(|e| Error::message(format!("failed to run tailscale CLI: {e}")))?;
150→                    if !status.success() {
151→                        let stderr_str = String::from_utf8_lossy(&stderr_buf);
152→                        tracing::debug!(
153→                            cmd = %cmd_str,
154→                            exit_code = ?status.code(),
155→                            stderr = %stderr_str.trim(),
156→                            "tailscale command failed"
157→                        );
158→                    }
159→                    return Ok(std::process::Output {
160→                        status,
161→                        stdout: stdout_buf,
162→                        stderr: stderr_buf,
163→                    });
164→                }
165→                n = stdout_handle.read(&mut stdout_tmp) => {
166→                    match n {
167→                        Ok(0) => {}, // EOF on stdout
168→                        Ok(n) => stdout_buf.extend_from_slice(&stdout_tmp[..n]),
169→                        Err(_) => {},
170→                    }
171→                }
172→                n = stderr_handle.read(&mut stderr_tmp) => {
173→                    match n {
174→                        Ok(0) => {}, // EOF on stderr
175→                        Ok(n) => stderr_buf.extend_from_slice(&stderr_tmp[..n]),
176→                        Err(_) => {},
177→                    }
178→                }
179→                _ = tokio::time::sleep_until(deadline) => {
180→                    break; // overall timeout
181→                }
182→            }
183→
184→            // Once we have stdout output (the meaningful content, not just
185→            // stderr warnings), give a short grace period while still reading
186→            // pipes, then bail — the process is likely waiting for user input.
187→            if !stdout_buf.is_empty() {
188→                let grace = tokio::time::Instant::now() + std::time::Duration::from_secs(2);
189→                loop {
190→                    tokio::select! {
191→                        status = child.wait() => {
192→                            let _ = stdout_handle.read_to_end(&mut stdout_buf).await;
193→                            let _ = stderr_handle.read_to_end(&mut stderr_buf).await;
194→                            let status = status
195→                                .map_err(|e| Error::message(format!("tailscale CLI: {e}")))?;
196→                            return Ok(std::process::Output {
197→                                status,
198→                                stdout: stdout_buf,
199→                                stderr: stderr_buf,
200→                            });
201→                        }
202→                        n = stdout_handle.read(&mut stdout_tmp) => {
203→                            if let Ok(n @ 1..) = n { stdout_buf.extend_from_slice(&stdout_tmp[..n]); }
204→                        }
205→                        n = stderr_handle.read(&mut stderr_tmp) => {
206→                            if let Ok(n @ 1..) = n { stderr_buf.extend_from_slice(&stderr_tmp[..n]); }
207→                        }
208→                        _ = tokio::time::sleep_until(grace) => {
209→                            break;
210→                        }
211→                    }
212→                }
213→                break; // exit outer loop after grace period
214→            }
215→        }
216→
217→        // Process is hanging — kill and return captured output as error.
218→        let _ = child.kill().await;
219→        let _ = child.wait().await;
220→
221→        let stdout_str = String::from_utf8_lossy(&stdout_buf).trim().to_string();
222→        let stderr_str = String::from_utf8_lossy(&stderr_buf).trim().to_string();
223→        warn!(
224→            cmd = %cmd_str,
225→            stdout = %stdout_str,
226→            stderr = %stderr_str,
227→            "tailscale command timed out"
228→        );
229→
230→        let combined = [stdout_str, stderr_str]
231→            .into_iter()
232→            .filter(|s| !s.is_empty())
233→            .collect::<Vec<_>>()
234→            .join("\n");
235→
236→        let msg = if combined.is_empty() {
237→            format!(
238→                "tailscale command timed out after {}s. \
239→                 Try running `{cmd_str}` in a terminal to see what's needed.",
240→                timeout.as_secs(),
241→            )
242→        } else {
243→            combined
244→        };
245→        Err(Error::message(msg))
246→    }
247→
248→    async fn parse_status_json() -> Result<serde_json::Value> {
249→        let output = Self::run_command(&["status", "--json"]).await?;
250→        if !output.status.success() {
251→            let stderr = String::from_utf8_lossy(&output.stderr);
252→            return Err(Error::message(format!("tailscale status failed: {stderr}")));
253→        }
254→        let value: serde_json::Value = serde_json::from_slice(&output.stdout)?;
255→        Ok(value)
256→    }
257→}
258→
259→#[async_trait]
260→impl TailscaleManager for CliTailscaleManager {
261→    async fn status(&self) -> Result<TailscaleStatus> {
262→        // Check if the tailscale CLI is installed.
263→        let installed = tokio::process::Command::new("tailscale")
264→            .arg("version")
265→            .stdout(std::process::Stdio::null())
266→            .stderr(std::process::Stdio::null())
267→            .status()
268→            .await
269→            .is_ok();
270→
271→        if !installed {
272→            return Ok(TailscaleStatus {
273→                mode: TailscaleMode::Off,
274→                hostname: None,
275→                url: None,
276→                tailscale_up: false,
277→                installed: false,
278→                tailnet: None,
279→                version: None,
280→                login_name: None,
281→                tailscale_ip: None,
282→            });
283→        }
284→
285→        // Parse `tailscale status --json` once to get hostname, tailnet, version, login.
286→        let (hostname, tailnet, version, login_name, tailscale_ip) =
287→            match Self::parse_status_json().await {
288→                Ok(val) => {
289→                    let dns_name = val
290→                        .pointer("/Self/DNSName")
291→                        .and_then(|v| v.as_str())
292→                        .map(|s| s.trim_end_matches('.').to_string());
293→                    let tailnet = val
294→                        .pointer("/CurrentTailnet/Name")
295→                        .and_then(|v| v.as_str())
296→                        .map(String::from);
297→                    let ver = val
298→                        .get("Version")
299→                        .and_then(|v| v.as_str())
300→                        .map(String::from);
301→                    // Find login name for the current user (Self/UserID → User map).
302→                    let login = val.pointer("/Self/UserID").and_then(|uid| {
303→                        let uid_str = uid.to_string();
304→                        val.pointer(&format!("/User/{uid_str}/LoginName"))
305→                            .and_then(|v| v.as_str())
306→                            .map(String::from)
307→                    });
308→                    // First IPv4 address from TailscaleIPs.
309→                    let ts_ip = val
310→                        .pointer("/Self/TailscaleIPs/0")
311→                        .and_then(|v| v.as_str())
312→                        .map(String::from);
313→                    (dns_name, tailnet, ver, login, ts_ip)
314→                },
315→                Err(_) => (None, None, None, None, None),
316→            };
317→
318→        let tailscale_up = hostname.is_some();
319→
320→        // Check if serve or funnel is active by looking at `tailscale serve status --json`.
321→        let serve_output = Self::run_command(&["serve", "status", "--json"]).await;
322→        let mode = match serve_output {
323→            Ok(ref out) if out.status.success() => {
324→                let body = String::from_utf8_lossy(&out.stdout);
325→                let body = body.trim();
326→                if body.is_empty() || body == "{}" || body == "null" {
327→                    TailscaleMode::Off
328→                } else if let Ok(val) = serde_json::from_str::<serde_json::Value>(body) {
329→                    if has_funnel_enabled(&val) {
330→                        TailscaleMode::Funnel
331→                    } else {
332→                        TailscaleMode::Serve
333→                    }
334→                } else {
335→                    TailscaleMode::Off
336→                }
337→            },
338→            _ => TailscaleMode::Off,
339→        };
340→
341→        let url = hostname.as_ref().map(|h| format!("https://{h}"));
342→
343→        Ok(TailscaleStatus {
344→            mode,
345→            hostname,
346→            url,
347→            tailscale_up,
348→            installed,
349→            tailnet,
350→            version,
351→            login_name,
352→            tailscale_ip,
353→        })
354→    }
355→
356→    async fn enable_serve(&self, port: u16, tls: bool) -> Result<()> {
357→        // First reset any existing serve/funnel.
358→        info!("resetting tailscale serve before enabling");
359→        let _ = Self::run_command(&["serve", "reset"]).await;
360→
361→        let target = serve_target(port, tls);
362→        info!(port, target = %target, tls, "running tailscale serve --bg");
363→        let output = Self::run_command(&["serve", "--bg", "--yes", &target]).await?;
364→        if !output.status.success() {
365→            let stderr = String::from_utf8_lossy(&output.stderr);
366→            return Err(Error::message(format!("tailscale serve failed: {stderr}")));
367→        }
368→        let stdout = String::from_utf8_lossy(&output.stdout);
369→        info!(port, stdout = %stdout.trim(), "tailscale serve enabled");
370→        Ok(())
371→    }
372→
373→    async fn enable_funnel(&self, port: u16, tls: bool) -> Result<()> {
374→        // First reset any existing serve/funnel.
375→        info!("resetting tailscale funnel before enabling");
376→        let _ = Self::run_command(&["funnel", "reset"]).await;
377→
378→        let target = serve_target(port, tls);
379→        info!(port, target = %target, tls, "running tailscale funnel --bg");
380→        let output = Self::run_command(&["funnel", "--bg", "--yes", &target]).await?;
381→        if !output.status.success() {
382→            let stderr = String::from_utf8_lossy(&output.stderr);
383→            return Err(Error::message(format!("tailscale funnel failed: {stderr}")));
384→        }
385→        let stdout = String::from_utf8_lossy(&output.stdout);
386→        info!(port, stdout = %stdout.trim(), "tailscale funnel enabled");
387→        Ok(())
388→    }
389→
390→    async fn disable(&self) -> Result<()> {
391→        let serve_out = Self::run_command(&["serve", "reset"]).await?;
392→        if !serve_out.status.success() {
393→            let stderr = String::from_utf8_lossy(&serve_out.stderr);
394→            warn!("tailscale serve reset: {stderr}");
395→        }
396→        let funnel_out = Self::run_command(&["funnel", "reset"]).await?;
397→        if !funnel_out.status.success() {
398→            let stderr = String::from_utf8_lossy(&funnel_out.stderr);
399→            warn!("tailscale funnel reset: {stderr}");
400→        }
401→        info!("tailscale serve/funnel disabled");
402→        Ok(())
403→    }
404→
405→    async fn hostname(&self) -> Result<Option<String>> {
406→        match Self::parse_status_json().await {
407→            Ok(val) => {
408→                // The JSON has a "Self" object with "DNSName" field.
409→                let dns_name = val
410→                    .pointer("/Self/DNSName")
411→                    .and_then(|v| v.as_str())
412→                    .map(|s| s.trim_end_matches('.').to_string());
413→                Ok(dns_name)
414→            },
415→            Err(_) => Ok(None),
416→        }
417→    }
418→}
419→
420→// ── Helpers ──────────────────────────────────────────────────────────────────
421→
422→/// Build the target URL for tailscale serve/funnel.
423→/// When the gateway uses TLS, tailscale needs `https+insecure://` to proxy to a
424→/// server with a self-signed certificate.
425→fn serve_target(port: u16, tls: bool) -> String {
426→    if tls {
427→        format!("https+insecure://127.0.0.1:{port}")
428→    } else {
429→        format!("http://127.0.0.1:{port}")
430→    }
431→}
432→
433→/// Check if the serve status JSON indicates funnel is enabled.
434→fn has_funnel_enabled(val: &serde_json::Value) -> bool {
435→    // tailscale serve status --json returns something like:
436→    // { "TCP": { "443": { "HTTPS": true } }, "AllowFunnel": { "443": true } }
