  1→//! TLS certificate management and HTTPS server support.
  2→//!
  3→//! On first run, generates a local CA and server certificate (mkcert-style)
  4→//! so the gateway can serve HTTPS out of the box. A companion plain-HTTP
  5→//! server on a secondary port serves the CA cert for easy download and
  6→//! redirects everything else to HTTPS.
  7→
  8→pub mod error;
  9→
 10→pub use error::{Context, Error, Result};
 11→
 12→use std::{
 13→    collections::BTreeSet,
 14→    io::BufReader,
 15→    net::{IpAddr, SocketAddr},
 16→    path::{Path, PathBuf},
 17→    sync::Arc,
 18→    time::SystemTime,
 19→};
 20→
 21→use {
 22→    axum::{Router, extract::State, response::IntoResponse, routing::get},
 23→    rcgen::{BasicConstraints, CertificateParams, DnType, IsCa, KeyPair, KeyUsagePurpose, SanType},
 24→    rustls::ServerConfig,
 25→    time::OffsetDateTime,
 26→    tokio::{
 27→        io::AsyncWriteExt,
 28→        net::{TcpListener, TcpStream},
 29→    },
 30→    tracing::{debug, info},
 31→};
 32→
 33→/// The hostname used for loopback URLs instead of raw `127.0.0.1`.
 34→/// Subdomains of `.localhost` resolve to loopback per RFC 6761.
 35→pub const LOCALHOST_DOMAIN: &str = "moltis.localhost";
 36→
 37→/// Additional SAN entries that should be present on the auto-generated server
 38→/// certificate for this runtime.
 39→#[derive(Clone, Debug, Eq, Ord, PartialEq, PartialOrd)]
 40→pub enum ServerSan {
 41→    Dns(String),
 42→    Ip(IpAddr),
 43→}
 44→
 45→impl ServerSan {
 46→    fn metadata_line(&self) -> String {
 47→        match self {
 48→            Self::Dns(name) => format!("dns:{name}"),
 49→            Self::Ip(ip) => format!("ip:{ip}"),
 50→        }
 51→    }
 52→
 53→    fn from_metadata_line(line: &str) -> Option<Self> {
 54→        let (kind, value) = line.split_once(':')?;
 55→        match kind {
 56→            "dns" if !value.is_empty() => Some(Self::Dns(value.to_string())),
 57→            "ip" => value.parse().ok().map(Self::Ip),
 58→            _ => None,
 59→        }
 60→    }
 61→}
 62→
 63→/// DNS SAN names that must always exist on generated server certificates.
 64→fn required_dns_san_names() -> Vec<String> {
 65→    let mut names = vec![
 66→        LOCALHOST_DOMAIN.to_string(),
 67→        format!("*.{LOCALHOST_DOMAIN}"),
 68→        "localhost".to_string(),
 69→    ];
 70→
 71→    if let Some(hostname) = hostname::get()
 72→        .ok()
 73→        .and_then(|host| host.into_string().ok())
 74→    {
 75→        append_system_host_sans(&mut names, &hostname);
 76→    }
 77→
 78→    names.sort_unstable();
 79→    names.dedup();
 80→    names
 81→}
 82→
 83→fn append_system_host_sans(names: &mut Vec<String>, hostname: &str) {
 84→    let normalized = hostname.trim().trim_end_matches('.').to_ascii_lowercase();
 85→
 86→    if normalized.is_empty() || normalized == "localhost" || normalized == LOCALHOST_DOMAIN {
 87→        return;
 88→    }
 89→
 90→    names.push(normalized.clone());
 91→    if !normalized.contains('.') {
 92→        names.push(format!("{normalized}.local"));
 93→    }
 94→}
 95→
 96→fn default_required_sans() -> Vec<ServerSan> {
 97→    let mut sans = required_dns_san_names()
 98→        .into_iter()
 99→        .map(ServerSan::Dns)
100→        .collect::<Vec<_>>();
101→    sans.push(ServerSan::Ip(IpAddr::V4(std::net::Ipv4Addr::LOCALHOST)));
102→    sans.push(ServerSan::Ip(IpAddr::V6(std::net::Ipv6Addr::LOCALHOST)));
103→    normalize_sans(sans)
104→}
105→
106→fn required_server_sans(runtime_sans: &[ServerSan]) -> Vec<ServerSan> {
107→    normalize_sans(
108→        default_required_sans()
109→            .into_iter()
110→            .chain(runtime_sans.iter().cloned()),
111→    )
112→}
113→
114→fn normalize_sans(sans: impl IntoIterator<Item = ServerSan>) -> Vec<ServerSan> {
115→    sans.into_iter()
116→        .collect::<BTreeSet<_>>()
117→        .into_iter()
118→        .collect()
119→}
120→
121→fn is_default_loopback_ip(ip: &IpAddr) -> bool {
122→    matches!(
123→        ip,
124→        IpAddr::V4(v4) if *v4 == std::net::Ipv4Addr::LOCALHOST
125→    ) || matches!(
126→        ip,
127→        IpAddr::V6(v6) if *v6 == std::net::Ipv6Addr::LOCALHOST
128→    )
129→}
130→
131→fn der_contains_ascii(der: &[u8], needle: &str) -> bool {
132→    der.windows(needle.len())
133→        .any(|window| window == needle.as_bytes())
134→}
135→
136→/// Trait for TLS certificate management, allowing alternative implementations.
137→pub trait CertManager: Send + Sync {
138→    /// Returns (ca_cert_path, server_cert_path, server_key_path).
139→    /// Generates certificates if they don't exist or are expired.
140→    fn ensure_certs(&self, runtime_sans: &[ServerSan]) -> Result<(PathBuf, PathBuf, PathBuf)>;
141→
142→    /// Build a `rustls::ServerConfig` from the given cert and key PEM files.
143→    fn build_rustls_config(&self, cert: &Path, key: &Path) -> Result<ServerConfig>;
144→}
145→
146→/// Default file-system-backed certificate manager.
147→pub struct FsCertManager {
148→    cert_dir: PathBuf,
149→}
150→
151→impl FsCertManager {
152→    pub fn new() -> Result<Self> {
153→        let dir = cert_dir()?;
154→        Ok(Self { cert_dir: dir })
155→    }
156→
157→    #[allow(clippy::unwrap_used, clippy::expect_used)]
158→    #[cfg(test)]
159→    pub fn with_dir(dir: PathBuf) -> Self {
160→        Self { cert_dir: dir }
161→    }
162→}
163→
164→/// Returns the certificate storage directory (`~/.config/moltis/certs/`).
165→pub fn cert_dir() -> Result<PathBuf> {
166→    let dir = moltis_config::config_dir()
167→        .unwrap_or_else(|| PathBuf::from(".moltis"))
168→        .join("certs");
169→    std::fs::create_dir_all(&dir).context("failed to create certs directory")?;
170→    Ok(dir)
171→}
172→
173→impl CertManager for FsCertManager {
174→    fn ensure_certs(&self, runtime_sans: &[ServerSan]) -> Result<(PathBuf, PathBuf, PathBuf)> {
175→        let ca_cert_path = self.cert_dir.join("ca.pem");
176→        let ca_key_path = self.cert_dir.join("ca-key.pem");
177→        let server_cert_path = self.cert_dir.join("server.pem");
178→        let server_key_path = self.cert_dir.join("server-key.pem");
179→        let server_sans_path = self.cert_dir.join("server-sans.txt");
180→        let required_sans = required_server_sans(runtime_sans);
181→
182→        let need_regen = !ca_cert_path.exists()
183→            || !server_cert_path.exists()
184→            || !server_key_path.exists()
185→            || is_expired(&server_cert_path, &server_sans_path, 30, &required_sans);
186→
187→        if need_regen {
188→            info!("generating TLS certificates");
189→            let (ca_cert_pem, ca_key_pem, server_cert_pem, server_key_pem) =
190→                generate_all(&required_sans)?;
191→            std::fs::write(&ca_cert_path, &ca_cert_pem)?;
192→            std::fs::write(&ca_key_path, &ca_key_pem)?;
193→            std::fs::write(&server_cert_path, &server_cert_pem)?;
194→            std::fs::write(&server_key_path, &server_key_pem)?;
195→            write_san_metadata(&server_sans_path, &required_sans)?;
196→            info!(dir = %self.cert_dir.display(), "certificates written");
197→        }
198→
199→        Ok((ca_cert_path, server_cert_path, server_key_path))
200→    }
201→
202→    fn build_rustls_config(&self, cert: &Path, key: &Path) -> Result<ServerConfig> {
203→        load_rustls_config(cert, key)
204→    }
205→}
206→
207→/// Check if a PEM cert file needs regeneration.
208→///
209→/// Returns `true` when the file is older than `days` days (proxy for
210→/// approaching expiry) **or** when it was generated before required DNS SANs
211→/// were added. The DER-encoded cert contains
212→/// DNS names as raw ASCII (IA5String), so a byte search on the decoded
213→/// DER is sufficient to detect the missing SAN.
214→fn is_expired(
215→    path: &Path,
216→    san_metadata_path: &Path,
217→    days: u64,
218→    required_sans: &[ServerSan],
219→) -> bool {
220→    let Ok(meta) = std::fs::metadata(path) else {
221→        return true;
222→    };
223→    let Ok(modified) = meta.modified() else {
224→        return true;
225→    };
226→    let age = SystemTime::now()
227→        .duration_since(modified)
228→        .unwrap_or_default();
229→    if age > time::Duration::days(days as i64).unsigned_abs() {
230→        return true;
231→    }
232→    needs_san_update(path, san_metadata_path, required_sans)
233→}
234→
235→/// Returns `true` if the cert at `path` does not contain the currently
236→/// required DNS SANs (i.e. was generated before the latest SAN migration).
237→fn needs_san_update(path: &Path, san_metadata_path: &Path, required_sans: &[ServerSan]) -> bool {
238→    if let Some(existing_sans) = read_san_metadata(san_metadata_path) {
239→        return required_sans
240→            .iter()
241→            .any(|entry| !existing_sans.contains(entry));
242→    }
243→
244→    let Ok(pem_bytes) = std::fs::read(path) else {
245→        return true;
246→    };
247→    let certs: Vec<_> = rustls_pemfile::certs(&mut BufReader::new(pem_bytes.as_slice()))
248→        .filter_map(|r| r.ok())
249→        .collect();
250→    if certs.is_empty() {
251→        return true;
252→    }
253→    let der = certs[0].as_ref();
254→    required_sans.iter().any(|entry| match entry {
255→        // Wildcard entries are not required for compatibility checks.
256→        ServerSan::Dns(name) if !name.starts_with("*.") => !der_contains_ascii(der, name),
257→        // Legacy certs do not carry SAN metadata, so require one regeneration
258→        // to pick up any non-loopback runtime IPs.
259→        ServerSan::Ip(ip) if !is_default_loopback_ip(ip) => true,
260→        _ => false,
261→    })
262→}
263→
264→fn read_san_metadata(path: &Path) -> Option<Vec<ServerSan>> {
265→    let contents = std::fs::read_to_string(path).ok()?;
266→    let mut sans = Vec::new();
267→    sans.extend(
268→        contents
269→            .lines()
270→            .map(str::trim)
271→            .filter(|line| !line.is_empty())
272→            .filter_map(ServerSan::from_metadata_line),
273→    );
274→    Some(normalize_sans(sans))
275→}
276→
277→fn write_san_metadata(path: &Path, sans: &[ServerSan]) -> Result<()> {
278→    let contents = sans
279→        .iter()
280→        .map(ServerSan::metadata_line)
281→        .collect::<Vec<_>>()
282→        .join("\n");
283→    let contents = if contents.is_empty() {
284→        String::new()
285→    } else {
286→        format!("{contents}\n")
287→    };
288→    std::fs::write(path, contents).context("write server SAN metadata")?;
289→    Ok(())
290→}
291→
292→/// Generate CA + server certificates. Returns (ca_cert, ca_key, server_cert, server_key) PEM strings.
293→fn generate_all(required_sans: &[ServerSan]) -> Result<(String, String, String, String)> {
294→    let now = OffsetDateTime::now_utc();
295→
296→    // --- CA ---
297→    let ca_key = KeyPair::generate()?;
298→    let mut ca_params = CertificateParams::new(Vec::<String>::new())?;
299→    ca_params
300→        .distinguished_name
301→        .push(DnType::CommonName, "Moltis Local CA");
302→    ca_params
303→        .distinguished_name
304→        .push(DnType::OrganizationName, "Moltis");
305→    ca_params.is_ca = IsCa::Ca(BasicConstraints::Unconstrained);
306→    ca_params.key_usages = vec![KeyUsagePurpose::KeyCertSign, KeyUsagePurpose::CrlSign];
307→    // 10-year validity from today.
308→    ca_params.not_before = now;
309→    ca_params.not_after = now + time::Duration::days(365 * 10);
310→    let ca_cert = ca_params.self_signed(&ca_key)?;
311→
312→    // --- Server cert signed by CA ---
313→    let server_key = KeyPair::generate()?;
314→    let mut server_params = CertificateParams::new(vec![LOCALHOST_DOMAIN.to_string()])?;
315→    server_params
316→        .distinguished_name
317→        .push(DnType::CommonName, LOCALHOST_DOMAIN);
318→    let subject_alt_names: Vec<SanType> = required_sans
319→        .iter()
320→        .filter_map(|entry| match entry {
321→            ServerSan::Dns(name) => name.as_str().try_into().ok().map(SanType::DnsName),
322→            ServerSan::Ip(ip) => Some(SanType::IpAddress(*ip)),
323→        })
324→        .collect();
325→    server_params.subject_alt_names = subject_alt_names;
326→    // 1-year validity from today.
327→    server_params.not_before = now;
328→    server_params.not_after = now + time::Duration::days(365);
329→    let server_cert = server_params.signed_by(&server_key, &ca_cert, &ca_key)?;
330→
331→    Ok((
332→        ca_cert.pem(),
333→        ca_key.serialize_pem(),
334→        server_cert.pem(),
335→        server_key.serialize_pem(),
336→    ))
337→}
338→
339→/// Load cert + key PEM files into a `rustls::ServerConfig`.
340→fn load_rustls_config(cert_path: &Path, key_path: &Path) -> Result<ServerConfig> {
341→    // Ensure a crypto provider is installed (ring via feature flag).
342→    let _ = rustls::crypto::ring::default_provider().install_default();
343→    let cert_file = std::fs::File::open(cert_path).context("open server cert")?;
344→    let key_file = std::fs::File::open(key_path).context("open server key")?;
345→
346→    let certs: Vec<_> = rustls_pemfile::certs(&mut BufReader::new(cert_file))
347→        .collect::<std::result::Result<Vec<_>, _>>()
348→        .context("parse certs")?;
349→
350→    let key = rustls_pemfile::private_key(&mut BufReader::new(key_file))
351→        .context("parse private key")?
352→        .context("no private key found")?;
353→
354→    let mut config = ServerConfig::builder()
355→        .with_no_client_auth()
356→        .with_single_cert(certs, key)
357→        .context("build rustls ServerConfig")?;
358→    config.alpn_protocols = vec![b"h2".to_vec(), b"http/1.1".to_vec()];
359→    Ok(config)
360→}
361→
362→// ── Plain-HTTP redirect server ──────────────────────────────────────────────
363→
364→#[derive(Clone)]
365→struct HttpRedirectState {
366→    https_port: u16,
367→    ca_pem: Arc<Vec<u8>>,
368→    localhost_mode: bool,
369→    bind_host: String,
370→}
371→
372→fn is_localhost_name(name: &str) -> bool {
373→    matches!(name, "localhost" | "127.0.0.1" | "::1") || name.ends_with(".localhost")
374→}
375→
376→fn host_from_headers(headers: &axum::http::HeaderMap) -> Option<String> {
377→    use axum::http::uri::Authority;
378→
379→    let raw = headers.get(axum::http::header::HOST)?.to_str().ok()?;
380→    let authority: Authority = raw.parse().ok()?;
381→    Some(authority.host().to_string())
382→}
383→
384→fn format_url_host(host: &str) -> String {
385→    if host.contains(':') && !host.starts_with('[') {
386→        format!("[{host}]")
387→    } else {
388→        host.to_string()
389→    }
390→}
391→
392→/// Start a plain-HTTP server that serves the CA cert and redirects to HTTPS.
393→pub async fn start_http_redirect_server(
394→    bind: &str,
395→    http_port: u16,
396→    https_port: u16,
397→    ca_cert_path: &Path,
398→) -> Result<()> {
399→    let ca_pem = std::fs::read(ca_cert_path).context("read CA cert")?;
400→    let localhost_mode = is_localhost_name(bind);
401→    let state = HttpRedirectState {
402→        https_port,
403→        ca_pem: Arc::new(ca_pem),
404→        localhost_mode,
405→        bind_host: bind.to_string(),
406→    };
407→
408→    let app = Router::new()
409→        .route("/certs/ca.pem", get(serve_ca_cert))
410→        .fallback(redirect_to_https)
411→        .with_state(state);
412→
413→    let ip: IpAddr = bind
414→        .parse()
415→        .with_context(|| format!("invalid bind address '{bind}'"))?;
416→    let addr = SocketAddr::new(ip, http_port);
417→    let listener = TcpListener::bind(addr).await?;
418→    let display_host = if localhost_mode {
419→        "localhost"
420→    } else {
421→        bind
422→    };
423→    info!(
424→        "HTTP redirect server listening http://{}:{http_port}/certs/ca.pem",
425→        display_host
426→    );
427→    axum::serve(listener, app).await?;
428→    Ok(())
429→}
430→
431→async fn serve_ca_cert(State(state): State<HttpRedirectState>) -> impl IntoResponse {
432→    (
433→        [
434→            ("content-type", "application/x-pem-file"),
435→            (
436→                "content-disposition",
437→                "attachment; filename=\"moltis-ca.pem\"",
438→            ),
439→        ],
440→        state.ca_pem.as_ref().clone(),
441→    )
442→}
443→
444→async fn redirect_to_https(
445→    State(state): State<HttpRedirectState>,
446→    headers: axum::http::HeaderMap,
447→    uri: axum::http::Uri,
448→) -> impl IntoResponse {
449→    let host = if state.localhost_mode {
450→        "localhost".to_string()
451→    } else {
452→        host_from_headers(&headers).unwrap_or_else(|| state.bind_host.clone())
453→    };
454→    let path_and_query = uri.path_and_query().map_or("/", |pq| pq.as_str());
455→    let target = format!(
456→        "https://{}:{}{}",
457→        format_url_host(&host),
458→        state.https_port,
459→        path_and_query
460→    );
461→    axum::response::Redirect::temporary(&target)
462→}
463→
464→// ── TLS server with HTTP redirect ───────────────────────────────────────────
465→
466→/// Serve an axum app over TLS on a single port, with automatic HTTP-to-HTTPS
467→/// redirect for plain HTTP requests.
468→///
469→/// When a client connects with plain HTTP instead of TLS, a 301 redirect is
470→/// sent pointing to the HTTPS URL. This prevents the "broken page" that users
471→/// see when accidentally navigating to `http://host:port/` instead of `https://`.
472→pub async fn serve_tls_with_http_redirect(
473→    listener: TcpListener,
474→    tls_config: Arc<ServerConfig>,
475→    app: Router,
476→    port: u16,
477→    bind_host: &str,
478→) -> Result<()> {
479→    let acceptor = tokio_rustls::TlsAcceptor::from(tls_config);
480→    let localhost_mode = is_localhost_name(bind_host);
481→    let bind_host = bind_host.to_string();
482→
483→    // Create the make_service so ConnectInfo<SocketAddr> works in handlers.
484→    let mut make_service = app.into_make_service_with_connect_info::<SocketAddr>();
485→
486→    loop {
487→        let (stream, addr) = match listener.accept().await {
488→            Ok(conn) => conn,
489→            Err(e) => {
490→                if is_accept_error(&e) {
491→                    continue;
492→                }
493→                tracing::error!("accept error: {e}");
494→                tokio::time::sleep(std::time::Duration::from_secs(1)).await;
495→                continue;
496→            },
497→        };
498→
499→        // Peek at the first byte to distinguish TLS from plain HTTP.
500→        // TLS ClientHello always starts with 0x16 (ContentType::Handshake).

500→        // TLS ClientHello always starts with 0x16 (ContentType::Handshake).
501→        let mut peek_buf = [0u8; 1];
502→        match stream.peek(&mut peek_buf).await {
503→            Ok(1) if peek_buf[0] == 0x16 => {
504→                // TLS — hand off to a per-connection task.
505→                let acceptor = acceptor.clone();
506→                let service = <_ as tower::Service<SocketAddr>>::call(&mut make_service, addr)
507→                    .await
508→                    .unwrap_or_else(|e| match e {});
509→                tokio::spawn(async move {
510→                    let Ok(tls_stream) = acceptor.accept(stream).await.inspect_err(|e| {
511→                        debug!("TLS handshake failed from {addr}: {e}");
512→                    }) else {
513→                        return;
514→                    };
515→                    let io = hyper_util::rt::TokioIo::new(tls_stream);
516→                    let hyper_service = hyper_util::service::TowerToHyperService::new(service);
517→                    if let Err(e) = hyper_util::server::conn::auto::Builder::new(
518→                        hyper_util::rt::TokioExecutor::new(),
519→                    )
520→                    .serve_connection_with_upgrades(io, hyper_service)
521→                    .await
522→                    {
523→                        debug!("connection error from {addr}: {e}");
524→                    }
525→                });
526→            },
527→            Ok(_) => {
528→                // Plain HTTP — send redirect in a background task.
529→                let redirect_host = bind_host.clone();
530→                tokio::spawn(async move {
531→                    if let Err(e) =
532→                        send_http_redirect(stream, port, &redirect_host, localhost_mode).await
533→                    {
534→                        debug!("HTTP redirect to {addr} failed: {e}");
535→                    }
536→                });
537→            },
538→            Err(e) => {
539→                debug!("peek failed from {addr}: {e}");
540→            },
541→        }
542→    }
543→}
