545→fn is_accept_error(e: &std::io::Error) -> bool {
546→    matches!(
547→        e.kind(),
548→        std::io::ErrorKind::ConnectionRefused
549→            | std::io::ErrorKind::ConnectionAborted
550→            | std::io::ErrorKind::ConnectionReset
551→    )
552→}
