554→/// Read a plain HTTP request from a TCP stream and send a 301 redirect to HTTPS.
555→async fn send_http_redirect(
556→    mut stream: TcpStream,
557→    https_port: u16,
558→    bind_host: &str,
559→    localhost_mode: bool,
560→) -> Result<()> {
561→    // Read enough to parse the request line and Host header.
562→    let mut buf = vec![0u8; 4096];
563→    let n = tokio::time::timeout(std::time::Duration::from_secs(5), stream.peek(&mut buf))
564→        .await
565→        .context("timeout reading HTTP request")?
566→        .context("reading HTTP request")?;
567→
568→    let raw = String::from_utf8_lossy(&buf[..n]);
569→
570→    // Parse request path from first line: "GET /path HTTP/1.x"
571→    let path = raw
572→        .lines()
573→        .next()
574→        .and_then(|line| line.split_whitespace().nth(1))
575→        .unwrap_or("/");
576→
577→    // Parse Host header, stripping port if present.
578→    let host = if localhost_mode {
579→        "localhost".to_string()
580→    } else {
581→        raw.lines()
582→            .find_map(|line| {
583→                if line.get(..5)?.eq_ignore_ascii_case("host:") {
584→                    let value = line[5..].trim();
585→                    // Use Authority parser to correctly handle IPv6, ports, etc.
586→                    if let Ok(authority) = value.parse::<axum::http::uri::Authority>() {
587→                        Some(authority.host().to_string())
588→                    } else {
589→                        Some(value.to_string())
590→                    }
591→                } else {
592→                    None
593→                }
594→            })
595→            .unwrap_or_else(|| bind_host.to_string())
596→    };
597→
598→    let location = format!("https://{}:{}{}", format_url_host(&host), https_port, path);
599→    let body =
600→        format!("<html><body>Redirecting to <a href=\"{location}\">{location}</a></body></html>");
601→    let response = format!(
602→        "HTTP/1.1 301 Moved Permanently\r\n\
603→         Location: {location}\r\n\
604→         Content-Type: text/html\r\n\
605→         Content-Length: {}\r\n\
606→         Connection: close\r\n\
607→         \r\n\
608→         {body}",
609→        body.len()
610→    );
611→
612→    stream.write_all(response.as_bytes()).await?;
613→    stream.shutdown().await?;
614→    Ok(())
615→}
