        let json = serde_json::to_value(&frame).unwrap();
        assert!(!json.as_object().unwrap().contains_key("stream"));
        assert!(!json.as_object().unwrap().contains_key("done"));
        assert!(!json.as_object().unwrap().contains_key("channel"));
