    #[test]
    fn host_from_headers_strips_port() {
        let mut headers = axum::http::HeaderMap::new();
        headers.insert(
            axum::http::header::HOST,
            "example.com:8080".parse().unwrap(),
        );
        assert_eq!(host_from_headers(&headers).as_deref(), Some("example.com"));
    }

