105→impl GitHubCopilotProvider {
106→    pub fn new(model: String) -> Self {
107→        Self {
108→            model,
109→            client: crate::shared_http_client(),
110→            token_store: TokenStore::new(),
111→        }
112→    }
113→
114→    /// Start the GitHub device-flow: request a device code from GitHub.
115→    pub async fn request_device_code(
116→        client: &reqwest::Client,
117→    ) -> anyhow::Result<DeviceCodeResponse> {
118→        let resp = client
119→            .post(GITHUB_DEVICE_CODE_URL)
120→            .header("Accept", "application/json")
121→            .form(&[("client_id", GITHUB_CLIENT_ID), ("scope", "")])
122→            .send()
123→            .await?;
124→
125→        if !resp.status().is_success() {
126→            let body = resp.text().await.unwrap_or_default();
127→            anyhow::bail!("GitHub device code request failed: {body}");
128→        }
129→
130→        Ok(resp.json().await?)
131→    }
132→
133→    /// Poll GitHub for the access token after the user has entered the code.
134→    pub async fn poll_for_token(
135→        client: &reqwest::Client,
136→        device_code: &str,
137→        interval: u64,
138→    ) -> anyhow::Result<String> {
139→        loop {
140→            tokio::time::sleep(Duration::from_secs(interval)).await;
141→
142→            let resp = client
143→                .post(GITHUB_TOKEN_URL)
144→                .header("Accept", "application/json")
145→                .form(&[
146→                    ("client_id", GITHUB_CLIENT_ID),
147→                    ("device_code", device_code),
148→                    ("grant_type", "urn:ietf:params:oauth:grant-type:device_code"),
149→                ])
150→                .send()
151→                .await?;
152→
153→            let body: GithubTokenResponse = resp.json().await?;
154→
155→            if let Some(token) = body.access_token {
156→                return Ok(token);
157→            }
158→
159→            match body.error.as_deref() {
160→                Some("authorization_pending") => continue,
161→                Some("slow_down") => {
162→                    tokio::time::sleep(Duration::from_secs(5)).await;
163→                    continue;
164→                },
165→                Some(err) => anyhow::bail!("GitHub device flow error: {err}"),
166→                None => anyhow::bail!("unexpected response from GitHub token endpoint"),
167→            }
168→        }
169→    }
170→
171→    /// Get a valid Copilot API token and resolved base URL.
172→    async fn get_copilot_auth(&self) -> anyhow::Result<CopilotAuth> {
173→        fetch_copilot_auth_with_fallback(self.client, &self.token_store).await
174→    }
175→}
