182→fn token_store_with_provider_tokens(primary: &TokenStore) -> Option<TokenStore> {
183→    debug!("checking primary token store for {PROVIDER_NAME}");
184→    if primary.load(PROVIDER_NAME).is_some() {
185→        debug!("found {PROVIDER_NAME} tokens in primary store");
186→        return Some(primary.clone());
187→    }
188→    if let Some(home_store) = home_token_store_if_different() {
189→        debug!("checking home token store for {PROVIDER_NAME}");
190→        if home_store.load(PROVIDER_NAME).is_some() {
191→            debug!("found {PROVIDER_NAME} tokens in home store");
192→            return Some(home_store);
193→        }
194→    }
195→    debug!("{PROVIDER_NAME} tokens not found in any store");
196→    None
197→}
