228→/// Build a [`CopilotAuth`] from an `account_id` value that may contain a
229→/// proxy-ep hostname persisted from a previous token exchange.
230→fn copilot_auth_from_parts(token: Secret<String>, proxy_ep: Option<&str>) -> CopilotAuth {
231→    match proxy_ep.filter(|s| !s.is_empty()) {
232→        Some(ep) => {
233→            let ep = ep.trim();
234→            // Reject anything that isn't a plain hostname to prevent SSRF via
235→            // crafted proxy-ep values (e.g. internal IPs, @-redirects).
236→            if !ep
237→                .chars()
238→                .all(|c| c.is_ascii_alphanumeric() || matches!(c, '.' | '-'))
239→            {
240→                warn!(proxy_ep = %ep, "ignoring malformed proxy-ep, falling back to individual endpoint");
241→                return CopilotAuth {
242→                    token,
243→                    base_url: COPILOT_API_BASE.to_string(),
244→                    is_enterprise: false,
245→                };
246→            }
247→            // Reject bare IP addresses (v4/v6) to prevent SSRF against cloud
248→            // metadata services, loopback, and RFC-1918 ranges.
249→            if ep.parse::<std::net::IpAddr>().is_ok() {
250→                warn!(proxy_ep = %ep, "ignoring IP-address proxy-ep, falling back to individual endpoint");
251→                return CopilotAuth {
252→                    token,
253→                    base_url: COPILOT_API_BASE.to_string(),
254→                    is_enterprise: false,
255→                };
256→            }
257→            debug!(proxy_ep = %ep, "using enterprise proxy endpoint");
258→            CopilotAuth {
259→                token,
260→                base_url: format!("https://{ep}"),
261→                is_enterprise: true,
262→            }
263→        },
264→        None => CopilotAuth {
265→            token,
266→            base_url: COPILOT_API_BASE.to_string(),
267→            is_enterprise: false,
268→        },
269→    }
270→}
271→
272→async fn fetch_copilot_auth(
273→    client: &reqwest::Client,
274→    token_store: &TokenStore,
275→) -> anyhow::Result<CopilotAuth> {
276→    let tokens = token_store.load(PROVIDER_NAME).ok_or_else(|| {
277→        anyhow::anyhow!("not logged in to github-copilot — run OAuth device flow first")
278→    })?;
279→
280→    // The `access_token` stored is the GitHub user token.
281→    // We exchange it for a short-lived Copilot API token and cache it.
282→    // The proxy-ep (if any) is persisted in the `account_id` field.
283→    if let Some(copilot_tokens) = token_store.load("github-copilot-api")
284→        && let Some(expires_at) = copilot_tokens.expires_at
285→    {
286→        let now = std::time::SystemTime::now()
287→            .duration_since(std::time::UNIX_EPOCH)
288→            .unwrap_or_default()
289→            .as_secs();
290→        if now + 60 < expires_at {
291→            let token = copilot_tokens.access_token.clone();
292→            let proxy_ep = copilot_tokens.account_id.as_deref();
293→            return Ok(copilot_auth_from_parts(token, proxy_ep));
294→        }
295→    }
296→
297→    let resp = client
298→        .get(COPILOT_TOKEN_URL)
299→        .header(
300→            "Authorization",
301→            format!("token {}", tokens.access_token.expose_secret()),
302→        )
303→        .header("Accept", "application/json")
304→        .header(
305→            "User-Agent",
306→            "moltis/0.1.0 (GitHub Copilot compatible client)",
307→        )
308→        .send()
309→        .await?;
310→
311→    if !resp.status().is_success() {
312→        let body = resp.text().await.unwrap_or_default();
313→        anyhow::bail!("Copilot token exchange failed: {body}");
314→    }
315→
316→    let copilot_resp: CopilotTokenResponse = resp.json().await?;
317→    let _ = token_store.save("github-copilot-api", &OAuthTokens {
318→        access_token: copilot_resp.token.clone(),
319→        refresh_token: None,
320→        id_token: None,
321→        // NOTE: account_id is repurposed here to persist the enterprise
322→        // proxy-ep hostname so it can be recovered from the token cache.
323→        account_id: copilot_resp.proxy_ep.clone(),
324→        expires_at: Some(copilot_resp.expires_at),
325→    });
326→
327→    Ok(copilot_auth_from_parts(
328→        copilot_resp.token,
329→        copilot_resp.proxy_ep.as_deref(),
330→    ))
331→}
