415→fn parse_models_payload(value: &serde_json::Value) -> Vec<super::DiscoveredModel> {
416→    let mut candidates = Vec::new();
417→    collect_candidate_arrays(value, &mut candidates);
418→
419→    let mut models = Vec::new();
420→    let mut seen = HashSet::new();
421→    for entry in candidates {
422→        if let Some(model) = parse_model_entry(entry)
423→            && seen.insert(model.id.clone())
424→        {
425→            models.push(model);
426→        }
427→    }
428→
429→    // Sort by created_at descending (newest first). Models without a
430→    // timestamp are placed after those with one, preserving relative order.
431→    models.sort_by(|a, b| match (a.created_at, b.created_at) {
432→        (Some(a_ts), Some(b_ts)) => b_ts.cmp(&a_ts), // newest first
433→        (Some(_), None) => std::cmp::Ordering::Less, // timestamp before no-timestamp
434→        (None, Some(_)) => std::cmp::Ordering::Greater,
435→        (None, None) => std::cmp::Ordering::Equal,
436→    });
437→
438→    models
439→}
