469→/// Spawn model discovery in a background thread and return the receiver
470→/// immediately, without blocking.
471→pub fn start_model_discovery() -> mpsc::Receiver<anyhow::Result<Vec<super::DiscoveredModel>>> {
472→    let (tx, rx) = mpsc::sync_channel(1);
473→    std::thread::spawn(move || {
474→        let result = tokio::runtime::Builder::new_current_thread()
475→            .enable_all()
476→            .build()
477→            .map_err(anyhow::Error::from)
478→            .and_then(|rt| {
479→                rt.block_on(async {
480→                    let client = reqwest::Client::builder()
481→                        .timeout(Duration::from_secs(8))
482→                        .build()?;
483→                    let token_store = TokenStore::new();
484→                    let auth = fetch_copilot_auth_with_fallback(&client, &token_store).await?;
485→                    fetch_models_from_api(&client, &auth).await
486→                })
487→            });
488→        let _ = tx.send(result);
489→    });
490→    rx
491→}
