206→        }
207→
208→        let key = resolve_api_key(config, def.config_name, def.env_key, env_overrides);
209→        let key = if !def.requires_api_key {
210→            key.or_else(|| Some(secrecy::Secret::new(def.config_name.into())))
211→        } else if def.config_name == "gemini" {
212→            key.or_else(|| env_value(env_overrides, "GOOGLE_API_KEY").map(secrecy::Secret::new))
213→        } else {
214→            key
215→        };
216→        let Some(key) = key else {
217→            continue;
218→        };
219→
220→        let base_url = config
221→            .get(def.config_name)
222→            .and_then(|e| e.base_url.clone())
223→            .or_else(|| env_value(env_overrides, def.env_base_url_key))
224→            .unwrap_or_else(|| def.default_base_url.into());
225→
226→        if def.local_only {
227→            let has_explicit_entry = config.get(def.config_name).is_some();
228→            let has_env_base_url = env_value(env_overrides, def.env_base_url_key).is_some();
229→            let preferred = configured_models_for_provider(config, def.config_name);
230→            if !has_explicit_entry && !has_env_base_url && preferred.is_empty() {
231→                continue;
232→            }
233→        }
234→
235→        let user_opted_in = config
236→            .get(def.config_name)
237→            .is_some_and(|entry| entry.fetch_models);
238→        let try_fetch = def.supports_model_discovery || user_opted_in;
239→        if !try_fetch || !should_fetch_models(config, def.config_name) {
240→            continue;
241→        }
242→
243→        if def.config_name == "ollama" {
244→            tasks.push((
245→                def.config_name.into(),
246→                Box::pin(ollama::discover_ollama_models_from_api(base_url)),
247→            ));
248→        } else {
249→            tasks.push((
250→                def.config_name.into(),
251→                Box::pin(openai::fetch_models_from_api(key, base_url)),
252→            ));
253→        }
254→    }
255→
256→    // ── Custom providers ──────────────────────────────────────────────
257→    for (name, entry) in &config.providers {
258→        if !name.starts_with("custom-") || !entry.enabled {
259→            continue;
260→        }
261→        if !filter_matches(name) {
262→            continue;
263→        }
264→        let Some(api_key) = entry
265→            .api_key
266→            .as_ref()
267→            .filter(|k| !k.expose_secret().is_empty())
268→        else {
269→            continue;
270→        };
271→        let Some(base_url) = entry.base_url.as_ref().filter(|u| !u.trim().is_empty()) else {
272→            continue;
273→        };
274→        if should_fetch_models(config, name) {
275→            tasks.push((
276→                name.clone(),
277→                Box::pin(openai::fetch_models_from_api(
278→                    api_key.clone(),
279→                    base_url.clone(),
280→                )),
281→            ));
282→        }
283→    }
284→
285→    // Run all fetches concurrently.
286→    let names: Vec<String> = tasks.iter().map(|(n, _)| n.clone()).collect();
287→    let futures: Vec<_> = tasks.into_iter().map(|(_, fut)| fut).collect();
288→    let results = join_all(futures).await;
289→
290→    let mut map = HashMap::new();
291→    for (name, result) in names.into_iter().zip(results) {
292→        match result {
293→            Ok(models) => {
294→                tracing::debug!(
295→                    provider = %name,
296→                    model_count = models.len(),
297→                    "runtime model rediscovery succeeded"
298→                );
299→                map.insert(name, models);
300→            },
301→            Err(err) => {
302→                tracing::debug!(
303→                    provider = %name,
304→                    error = %err,
305→                    "runtime model rediscovery failed"
306→                );
307→            },
308→        }
309→    }
310→
311→    // Batch-probe any newly discovered Ollama models for `/api/show` metadata
312→    // (tool capabilities, family info). Runs outside any registry lock.
313→    let ollama_probes = if let Some(ollama_models) = map.get("ollama") {
314→        let ollama_base_url = config
315→            .get("ollama")
316→            .and_then(|e| e.base_url.clone())
317→            .or_else(|| env_value(env_overrides, "OLLAMA_BASE_URL"))
318→            .unwrap_or_else(|| "http://localhost:11434".into());
319→        probe_ollama_models_batch_async(&ollama_base_url, ollama_models).await
320→    } else {
321→        HashMap::new()
322→    };
323→
324→    RediscoveryResult {
325→        models: map,
326→        ollama_probes,
327→    }
328→}
