123→    /// Load a provider from configuration.
124→    ///
125→    /// This will download the model if needed.
126→    pub async fn from_config(config: LocalGgufConfig) -> Result<Self> {
127→        let load_start = Instant::now();
128→
129→        // Resolve model path
130→        let (model_path, model_def) = if let Some(path) = config.model_path {
131→            // User provided direct path
132→            if !path.exists() {
133→                bail!("model file not found: {}", path.display());
134→            }
135→            (path, find_model(&config.model_id))
136→        } else {
137→            // Look up in registry and download if needed
138→            let Some(def) = find_model(&config.model_id) else {
139→                bail!(
140→                    "unknown model '{}'. Use model_path for custom GGUF files.",
141→                    config.model_id
142→                );
143→            };
144→
145→            // MLX models require the MLX backend (Python mlx_lm), not llama.cpp
146→            if matches!(def.backend, models::ModelBackend::Mlx) {
147→                bail!(
148→                    "Model '{}' requires the MLX backend which is not available in this context. \
149→                     MLX models need Python with mlx_lm installed. \
150→                     Please select a GGUF model instead (e.g., 'llama-3.2-1b-q4_k_m').",
151→                    config.model_id
152→                );
153→            }
154→
155→            let path = models::ensure_model(def, &config.cache_dir).await?;
156→            (path, Some(def))
157→        };
158→
159→        // Determine context size
160→        let context_size = config
161→            .context_size
162→            .or_else(|| model_def.map(|d| d.context_window))
163→            .unwrap_or(8192);
164→
165→        // Load the model
166→        debug!(model = %config.model_id, "initializing llama backend");
167→        let backend = LlamaBackend::init().context("initializing llama backend")?;
168→
169→        let mut model_params = LlamaModelParams::default();
170→
171→        // GPU offloading
172→        if config.gpu_layers > 0 {
173→            model_params = model_params.with_n_gpu_layers(config.gpu_layers);
174→            info!(gpu_layers = config.gpu_layers, "GPU offloading enabled");
175→        }
176→
177→        debug!(
178→            path = %model_path.display(),
179→            model = %config.model_id,
180→            "loading GGUF model file"
181→        );
182→        let model = LlamaModel::load_from_file(&backend, &model_path, &model_params)
183→            .map_err(|e| anyhow::anyhow!("failed to load GGUF model: {e}"))?;
184→
185→        let load_duration = load_start.elapsed();
186→
187→        info!(
188→            path = %model_path.display(),
189→            model = %config.model_id,
190→            context_size,
191→            load_duration_secs = load_duration.as_secs_f64(),
192→            "loaded local GGUF model"
193→        );
194→
195→        // Record model load metrics
196→        #[cfg(feature = "metrics")]
197→        {
198→            // Use a local-llm specific metric for model loading
199→            histogram!(
200→                "moltis_local_llm_model_load_duration_seconds",
201→                labels::MODEL => config.model_id.clone()
202→            )
203→            .record(load_duration.as_secs_f64());
204→
205→            gauge!(
206→                "moltis_local_llm_models_loaded",
207→                labels::MODEL => config.model_id.clone()
208→            )
209→            .increment(1.0);
210→        }
211→
212→        Ok(Self::new_with_model(
213→            backend,
214→            model,
215→            config.model_id,
216→            model_def,
217→            context_size,
218→            config.temperature,
219→        ))
220→    }
