222→    /// Get the chat template hint for this model.
223→    fn chat_template(&self) -> ChatTemplateHint {
224→        self.model_def
225→            .map(|d| d.chat_template)
226→            .unwrap_or(ChatTemplateHint::Auto)
227→    }
