229→    /// Generate text synchronously (called from blocking context).
230→    ///
231→    /// When `tool_names` is non-empty, a lazy GBNF grammar sampler constrains
232→    /// the output to valid `tool_call` fenced blocks.
233→    fn generate_sync(
234→        &self,
235→        prompt: &str,
236→        max_tokens: u32,
237→        tool_names: &[&str],
238→    ) -> Result<(String, u32, u32)> {
239→        let generation_start = Instant::now();
240→        let model = self.model.blocking_lock();
241→        let backend = &self.backend.0;
242→
243→        // Batch size for processing (default in llama.cpp is 2048, we use 512 for safety)
244→        let batch_size: usize = 512;
245→
246→        // Create context
247→        let ctx_params = LlamaContextParams::default()
248→            .with_n_ctx(NonZeroU32::new(self.context_size))
249→            .with_n_batch(batch_size as u32);
250→        let mut ctx = model
251→            .new_context(backend, ctx_params)
252→            .map_err(|e| anyhow::anyhow!("failed to create llama context: {e}"))?;
253→
254→        // Tokenize prompt
255→        let tokens = model
256→            .str_to_token(prompt, llama_cpp_2::model::AddBos::Always)
257→            .map_err(|e| anyhow::anyhow!("tokenization failed: {e}"))?;
258→
259→        let input_tokens = tokens.len() as u32;
260→        debug!(input_tokens, batch_size, "tokenized prompt");
261→
262→        if tokens.is_empty() {
263→            bail!("empty token sequence");
264→        }
265→
266→        // Process prompt in batches to avoid exceeding n_batch
267→        debug!(
268→            num_chunks = tokens.len().div_ceil(batch_size),
269→            "processing prompt"
270→        );
271→        let mut batch = LlamaBatch::new(batch_size, 1);
272→        for (chunk_idx, chunk) in tokens.chunks(batch_size).enumerate() {
273→            batch.clear();
274→            let chunk_start = chunk_idx * batch_size;
275→            let is_last_chunk = chunk_start + chunk.len() == tokens.len();
276→
277→            for (i, &token) in chunk.iter().enumerate() {
278→                let pos = (chunk_start + i) as i32;
279→                // Only compute logits for the very last token
280→                let is_last = is_last_chunk && i == chunk.len() - 1;
281→                batch
282→                    .add(token, pos, &[0], is_last)
283→                    .map_err(|e| anyhow::anyhow!("batch add failed: {e}"))?;
284→            }
285→
286→            ctx.decode(&mut batch)
287→                .map_err(|e| anyhow::anyhow!("prompt decode failed: {e}"))?;
288→        }
289→
290→        let prompt_eval_time = generation_start.elapsed();
291→        debug!(
292→            prompt_eval_secs = prompt_eval_time.as_secs_f64(),
293→            "prompt evaluation complete"
294→        );
295→
296→        // Set up sampler chain.
297→        // When tools are available, add a lazy grammar sampler that activates
298→        // when the model emits ` ``` ` (start of a fenced block).
299→        let mut samplers: Vec<LlamaSampler> = Vec::new();
300→
301→        if let Some(grammar_str) = tool_grammar::build_tool_call_grammar(tool_names) {
302→            match LlamaSampler::grammar_lazy(&model, &grammar_str, "root", ["```tool_call"], &[]) {
303→                Ok(grammar_sampler) => {
304→                    debug!("grammar-constrained sampling enabled for tool calls");
305→                    samplers.push(grammar_sampler);
306→                },
307→                Err(e) => {
308→                    warn!(%e, "failed to create grammar sampler, falling back to unconstrained");
309→                },
310→            }
311→        }
312→
313→        samplers.push(LlamaSampler::temp(self.temperature));
314→        samplers.push(LlamaSampler::dist(42)); // Seed
315→
316→        let mut sampler = LlamaSampler::chain_simple(samplers);
317→
318→        // Generate tokens
319→        let token_gen_start = Instant::now();
320→        let mut output_tokens = Vec::new();
321→        let mut pos = tokens.len() as i32;
322→        let eos_token = model.token_eos();
323→
324→        for _ in 0..max_tokens {
325→            // Sample from the last position in the batch
326→            let token = sampler.sample(&ctx, batch.n_tokens() - 1);
327→
328→            if token == eos_token {
329→                debug!("reached EOS token");
330→                break;
331→            }
332→
333→            output_tokens.push(token);
334→            sampler.accept(token);
335→
336→            // Decode next token
337→            batch.clear();
338→            batch
339→                .add(token, pos, &[0], true)
340→                .map_err(|e| anyhow::anyhow!("batch add token failed: {e}"))?;
341→            ctx.decode(&mut batch)
342→                .map_err(|e| anyhow::anyhow!("token decode failed: {e}"))?;
343→
344→            pos += 1;
345→        }
346→
347→        let token_gen_duration = token_gen_start.elapsed();
348→        let total_duration = generation_start.elapsed();
349→        let output_token_count = output_tokens.len() as u32;
350→
351→        // Calculate tokens per second
352→        let tokens_per_sec = if token_gen_duration.as_secs_f64() > 0.0 {
353→            output_token_count as f64 / token_gen_duration.as_secs_f64()
354→        } else {
355→            0.0
356→        };
357→
358→        debug!(
359→            output_tokens = output_token_count,
360→            generation_secs = token_gen_duration.as_secs_f64(),
361→            total_secs = total_duration.as_secs_f64(),
362→            tokens_per_sec = format!("{:.1}", tokens_per_sec),
363→            "generation complete"
364→        );
365→
366→        // Detokenize output
367→        let output_text = detokenize(&model, &output_tokens)?;
368→
369→        Ok((output_text, input_tokens, output_token_count))
370→    }
371→}
372→
373→/// Detokenize a sequence of tokens into a string.
374→fn detokenize(model: &LlamaModel, tokens: &[LlamaToken]) -> Result<String> {
375→    let mut decoder = encoding_rs::UTF_8.new_decoder();
376→    let mut output = String::new();
377→    for &token in tokens {
378→        let piece = model
379→            .token_to_piece(token, &mut decoder, true, None)
380→            .map_err(|e| anyhow::anyhow!("detokenization failed: {e}"))?;
381→        output.push_str(&piece);
382→    }
383→    Ok(output)
384→}
