650→fn extend_events_or_error(
651→    events: &mut Vec<StreamEvent>,
652→    new_events: Vec<StreamEvent>,
653→) -> anyhow::Result<()> {
654→    for event in new_events {
655→        if let StreamEvent::Error(msg) = &event {
656→            anyhow::bail!("{msg}");
657→        }
658→        events.push(event);
659→    }
660→    Ok(())
