663→async fn collect_streamed_responses_completion(
664→    client: &reqwest::Client,
665→    auth: &CopilotAuth,
666→    model: &str,
667→    messages: &[ChatMessage],
668→    tools: &[serde_json::Value],
669→) -> anyhow::Result<CompletionResponse> {
670→    let (instructions, input) = split_responses_instructions_and_input(messages.to_vec());
671→
672→    let mut body = serde_json::json!({
673→        "model": model,
674→        "stream": true,
675→        "input": input,
676→    });
677→    if let Some(instructions) = instructions {
678→        body["instructions"] = serde_json::Value::String(instructions);
679→    }
680→    if !tools.is_empty() {
681→        body["tools"] = serde_json::Value::Array(to_responses_api_tools(tools));
682→        body["tool_choice"] = serde_json::json!("auto");
683→    }
684→
685→    let http_resp = client
686→        .post(format!("{}/responses", auth.base_url))
687→        .header(
688→            "Authorization",
689→            format!("Bearer {}", auth.token.expose_secret()),
690→        )
691→        .header("content-type", "application/json")
692→        .header("Editor-Version", EDITOR_VERSION)
693→        .header("User-Agent", COPILOT_USER_AGENT)
694→        .json(&body)
695→        .send()
696→        .await?;
697→
698→    let status = http_resp.status();
699→    if !status.is_success() {
700→        let retry_after_ms = super::retry_after_ms_from_headers(http_resp.headers());
701→        let body_text = http_resp.text().await.unwrap_or_default();
702→        warn!(status = %status, body = %body_text, "github-copilot enterprise responses API error");
703→        anyhow::bail!(
704→            "{}",
705→            super::with_retry_after_marker(
706→                format!("GitHub Copilot Responses API error HTTP {status}: {body_text}"),
707→                retry_after_ms,
708→            )
709→        );
710→    }
711→
712→    let mut byte_stream = http_resp.bytes_stream();
713→    let mut buf = String::new();
714→    let mut state = ResponsesStreamState::default();
715→    let mut events: Vec<StreamEvent> = Vec::new();
716→
717→    while let Some(chunk) = byte_stream.next().await {
718→        let chunk = chunk?;
719→        buf.push_str(&String::from_utf8_lossy(&chunk));
720→
721→        let mut offset = 0usize;
722→        while let Some(pos) = buf[offset..].find('\n') {
723→            let pos = offset + pos;
724→            let line = buf[offset..pos].trim();
725→            offset = pos + 1;
726→
727→            if line.is_empty() {
728→                continue;
729→            }
730→
731→            let Some(data) = line
732→                .strip_prefix("data: ")
733→                .or_else(|| line.strip_prefix("data:"))
734→            else {
735→                continue;
736→            };
737→
738→            match process_responses_sse_line(data, &mut state) {
739→                SseLineResult::Done => {
740→                    extend_events_or_error(&mut events, finalize_responses_stream(&mut state))?;
741→                    return Ok(stream_events_to_completion(events));
742→                },
743→                SseLineResult::Events(new_events) => {
744→                    extend_events_or_error(&mut events, new_events)?;
745→                },
746→                SseLineResult::Skip => {},
747→            }
748→        }
749→        if offset > 0 {
750→            buf.drain(..offset);
751→        }
752→    }
753→
754→    // Process any trailing data in the buffer.
755→    let line = buf.trim();
756→    if !line.is_empty()
757→        && let Some(data) = line
758→            .strip_prefix("data: ")
759→            .or_else(|| line.strip_prefix("data:"))
760→    {
761→        match process_responses_sse_line(data, &mut state) {
762→            SseLineResult::Done => {
763→                extend_events_or_error(&mut events, finalize_responses_stream(&mut state))?;
764→                return Ok(stream_events_to_completion(events));
765→            },
766→            SseLineResult::Events(new_events) => {
767→                extend_events_or_error(&mut events, new_events)?;
768→            },
769→            SseLineResult::Skip => {},
770→        }
771→    }
772→
773→    extend_events_or_error(&mut events, finalize_responses_stream(&mut state))?;
774→    Ok(stream_events_to_completion(events))
775→}
