777→/// Collapse a collected list of [`StreamEvent`]s into a [`CompletionResponse`].
778→fn stream_events_to_completion(events: Vec<StreamEvent>) -> CompletionResponse {
779→    let mut text_parts: Vec<String> = Vec::new();
780→    let mut tool_calls: Vec<ToolCall> = Vec::new();
781→    let mut usage = Usage::default();
