790→                while pending_tools.len() <= index {
791→                    pending_tools.push((String::new(), String::new(), String::new()));
792→                }
793→                pending_tools[index].0 = id;
794→                pending_tools[index].1 = name;
795→            },
796→            StreamEvent::ToolCallArgumentsDelta { index, delta } => {
797→                if let Some(entry) = pending_tools.get_mut(index) {

