503→    fn register_dynamic_source_models(
504→        &mut self,
505→        source: &dyn DynamicModelDiscovery,
506→        config: &ProvidersConfig,
507→        catalog: Vec<DiscoveredModel>,
508→    ) {
509→        let Some(models) = Self::desired_models_for_dynamic_source(source, config, catalog) else {
510→            return;
