534→    #[cfg(any(feature = "provider-openai-codex", feature = "provider-github-copilot"))]
535→    fn refresh_dynamic_source_models(
536→        &mut self,
537→        source: &dyn DynamicModelDiscovery,
538→        config: &ProvidersConfig,
539→    ) -> bool {
540→        if !source.is_enabled_and_authenticated(config) {
541→            return false;
542→        }
543→        if !source.should_fetch_models(config) {
544→            return false;
545→        }
546→
547→        let live_catalog = match source.live_models() {
548→            Ok(models) => models,
549→            Err(err) => {
550→                tracing::warn!(
551→                    provider = source.provider_name(),
552→                    error = %err,
553→                    "skipping dynamic model refresh because live fetch failed"
554→                );
555→                return false;
556→            },
557→        };
558→
559→        let Some(next_models) =
560→            Self::desired_models_for_dynamic_source(source, config, live_catalog)
561→        else {
562→            return false;
563→        };
564→
565→        let new_entries: Vec<(ModelInfo, Arc<dyn LlmProvider>)> = next_models
566→            .into_iter()
567→            .map(|model| {
568→                let caps = model
569→                    .capabilities
570→                    .unwrap_or_else(|| ModelCapabilities::infer(&model.id));
571→                (
572→                    ModelInfo {
573→                        id: model.id.clone(),
574→                        provider: source.provider_name().to_string(),
575→                        display_name: source.display_name(&model.id, &model.display_name),
576→                        created_at: model.created_at,
577→                        recommended: model.recommended,
578→                        capabilities: caps,
579→                    },
580→                    source.build_provider(model.id, config),
581→                )
582→            })
583→            .collect();
584→
585→        // Replace stale provider entries atomically only after successful fetch.
586→        let stale_ids: Vec<String> = self
587→            .models
588→            .iter()
589→            .filter(|m| m.provider == source.provider_name())
590→            .map(|m| m.id.clone())
591→            .collect();
592→        for model_id in &stale_ids {
593→            self.providers.remove(model_id);
594→        }
595→        self.models.retain(|m| m.provider != source.provider_name());
596→        for (info, provider) in new_entries {
597→            self.register(info, provider);
598→        }

