241→/// Fetch available models from the OpenAI-compatible `/models` endpoint.
242→pub async fn fetch_models_from_api(
243→    api_key: secrecy::Secret<String>,
244→    base_url: String,
245→) -> anyhow::Result<Vec<DiscoveredModel>> {
246→    let client = crate::shared_http_client();
247→    let response = client
248→        .get(models_endpoint(&base_url))
249→        .timeout(Duration::from_secs(15))
250→        .header(
251→            "Authorization",
252→            format!("Bearer {}", api_key.expose_secret()),
253→        )
254→        .header("Accept", "application/json")
255→        .send()
256→        .await?;
257→    let status = response.status();
258→    let body = response.text().await?;
259→    if !status.is_success() {
260→        anyhow::bail!("openai models API error HTTP {status}");
261→    }
262→    let payload: serde_json::Value = serde_json::from_str(&body)?;
263→    let models = parse_models_payload(&payload);
264→    if models.is_empty() {
265→        anyhow::bail!("openai models API returned no models");
266→    }
267→    Ok(models)
268→}
