270→/// Spawn model discovery in a background thread and return the receiver
271→/// immediately, without blocking. Call `.recv()` later to collect the result.
272→pub fn start_model_discovery(
273→    api_key: secrecy::Secret<String>,
274→    base_url: String,
275→) -> mpsc::Receiver<anyhow::Result<Vec<DiscoveredModel>>> {
276→    let (tx, rx) = mpsc::sync_channel(1);
277→    std::thread::spawn(move || {
278→        let result = tokio::runtime::Builder::new_current_thread()
279→            .enable_all()
280→            .build()
281→            .map_err(anyhow::Error::from)
282→            .and_then(|rt| rt.block_on(fetch_models_from_api(api_key, base_url)));
283→        let _ = tx.send(result);
284→    });
285→    rx
286→}
