834→/// Returns `true` if the given model is known to require the Responses API
835→/// (`/responses`) instead of Chat Completions (`/chat/completions`).
836→fn needs_responses_api(model: &str) -> bool {
837→    let m = model.to_ascii_lowercase();
838→    m.starts_with("gpt-5.4") || m == "gpt-5.2-pro" || m.starts_with("codex-")
839→}
840→
841→/// Returns `true` if an error body from the Chat Completions API indicates
842→/// that the model only supports the Responses API.
843→fn is_responses_api_required_error(body: &str) -> bool {
844→    let lower = body.to_ascii_lowercase();
845→    lower.contains("unsupported_api_for_model")
846→        || lower.contains("not accessible via the /chat/completions")
847→}
