851→#[async_trait]
852→impl LlmProvider for GitHubCopilotProvider {
853→    fn name(&self) -> &str {
854→        PROVIDER_NAME
855→    }
856→
857→    fn id(&self) -> &str {
858→        &self.model
859→    }
860→
861→    fn supports_tools(&self) -> bool {
862→        super::supports_tools_for_model(&self.model)
863→    }
864→
865→    async fn complete(
866→        &self,
867→        messages: &[ChatMessage],
868→        tools: &[serde_json::Value],
869→    ) -> anyhow::Result<CompletionResponse> {
870→        if needs_responses_api(&self.model) {
871→            return self.complete_responses(messages, tools).await;
872→        }
873→
874→        let auth = self.get_copilot_auth().await?;
875→
876→        // Enterprise proxy only supports streaming — delegate to the
877→        // streaming path and collect the result.
878→        if auth.is_enterprise {
879→            return collect_streamed_completion(self.client, &auth, &self.model, messages, tools)
880→                .await;
881→        }
882→
883→        let openai_messages: Vec<serde_json::Value> =
884→            messages.iter().map(ChatMessage::to_openai_value).collect();
885→        let mut body = serde_json::json!({
886→            "model": self.model,
887→            "messages": openai_messages,
888→        });
889→
890→        if !tools.is_empty() {
891→            body["tools"] = serde_json::Value::Array(to_openai_tools(tools, true));
892→        }
893→
894→        debug!(
895→            model = %self.model,
896→            messages_count = messages.len(),
897→            tools_count = tools.len(),
898→            "github-copilot complete request"
899→        );
900→        trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "github-copilot request body");
901→
902→        let http_resp = self
903→            .client
904→            .post(format!("{}/chat/completions", auth.base_url))
905→            .header(
906→                "Authorization",
907→                format!("Bearer {}", auth.token.expose_secret()),
908→            )
909→            .header("content-type", "application/json")
910→            .header("Editor-Version", EDITOR_VERSION)
911→            .header("User-Agent", COPILOT_USER_AGENT)
912→            .json(&body)
913→            .send()
914→            .await?;
915→
916→        let status = http_resp.status();
917→        if !status.is_success() {
918→            let retry_after_ms = super::retry_after_ms_from_headers(http_resp.headers());
919→            let body_text = http_resp.text().await.unwrap_or_default();
920→
921→            // Fallback: if the model requires Responses API, retry with it.
922→            if status == reqwest::StatusCode::BAD_REQUEST
923→                && is_responses_api_required_error(&body_text)
924→            {
925→                debug!(
926→                    model = %self.model,
927→                    "chat completions returned unsupported_api_for_model, retrying with responses API"
928→                );
929→                return self.complete_responses(messages, tools).await;
930→            }
931→
932→            warn!(status = %status, body = %body_text, "github-copilot API error");
933→            anyhow::bail!(
934→                "{}",
935→                super::with_retry_after_marker(
936→                    format!("GitHub Copilot API error HTTP {status}: {body_text}"),
937→                    retry_after_ms,
938→                )
939→            );
940→        }
941→
942→        let resp = http_resp.json::<serde_json::Value>().await?;
943→        trace!(response = %resp, "github-copilot raw response");
944→
945→        let message = &resp["choices"][0]["message"];
946→
947→        let text = message["content"].as_str().map(|s| s.to_string());
948→        let tool_calls = parse_tool_calls(message);
949→
950→        let usage = parse_openai_compat_usage_from_payload(&resp).unwrap_or_default();
951→
952→        Ok(CompletionResponse {
953→            text,
954→            tool_calls,
955→            usage,
956→        })
957→    }
958→
959→    #[allow(clippy::collapsible_if)]
960→    fn stream(
961→        &self,
962→        messages: Vec<ChatMessage>,
963→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
964→        self.stream_with_tools(messages, vec![])
965→    }
966→
967→    #[allow(clippy::collapsible_if)]
968→    fn stream_with_tools(
969→        &self,
970→        messages: Vec<ChatMessage>,
971→        tools: Vec<serde_json::Value>,
972→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
973→        if needs_responses_api(&self.model) {
974→            return self.stream_responses_api(messages, tools);
975→        }
976→        self.stream_chat_completions(messages, tools)
977→    }
978→}
