 95→    /// Return the reasoning effort string if configured.
 96→    pub(crate) fn reasoning_effort_str(&self) -> Option<&'static str> {
 97→        use moltis_agents::model::ReasoningEffort;
 98→        self.reasoning_effort.map(|e| match e {
 99→            ReasoningEffort::Low => "low",
100→            ReasoningEffort::Medium => "medium",
101→            ReasoningEffort::High => "high",
102→        })
103→    }
104→
105→    /// Apply `reasoning_effort` for the **Chat Completions** API (used by
106→    /// `complete()` and `stream_with_tools_sse()`).
107→    ///
108→    /// Format: `"reasoning_effort": "high"` (top-level string field).
109→    pub(crate) fn apply_reasoning_effort_chat(&self, body: &mut serde_json::Value) {
110→        if let Some(effort) = self.reasoning_effort_str() {
111→            body["reasoning_effort"] = serde_json::json!(effort);
112→        }
113→    }
114→
115→    /// Apply `reasoning_effort` for the **Responses** API (used by
116→    /// `stream_with_tools_websocket()`).
117→    ///
118→    /// Format: `"reasoning": { "effort": "high" }` (nested object).
119→    pub(crate) fn apply_reasoning_effort_responses(&self, body: &mut serde_json::Value) {
120→        if let Some(effort) = self.reasoning_effort_str() {
121→            body["reasoning"] = serde_json::json!({ "effort": effort });
122→        }
123→    }
124→
125→    /// Build the HTTP URL for the Responses API (`/responses`).
126→    ///
127→    /// If the base URL already ends with `/responses`, use it as-is.
128→    /// Otherwise derive it as a sibling of `/chat/completions`, ensuring
129→    /// `/v1` is present — matching the normalization in
130→    /// `responses_websocket_url`.
131→    pub(crate) fn responses_sse_url(&self) -> String {
132→        let base = self.base_url.trim_end_matches('/');
133→        if base.ends_with("/responses") {
134→            return base.to_string();
135→        }
136→        if let Some(prefix) = base.strip_suffix("/chat/completions") {
137→            return format!("{prefix}/responses");
138→        }
139→        // Ensure /v1 is present, consistent with responses_websocket_url.
140→        if base.ends_with("/v1") {
141→            format!("{base}/responses")
142→        } else {
143→            format!("{base}/v1/responses")
144→        }
145→    }
146→}
