202→    async fn model_metadata(&self) -> anyhow::Result<ModelMetadata> {
203→        let meta = self
204→            .metadata_cache
205→            .get_or_try_init(|| async {
206→                let url = format!("{}/models/{}", self.base_url, self.model);
207→                debug!(url = %url, model = %self.model, "fetching model metadata");
208→
209→                let resp = self
210→                    .client
211→                    .get(&url)
212→                    .header(
213→                        "Authorization",
214→                        format!("Bearer {}", self.api_key.expose_secret()),
215→                    )
216→                    .send()
217→                    .await?;
218→
219→                if !resp.status().is_success() {
