229→                let context_length = body
230→                    .get("context_window")
231→                    .or_else(|| body.get("context_length"))
232→                    .and_then(|v| v.as_u64())
233→                    .map(|v| v as u32)
234→                    .unwrap_or_else(|| self.context_window());
235→
236→                Ok(ModelMetadata {
237→                    id: body
238→                        .get("id")
239→                        .and_then(|v| v.as_str())
240→                        .unwrap_or(&self.model)
241→                        .to_string(),
242→                    context_length,
243→                })
244→            })
245→            .await?;
246→        Ok(meta.clone())
247→    }
