275→    #[allow(clippy::collapsible_if)]
276→    fn stream_with_tools(
277→        &self,
278→        messages: Vec<ChatMessage>,
279→        tools: Vec<serde_json::Value>,
280→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
281→        match (self.wire_api, self.stream_transport) {
282→            (WireApi::Responses, ProviderStreamTransport::Sse) => {
283→                self.stream_responses_sse(messages, tools)
284→            },
285→            (WireApi::Responses, _) => {
286→                // WebSocket / Auto both go through the WS path which already
287→                // uses the responses format.
288→                self.stream_with_tools_websocket(
289→                    messages,
290→                    tools,
291→                    matches!(self.stream_transport, ProviderStreamTransport::Auto),
292→                )
293→            },
294→            (WireApi::ChatCompletions, ProviderStreamTransport::Sse) => {
295→                self.stream_with_tools_sse(messages, tools)
296→            },
297→            (WireApi::ChatCompletions, ProviderStreamTransport::Websocket) => {
298→                self.stream_with_tools_websocket(messages, tools, false)
299→            },
300→            (WireApi::ChatCompletions, ProviderStreamTransport::Auto) => {
301→                self.stream_with_tools_websocket(messages, tools, true)
302→            },
303→        }
304→    }
