669→    fn replace_anthropic_catalog(
670→        &mut self,
671→        models: Vec<DiscoveredModel>,
672→        key: &secrecy::Secret<String>,
673→        base_url: &str,
674→        provider_label: &str,
675→        alias: Option<String>,
676→        cache_retention: moltis_config::CacheRetention,
677→    ) -> usize {
678→        let new_entries: Vec<(ModelInfo, Arc<dyn LlmProvider>)> = models
679→            .into_iter()
680→            .map(|model| {
681→                let caps = model
682→                    .capabilities
683→                    .unwrap_or_else(|| ModelCapabilities::infer(&model.id));
684→                let provider = Arc::new(
685→                    anthropic::AnthropicProvider::with_alias(
686→                        key.clone(),
687→                        model.id.clone(),
688→                        base_url.to_string(),
689→                        alias.clone(),
690→                    )
691→                    .with_cache_retention(cache_retention),
692→                );
693→                (
694→                    ModelInfo {
695→                        id: model.id,
696→                        provider: provider_label.to_string(),
697→                        display_name: model.display_name,
698→                        created_at: model.created_at,
699→                        recommended: model.recommended,
700→                        capabilities: caps,
701→                    },
702→                    provider as Arc<dyn LlmProvider>,
703→                )
704→            })
705→            .collect();
706→
707→        let previous_ids: HashSet<String> = self
708→            .models
709→            .iter()
710→            .filter(|m| m.provider == provider_label)
711→            .map(|m| m.id.clone())
712→            .collect();
713→
714→        self.models.retain(|m| m.provider != provider_label);
715→        self.providers.retain(|id, _| !previous_ids.contains(id));
716→
717→        let next_ids: HashSet<String> = new_entries
718→            .iter()
719→            .map(|(info, _)| namespaced_model_id(provider_label, raw_model_id(&info.id)))
720→            .collect();
721→
722→        for (info, provider) in new_entries {
723→            self.register(info, provider);
724→        }
725→
726→        next_ids.difference(&previous_ids).count()
727→    }
