730→    pub fn register(&mut self, mut info: ModelInfo, provider: Arc<dyn LlmProvider>) {
731→        let model_id = raw_model_id(&info.id).to_string();
732→        let registry_model_id = namespaced_model_id(&info.provider, &model_id);
733→        info.id = registry_model_id.clone();
734→        let wrapped: Arc<dyn LlmProvider> = Arc::new(RegistryModelProvider {
735→            model_id: registry_model_id.clone(),
736→            inner: provider,
737→        });
738→        self.providers.insert(registry_model_id, wrapped);
739→        self.models.push(info);
