742→    /// Unregister a provider by model ID. Returns true if it was removed.
743→    pub fn unregister(&mut self, model_id: &str) -> bool {
744→        let resolved_id = self.resolve_registry_model_id(model_id, None);
745→        let removed = resolved_id
746→            .as_deref()
747→            .and_then(|id| self.providers.remove(id))
748→            .is_some();
749→        if removed && let Some(id) = resolved_id {
750→            self.models.retain(|m| m.id != id);
751→        }
752→        removed
753→    }
