1069→            };
1070→
1071→            let (instructions, input) =
1072→                split_responses_instructions_and_input(messages);
1073→
1074→            let mut body = serde_json::json!({
1075→                "model": self.model,
1076→                "stream": true,
1077→                "input": input,
1078→            });
1079→            if let Some(instructions) = instructions {
1080→                body["instructions"] = serde_json::Value::String(instructions);
1081→            }
1082→            if !tools.is_empty() {
1083→                body["tools"] = serde_json::Value::Array(to_responses_api_tools(&tools));
1084→                body["tool_choice"] = serde_json::json!("auto");
1085→            }
1086→
1087→            debug!(
1088→                model = %self.model,
1089→                tools_count = tools.len(),
1090→                "github-copilot stream_responses_api request"
1091→            );
1092→            trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "github-copilot responses stream request body");
1093→
1094→            let resp = match self
1095→                .client
1096→                .post(format!("{}/responses", auth.base_url))
1097→                .header("Authorization", format!("Bearer {}", auth.token.expose_secret()))
1098→                .header("content-type", "application/json")
1099→                .header("Editor-Version", EDITOR_VERSION)
1100→                .header("User-Agent", COPILOT_USER_AGENT)
1101→                .json(&body)
1102→                .send()
1103→                .await
1104→            {
1105→                Ok(r) => {
1106→                    if let Err(e) = r.error_for_status_ref() {
1107→                        let status = e.status().map(|s| s.as_u16()).unwrap_or(0);
1108→                        let retry_after_ms = super::retry_after_ms_from_headers(r.headers());
1109→                        let body_text = r.text().await.unwrap_or_default();
1110→                        yield StreamEvent::Error(super::with_retry_after_marker(
1111→                            format!("HTTP {status}: {body_text}"),
1112→                            retry_after_ms,
1113→                        ));
1114→                        return;
1115→                    }
1116→                    r
1117→                }
1118→                Err(e) => {
1119→                    yield StreamEvent::Error(e.to_string());
1120→                    return;
1121→                }
1122→            };
1123→
1124→            let mut byte_stream = resp.bytes_stream();
1125→            let mut buf = String::new();
1126→            let mut state = ResponsesStreamState::default();
1127→
1128→            while let Some(chunk) = byte_stream.next().await {
1129→                let chunk = match chunk {
1130→                    Ok(c) => c,
1131→                    Err(e) => {
1132→                        yield StreamEvent::Error(e.to_string());
1133→                        return;
1134→                    }
1135→                };
1136→                buf.push_str(&String::from_utf8_lossy(&chunk));
1137→
1138→                while let Some(pos) = buf.find('\n') {
1139→                    let line = buf[..pos].trim().to_string();
1140→                    buf = buf[pos + 1..].to_string();
1141→
1142→                    if line.is_empty() {
1143→                        continue;
1144→                    }
1145→
1146→                    let Some(data) = line
1147→                        .strip_prefix("data: ")
1148→                        .or_else(|| line.strip_prefix("data:"))
1149→                    else {
1150→                        continue;
1151→                    };
1152→
1153→                    match process_responses_sse_line(data, &mut state) {
1154→                        SseLineResult::Done => {
1155→                            for event in finalize_responses_stream(&mut state) {
1156→                                yield event;
1157→                            }
1158→                            return;
1159→                        }
1160→                        SseLineResult::Events(events) => {
1161→                            for event in events {
1162→                                yield event;
1163→                            }
1164→                        }
1165→                        SseLineResult::Skip => {}
1166→                    }
1167→                }
1168→            }
1169→
1170→            // Process any remaining data in the buffer.
1171→            let line = buf.trim().to_string();
1172→            if !line.is_empty()
1173→                && let Some(data) = line
1174→                    .strip_prefix("data: ")
1175→                    .or_else(|| line.strip_prefix("data:"))
1176→            {
1177→                match process_responses_sse_line(data, &mut state) {
1178→                    SseLineResult::Done => {
1179→                        for event in finalize_responses_stream(&mut state) {
1180→                            yield event;
1181→                        }
1182→                        return;
1183→                    }
1184→                    SseLineResult::Events(events) => {
1185→                        for event in events {
1186→                            yield event;
1187→                        }
1188→                    }
1189→                    SseLineResult::Skip => {}
1190→                }
1191→            }
1192→
1193→            for event in finalize_responses_stream(&mut state) {
1194→                yield event;
1195→            }
1196→        })
1197→    }

400→/// inside `<think>` tags in the `content` field rather than using a separate
401→/// `reasoning_content` field.  This helper splits content into the visible
402→/// answer text and the thinking text so callers can handle them appropriately.
403→///
404→/// Edge cases handled:
405→/// - Multiple `<think>` blocks interspersed with answer text
406→/// - Unclosed `<think>` tag (remainder treated as reasoning)
407→/// - Empty `<think></think>` blocks
408→/// - Nested angle brackets inside thinking text
409→pub fn strip_think_tags(content: &str) -> (String, String) {
410→    let mut visible = String::new();
411→    let mut thinking = String::new();
412→    let mut remaining = content;
413→
414→    loop {
415→        match remaining.find("<think>") {
416→            Some(start) => {
417→                // Text before <think> is visible
418→                visible.push_str(&remaining[..start]);
419→                let after_open = &remaining[start + "<think>".len()..];
420→                match after_open.find("</think>") {
421→                    Some(end) => {
422→                        thinking.push_str(&after_open[..end]);
423→                        remaining = &after_open[end + "</think>".len()..];
424→                    },
425→                    None => {
426→                        // Unclosed <think> — treat rest as reasoning
427→                        thinking.push_str(after_open);
428→                        break;
429→                    },
430→                }
431→            },
432→            None => {
433→                visible.push_str(remaining);
434→                break;
435→            },
436→        }
437→    }
438→
439→    (
440→        visible.trim_start().to_string(),
441→        thinking.trim_start().to_string(),
442→    )
443→}
