445→/// State for tracking streaming tool calls.
446→#[derive(Default)]
447→pub struct StreamingToolState {
448→    /// Map from index -> (id, name, arguments_buffer)
449→    pub tool_calls: HashMap<usize, (String, String, String)>,
450→    pub input_tokens: u32,
451→    pub output_tokens: u32,
452→    pub cache_read_tokens: u32,
453→    pub cache_write_tokens: u32,
454→    /// Whether we are currently inside a `<think>` block in streamed content.
455→    in_think_block: bool,
456→    /// Whether we are still stripping leading whitespace at the start of a
457→    /// think block. Set to `true` when entering `<think>`, cleared once
458→    /// non-whitespace reasoning content is emitted.
459→    think_strip_leading_ws: bool,
460→    /// Whether we are still stripping leading whitespace from visible content
461→    /// after exiting a `</think>` block. Models often emit `\n\n` between
462→    /// `</think>` and the actual answer.
463→    visible_strip_leading_ws: bool,
464→    /// Buffer for detecting `<think>` / `</think>` tags that may be split
465→    /// across SSE chunk boundaries.
466→    tag_buffer: String,
