469→/// Result of processing a single SSE line.
470→#[derive(Debug)]
471→pub enum SseLineResult {
472→    /// No actionable event (empty line, non-data prefix)
473→    Skip,
474→    /// Stream is done
475→    Done,
476→    /// Events to yield
477→    Events(Vec<StreamEvent>),
478→}
