480→/// Emit a `ReasoningDelta`, stripping leading whitespace at the start of a
481→/// think block so the UI doesn't show a blank prefix.
482→fn emit_reasoning(text: String, strip_leading_ws: &mut bool, events: &mut Vec<StreamEvent>) {
483→    if text.is_empty() {
484→        return;
485→    }
486→    let emitted = if *strip_leading_ws {
487→        let trimmed = text.trim_start();
488→        if trimmed.is_empty() {
489→            // Entire chunk was whitespace — keep stripping
490→            return;
491→        }
492→        *strip_leading_ws = false;
493→        trimmed.to_string()
494→    } else {
495→        text
496→    };
497→    events.push(StreamEvent::ReasoningDelta(emitted));
498→}
499→
500→/// Emit a visible `Delta`, stripping leading whitespace after a `</think>`
501→/// block so the UI doesn't show blank lines before the answer.
502→fn emit_visible(text: String, strip_leading_ws: &mut bool, events: &mut Vec<StreamEvent>) {
503→    if text.is_empty() {
504→        return;
505→    }
506→    let emitted = if *strip_leading_ws {
507→        let trimmed = text.trim_start();
508→        if trimmed.is_empty() {
509→            // Entire chunk was whitespace — keep stripping
510→            return;
511→        }
512→        *strip_leading_ws = false;
513→        trimmed.to_string()
514→    } else {
515→        text
516→    };
517→    events.push(StreamEvent::Delta(emitted));
518→}
