520→/// Process streamed content through the `<think>` tag state machine.
521→///
522→/// Content arriving inside `<think>...</think>` is emitted as
523→/// `ReasoningDelta`; content outside is emitted as `Delta`.
524→/// Tags may be split across SSE chunks — `tag_buffer` accumulates
525→/// partial tag fragments until they can be resolved.
526→/// Leading whitespace at the start of each think block is stripped.
527→fn process_content_think_tags(
528→    content: &str,
529→    state: &mut StreamingToolState,
530→    events: &mut Vec<StreamEvent>,
531→) {
532→    state.tag_buffer.push_str(content);
533→
534→    loop {
535→        if state.in_think_block {
536→            // Look for </think> to exit think mode
537→            match state.tag_buffer.find("</think>") {
538→                Some(pos) => {
539→                    let thinking = state.tag_buffer[..pos].to_string();
540→                    emit_reasoning(thinking, &mut state.think_strip_leading_ws, events);
541→                    state.in_think_block = false;
542→                    state.visible_strip_leading_ws = true;
543→                    let rest = state.tag_buffer[pos + "</think>".len()..].to_string();
544→                    state.tag_buffer = rest;
545→                    // Continue loop to process remaining content
546→                },
547→                None => {
548→                    // Check if buffer ends with a prefix of "</think>"
549→                    // to avoid emitting partial tag as reasoning text.
550→                    let suffix_match = longest_tag_suffix(&state.tag_buffer, "</think>");
551→                    if suffix_match > 0 {
552→                        let safe = state.tag_buffer.len() - suffix_match;
553→                        let emit = state.tag_buffer[..safe].to_string();
554→                        emit_reasoning(emit, &mut state.think_strip_leading_ws, events);
555→                        let kept = state.tag_buffer[safe..].to_string();
556→                        state.tag_buffer = kept;
557→                    } else {
558→                        // No partial tag — emit everything as reasoning
559→                        let buf = std::mem::take(&mut state.tag_buffer);
560→                        emit_reasoning(buf, &mut state.think_strip_leading_ws, events);
561→                    }
562→                    break;
563→                },
564→            }
565→        } else {
566→            // Look for <think> to enter think mode
567→            match state.tag_buffer.find("<think>") {
568→                Some(pos) => {
569→                    let visible = state.tag_buffer[..pos].to_string();
570→                    emit_visible(visible, &mut state.visible_strip_leading_ws, events);
571→                    state.in_think_block = true;
572→                    state.think_strip_leading_ws = true;
573→                    let rest = state.tag_buffer[pos + "<think>".len()..].to_string();
574→                    state.tag_buffer = rest;
575→                    // Continue loop to process remaining content
576→                },
577→                None => {
578→                    // Check if buffer ends with a prefix of "<think>"
579→                    let suffix_match = longest_tag_suffix(&state.tag_buffer, "<think>");
580→                    if suffix_match > 0 {
581→                        let safe = state.tag_buffer.len() - suffix_match;
582→                        let emit = state.tag_buffer[..safe].to_string();
583→                        emit_visible(emit, &mut state.visible_strip_leading_ws, events);
584→                        let kept = state.tag_buffer[safe..].to_string();
585→                        state.tag_buffer = kept;
586→                    } else {
587→                        // No partial tag — emit everything as visible
588→                        let buf = std::mem::take(&mut state.tag_buffer);
589→                        emit_visible(buf, &mut state.visible_strip_leading_ws, events);
590→                    }
591→                    break;
592→                },
593→            }
594→        }
595→    }
596→}
