600→/// For example, `longest_tag_suffix("abc<th", "<think>")` returns 3 because
601→/// `"<th"` is a 3-character prefix of `"<think>"`.
602→fn longest_tag_suffix(text: &str, tag: &str) -> usize {
603→    let text_bytes = text.as_bytes();
604→    let tag_bytes = tag.as_bytes();
605→    let max_check = text_bytes.len().min(tag_bytes.len());
606→    for len in (1..=max_check).rev() {
607→        if text_bytes[text_bytes.len() - len..] == tag_bytes[..len] {
608→            return len;
609→        }
610→    }
611→    0
612→}
