614→/// Process a single SSE data line and return any events to yield.
615→///
616→/// This handles the common OpenAI streaming format used by:
617→/// - OpenAI API
618→/// - GitHub Copilot API
619→/// - Kimi Code API
620→/// - Any other OpenAI-compatible API
621→///
622→/// Content inside `<think>...</think>` tags is emitted as `ReasoningDelta`
623→/// events rather than `Delta`, allowing the UI to show reasoning text
624→/// separately. This handles models (DeepSeek R1, QwQ, MiniMax) that embed
625→/// chain-of-thought in `content` rather than using `reasoning_content`.
626→pub fn process_openai_sse_line(data: &str, state: &mut StreamingToolState) -> SseLineResult {
627→    if data == "[DONE]" {
628→        return SseLineResult::Done;
629→    }
630→
631→    let Ok(evt) = serde_json::from_str::<serde_json::Value>(data) else {
632→        return SseLineResult::Skip;
633→    };
634→
635→    let mut events = vec![StreamEvent::ProviderRaw(evt.clone())];
636→
637→    if let Some(usage) = parse_openai_compat_usage_from_payload(&evt) {
638→        state.input_tokens = usage.input_tokens;
639→        state.output_tokens = usage.output_tokens;
640→        state.cache_read_tokens = usage.cache_read_tokens;
641→        state.cache_write_tokens = usage.cache_write_tokens;
642→    }
643→
644→    let delta = &evt["choices"][0]["delta"];
645→
646→    // Handle user-visible text content, stripping <think> tags.
647→    if let Some(content) = delta["content"].as_str()
648→        && !content.is_empty()
649→    {
650→        process_content_think_tags(content, state, &mut events);
651→    }
652→
653→    // Some OpenAI-compatible backends stream planning text in
654→    // `reasoning_content` or `reasoning`. Surface it separately so UI can
655→    //  show it in the thinking area without polluting final assistant text.
656→    let reasoning_text = delta["reasoning_content"]
657→        .as_str()
658→        .or_else(|| delta["reasoning"].as_str());
659→    if let Some(reasoning_content) = reasoning_text
660→        && !reasoning_content.is_empty()
661→    {
662→        events.push(StreamEvent::ReasoningDelta(reasoning_content.to_string()));
663→    }
664→
665→    // Handle tool calls
666→    if let Some(tcs) = delta["tool_calls"].as_array() {
667→        for tc in tcs {
668→            let index = tc["index"].as_u64().unwrap_or(0) as usize;
669→
670→            // Check if this is a new tool call (has id and function.name)
671→            if let (Some(id), Some(name)) = (tc["id"].as_str(), tc["function"]["name"].as_str()) {
672→                state
673→                    .tool_calls
674→                    .insert(index, (id.to_string(), name.to_string(), String::new()));
675→                events.push(StreamEvent::ToolCallStart {
676→                    id: id.to_string(),
677→                    name: name.to_string(),
678→                    index,
679→                });
680→            }
681→
682→            // Handle arguments delta
683→            if let Some(args_delta) = tc["function"]["arguments"].as_str()
684→                && !args_delta.is_empty()
685→            {
686→                if let Some((_, _, args_buf)) = state.tool_calls.get_mut(&index) {
687→                    args_buf.push_str(args_delta);
688→                }
689→                events.push(StreamEvent::ToolCallArgumentsDelta {
690→                    index,
691→                    delta: args_delta.to_string(),
692→                });
693→            }
694→        }
695→    }
696→
697→    // Detect error finish reasons (e.g. "network_error", "content_filter").
698→    // Normal reasons (null, "stop", "tool_calls", "length") are not errors.
699→    if let Some(reason) = evt["choices"][0]["finish_reason"].as_str() {
700→        match reason {
701→            "stop" | "tool_calls" | "length" | "function_call" => {},
702→            error_reason => {
703→                events.push(StreamEvent::Error(format!(
704→                    "Provider stream ended with finish_reason: {error_reason}"
705→                )));
706→            },
707→        }
708→    }
709→
710→    SseLineResult::Events(events)
711→}
