713→/// Generate the final events when stream ends (tool call completions + done).
714→///
715→/// Any residual content in the think-tag buffer is flushed as the appropriate
716→/// event type (reasoning if we were inside a think block, visible otherwise).
717→pub fn finalize_stream(state: &mut StreamingToolState) -> Vec<StreamEvent> {
718→    let mut events = Vec::new();
719→
720→    // Flush any remaining think-tag buffer content
721→    if !state.tag_buffer.is_empty() {
722→        let remaining = std::mem::take(&mut state.tag_buffer);
723→        if state.in_think_block {
724→            events.push(StreamEvent::ReasoningDelta(remaining));
725→        } else {
726→            events.push(StreamEvent::Delta(remaining));
727→        }
728→    }
729→
730→    // Emit completion for any pending tool calls
731→    for index in state.tool_calls.keys() {
732→        events.push(StreamEvent::ToolCallComplete { index: *index });
733→    }
734→
735→    events.push(StreamEvent::Done(Usage {
736→        input_tokens: state.input_tokens,
737→        output_tokens: state.output_tokens,
738→        cache_read_tokens: state.cache_read_tokens,
739→        cache_write_tokens: state.cache_write_tokens,
740→    }));
741→
742→    events
743→}
