749→/// Split system messages into `instructions` and convert the rest to Responses
750→/// API `input` items.
751→///
752→/// The Responses API uses a top-level `instructions` field instead of a system
753→/// message role.  This function extracts all system messages, joins them with
754→/// `\n\n`, and converts the remaining messages via [`to_responses_input`].
755→#[must_use]
756→pub fn split_responses_instructions_and_input(
757→    messages: Vec<ChatMessage>,
758→) -> (Option<String>, Vec<serde_json::Value>) {
759→    let mut instruction_parts: Vec<String> = Vec::new();
760→    let mut non_system: Vec<ChatMessage> = Vec::new();
761→
762→    for message in messages {
763→        match message {
764→            ChatMessage::System { content } => {
765→                if !content.trim().is_empty() {
766→                    instruction_parts.push(content);
767→                }
768→            },
769→            other => non_system.push(other),
770→        }
771→    }
772→
773→    let instructions = if instruction_parts.is_empty() {
774→        None
775→    } else {
776→        Some(instruction_parts.join("\n\n"))
777→    };
778→
779→    (instructions, to_responses_input(&non_system))
780→}
