782→/// Resolve the output index from a Responses API event.
783→///
784→/// The Responses API uses `output_index` for items and `index` for
785→/// sub-item fields.  WebSocket events may also use `item_index`.
786→/// Falls back to `fallback` if none of these keys are present.
787→pub fn responses_output_index(event: &serde_json::Value, fallback: usize) -> usize {
788→    event
789→        .get("output_index")
790→        .or_else(|| event.get("item_index"))
791→        .or_else(|| event.get("index"))
792→        .and_then(serde_json::Value::as_u64)
793→        .map(|i| i as usize)
794→        .unwrap_or(fallback)
795→}
