812→/// Process a single SSE data line from a Responses API stream.
813→///
814→/// Returns [`SseLineResult`] indicating whether to skip, yield events, or stop.
815→///
816→/// Handles the event types emitted by the Responses API:
817→/// - `response.output_text.delta` → text delta + `ProviderRaw`
818→/// - `response.output_item.added` (type=function_call) → tool call start + `ProviderRaw`
819→/// - `response.function_call_arguments.delta` → tool call arguments delta + `ProviderRaw`
820→/// - `response.function_call_arguments.done` → tool call complete + `ProviderRaw`
821→/// - `response.completed` → parse usage, done
822→/// - `error` / `response.failed` → error + `ProviderRaw`
823→pub fn process_responses_sse_line(data: &str, state: &mut ResponsesStreamState) -> SseLineResult {
824→    if data == "[DONE]" {
825→        return SseLineResult::Done;
826→    }
827→
828→    let Ok(evt) = serde_json::from_str::<serde_json::Value>(data) else {
829→        return SseLineResult::Skip;
830→    };
831→
832→    // Emit ProviderRaw for every parsed event, mirroring the Chat Completions path.
833→    let raw = StreamEvent::ProviderRaw(evt.clone());
834→
835→    match evt["type"].as_str().unwrap_or("") {
836→        "response.output_text.delta" => {
837→            if let Some(delta) = evt["delta"].as_str()
838→                && !delta.is_empty()
839→            {
840→                SseLineResult::Events(vec![raw, StreamEvent::Delta(delta.to_string())])
841→            } else {
842→                SseLineResult::Events(vec![raw])
843→            }
844→        },
845→        "response.output_item.added" => {
846→            if evt["item"]["type"].as_str() == Some("function_call") {
847→                let id = evt["item"]["call_id"].as_str().unwrap_or("").to_string();
848→                let name = evt["item"]["name"].as_str().unwrap_or("").to_string();
849→                let index = responses_output_index(&evt, state.current_tool_index);
850→                state.current_tool_index = state.current_tool_index.max(index + 1);
851→                state.tool_calls.insert(index, (id.clone(), name.clone()));
852→                SseLineResult::Events(vec![raw, StreamEvent::ToolCallStart { id, name, index }])
853→            } else {
854→                SseLineResult::Events(vec![raw])
855→            }
856→        },
857→        "response.function_call_arguments.delta" => {
858→            if let Some(delta) = evt["delta"].as_str()
859→                && !delta.is_empty()
860→            {
861→                let index =
862→                    responses_output_index(&evt, state.current_tool_index.saturating_sub(1));
863→                SseLineResult::Events(vec![raw, StreamEvent::ToolCallArgumentsDelta {
864→                    index,
865→                    delta: delta.to_string(),
866→                }])
867→            } else {
868→                SseLineResult::Events(vec![raw])
869→            }
870→        },
871→        "response.function_call_arguments.done" => {
872→            let index = responses_output_index(&evt, state.current_tool_index.saturating_sub(1));
873→            if state.completed_tool_calls.insert(index) {
874→                SseLineResult::Events(vec![raw, StreamEvent::ToolCallComplete { index }])
875→            } else {
876→                SseLineResult::Events(vec![raw])
877→            }
878→        },
879→        "response.completed" => {
880→            if let Some(usage) = evt
881→                .get("response")
882→                .and_then(|response| response.get("usage"))
883→            {
884→                let parsed = parse_openai_compat_usage(usage);
885→                state.input_tokens = parsed.input_tokens;
886→                state.output_tokens = parsed.output_tokens;
887→                state.cache_read_tokens = parsed.cache_read_tokens;
888→                state.cache_write_tokens = parsed.cache_write_tokens;
889→            }
890→            SseLineResult::Done
891→        },
892→        "error" | "response.failed" => {
893→            let msg = evt["error"]["message"]
894→                .as_str()
895→                .or_else(|| evt["response"]["error"]["message"].as_str())
896→                .or_else(|| evt["message"].as_str())
897→                .unwrap_or("unknown error");
898→            SseLineResult::Events(vec![raw, StreamEvent::Error(msg.to_string())])
899→        },
900→        _ => SseLineResult::Events(vec![raw]),
901→    }
902→}
