904→/// Generate the final events when a Responses API stream ends.
905→///
906→/// Emits `ToolCallComplete` for any pending tool calls and a final `Done` with
907→/// accumulated usage.
908→pub fn finalize_responses_stream(state: &mut ResponsesStreamState) -> Vec<StreamEvent> {
909→    let mut events = Vec::new();
910→
911→    let mut pending: Vec<usize> = state.tool_calls.keys().copied().collect();
912→    pending.sort_unstable();
913→    for index in pending {
914→        if state.completed_tool_calls.insert(index) {
915→            events.push(StreamEvent::ToolCallComplete { index });
916→        }
917→    }
918→
919→    events.push(StreamEvent::Done(Usage {
920→        input_tokens: state.input_tokens,
921→        output_tokens: state.output_tokens,
922→        cache_read_tokens: state.cache_read_tokens,
923→        cache_write_tokens: state.cache_write_tokens,
924→    }));
925→
926→    events
927→}
