929→/// Parse a non-streaming Responses API JSON response into [`CompletionResponse`].
930→///
931→/// The Responses API returns an `output` array containing `message` items
932→/// (with `content[].text`) and `function_call` items (with `call_id`, `name`,
933→/// `arguments`).
934→pub fn parse_responses_completion(resp: &serde_json::Value) -> CompletionResponse {
935→    let mut text: Option<String> = None;
936→    let mut tool_calls: Vec<ToolCall> = Vec::new();
937→
938→    if let Some(output) = resp.get("output").and_then(|o| o.as_array()) {
939→        for item in output {
940→            match item["type"].as_str().unwrap_or("") {
941→                "message" => {
942→                    if let Some(content) = item.get("content").and_then(|c| c.as_array()) {
943→                        for part in content {
944→                            if part["type"].as_str() == Some("output_text")
945→                                && let Some(t) = part["text"].as_str()
946→                            {
947→                                text = Some(text.map_or_else(|| t.to_string(), |prev| prev + t));
948→                            }
949→                        }
950→                    }
951→                },
952→                "function_call" => {
953→                    let id = item["call_id"].as_str().unwrap_or("").to_string();
954→                    let name = item["name"].as_str().unwrap_or("").to_string();
955→                    let arguments = decode_tool_call_arguments(item.get("arguments"));
956→                    tool_calls.push(ToolCall {
957→                        id,
958→                        name,
959→                        arguments,
960→                    });
961→                },
962→                _ => {},
963→            }
964→        }
965→    }
966→
967→    let usage = resp
968→        .get("usage")
969→        .map(parse_openai_compat_usage)
970→        .unwrap_or_default();
971→
972→    CompletionResponse {
973→        text,
974→        tool_calls,
975→        usage,
976→    }
977→}
