  1→//! GraphQL mutation resolvers, organized by service namespace.
  2→//!
  3→//! Resolvers call domain services directly through the `Services` bundle —
  4→//! no RPC string-based dispatch or `ServiceCaller` indirection.
  5→
  6→use async_graphql::{Context, Object, Result};
  7→
  8→use crate::{
  9→    error::{from_service, from_service_json, gql_err, parse_err},
 10→    scalars::Json,
 11→    services,
 12→    types::{
 13→        BoolResult, McpOAuthStartResult, ModelTestResult, ProviderOAuthStartResult,
 14→        SessionShareResult, TranscriptionResult, TtsConvertResult,
 15→    },
 16→};
 17→
 18→/// Root mutation type composing all namespace mutations.
 19→#[derive(Default)]
 20→pub struct MutationRoot;
 21→
