122→
123→#[derive(Default)]
124→pub struct SystemMutation;
125→
126→#[Object]
127→impl SystemMutation {
128→    /// Broadcast a system event.
129→    async fn event(
130→        &self,
131→        ctx: &Context<'_>,
132→        event: String,
133→        payload: Option<Json>,
134→    ) -> Result<BoolResult> {
135→        // System events are gateway-level; return ok.
136→        let _ = (ctx, event, payload);
137→        from_service(Ok(serde_json::json!({ "ok": true })))
138→    }
139→
140→    /// Touch activity timestamp.
141→    async fn set_heartbeats(&self, ctx: &Context<'_>) -> Result<BoolResult> {
142→        let _ = ctx;
143→        from_service(Ok(serde_json::json!({ "ok": true })))
144→    }
145→
146→    /// Trigger wake functionality.
147→    async fn wake(&self, ctx: &Context<'_>) -> Result<BoolResult> {
148→        let s = services!(ctx);
149→        from_service(s.voicewake.wake(serde_json::json!({})).await)
150→    }
151→
152→    /// Set talk mode.
153→    async fn talk_mode(&self, ctx: &Context<'_>, mode: String) -> Result<BoolResult> {
154→        let s = services!(ctx);
155→        from_service(
156→            s.voicewake
157→                .talk_mode(serde_json::json!({ "mode": mode }))
158→                .await,
159→        )
160→    }
161→
162→    /// Check for and run updates.
163→    async fn update_run(&self, ctx: &Context<'_>) -> Result<BoolResult> {
164→        let s = services!(ctx);
165→        from_service(s.update.run(serde_json::json!({})).await)
166→    }
