182→// ── Shared helper functions ─────────────────────────────────────────────
183→
184→/// Sanitize a tool name from model output.
185→///
186→/// Handles quirks from various LLM providers:
187→/// 1. Trims whitespace
188→/// 2. Strips surrounding double quotes (some models quote tool names)
189→/// 3. Strips `functions_` prefix (OpenAI legacy artifact from some models)
190→/// 4. Strips trailing `_\d+` suffix (parallel-call indexing from some models,
191→///    e.g. Kimi K2.5 via OpenRouter sends `exec_2`, `browser_4`)
192→fn sanitize_tool_name(name: &str) -> Cow<'_, str> {
193→    let trimmed = name.trim();
194→    let unquoted = trimmed
195→        .strip_prefix('"')
196→        .and_then(|s| s.strip_suffix('"'))
197→        .unwrap_or(trimmed);
198→
199→    // Strip `functions_` prefix (OpenAI legacy artifact from some models).
200→    // INVARIANT: no registered tool name starts with "functions_".
201→    let without_prefix = unquoted.strip_prefix("functions_").unwrap_or(unquoted);
202→
203→    // Strip trailing `_\d+` suffix (parallel-call indexing from some models).
204→    // INVARIANT: no registered tool name ends with `_\d+` (a purely numeric segment after the last underscore).
205→    let cleaned = without_prefix
206→        .rfind('_')
207→        .and_then(|pos| {
208→            let suffix = &without_prefix[pos + 1..];
209→            if !suffix.is_empty() && suffix.bytes().all(|b| b.is_ascii_digit()) && pos > 0 {
210→                Some(&without_prefix[..pos])
211→            } else {
212→                None
213→            }
214→        })
215→        .unwrap_or(without_prefix);
216→
217→    if cleaned == name {
218→        Cow::Borrowed(name)
219→    } else {
220→        Cow::Owned(cleaned.to_string())
221→    }
222→}
