224→fn build_after_llm_call_payload(
225→    session_key: &str,
226→    provider: &str,
227→    model: &str,
228→    text: Option<String>,
229→    tool_calls: &[ToolCall],
230→    usage: &Usage,
231→    iteration: usize,
232→) -> HookPayload {
233→    let tool_calls = tool_calls
234→        .iter()
235→        .map(|tc| {
236→            serde_json::json!({
237→                "id": tc.id,
238→                "name": tc.name,
239→                "arguments": tc.arguments,
240→            })
241→        })
242→        .collect();
243→
244→    HookPayload::AfterLLMCall {
245→        session_key: session_key.to_string(),
246→        provider: provider.to_string(),
247→        model: model.to_string(),
248→        text,
249→        tool_calls,
250→        input_tokens: usage.input_tokens,
251→        output_tokens: usage.output_tokens,
252→        iteration,
253→    }
254→}
255→
256→pub(crate) async fn dispatch_after_llm_call_hook(
257→    hook_registry: Option<&std::sync::Arc<HookRegistry>>,
258→    session_key: &str,
259→    provider: &str,
260→    model: &str,
261→    text: Option<String>,
262→    tool_calls: &[ToolCall],
263→    usage: &Usage,
264→    iteration: usize,
265→) -> Result<(), AgentRunError> {
266→    let Some(hooks) = hook_registry else {
267→        return Ok(());
268→    };
269→
270→    let payload = build_after_llm_call_payload(
271→        session_key,
272→        provider,
273→        model,
274→        text,
275→        tool_calls,
276→        usage,
277→        iteration,
278→    );
279→
280→    match hooks.dispatch(&payload).await {
281→        Ok(HookAction::Block(reason)) => {
282→            warn!(reason = %reason, "LLM response blocked by AfterLLMCall hook");
283→            Err(AgentRunError::Other(anyhow::anyhow!(
284→                "blocked by AfterLLMCall hook: {reason}"
285→            )))
286→        },
287→        Ok(HookAction::ModifyPayload(_)) => {
288→            tracing::debug!("AfterLLMCall ModifyPayload ignored (response is typed)");
289→            Ok(())
290→        },
291→        Ok(HookAction::Continue) => Ok(()),
292→        Err(e) => {
293→            warn!(error = %e, "AfterLLMCall hook dispatch failed");
294→            Ok(())
295→        },
296→    }
297→}
