336→/// Detect an explicit shell command in the latest user turn.
337→///
338→/// Only `/sh ...` commands are treated as explicit shell execution requests.
339→/// This keeps normal chat turns (`hey`, `hello`, etc.) out of the forced-exec path.
340→///
341→/// Supported forms:
342→/// - `/sh pwd`
343→/// - `/sh@mybot uname -a`
344→fn explicit_shell_command_from_user_content(user_content: &UserContent) -> Option<String> {
345→    let text = match user_content {
346→        UserContent::Text(text) => text.trim(),
347→        UserContent::Multimodal(_) => return None,
348→    };
349→
350→    if text.is_empty() || text.len() > 4096 || text.contains('\n') || text.contains('\r') {
351→        return None;
352→    }
353→
354→    let rest = text.strip_prefix('/')?;
355→    let split_idx = rest.find(char::is_whitespace)?;
356→    let head = &rest[..split_idx];
357→    let command = rest[split_idx..].trim_start();
358→    if command.is_empty() {
359→        return None;
360→    }
361→
362→    let head_lower = head.to_ascii_lowercase();
363→    let is_sh_prefix = if head_lower == "sh" {
364→        true
365→    } else {
366→        head_lower
367→            .strip_prefix("sh@")
368→            .is_some_and(|mention| !mention.is_empty())
369→    };
370→
371→    if !is_sh_prefix {
372→        return None;
373→    }
374→
375→    Some(command.to_string())
376→}
