437→#[must_use]
438→fn estimate_message_tokens(message: &ChatMessage) -> usize {
439→    estimate_prompt_text_tokens(&message.to_openai_value().to_string())
440→}
441→
442→#[must_use]
443→fn estimate_prompt_tokens(messages: &[ChatMessage], tool_schemas: &[serde_json::Value]) -> usize {
444→    let message_tokens: usize = messages.iter().map(estimate_message_tokens).sum();
445→    let tool_tokens: usize = tool_schemas
446→        .iter()
447→        .map(|schema| estimate_prompt_text_tokens(&schema.to_string()))
448→        .sum();
449→    message_tokens.saturating_add(tool_tokens)
450→}
