562→/// Consume the detector's post-batch action (if any) and apply it to the
563→/// runner state: push the directive user message into `messages`, emit the
564→/// `LoopInterventionFired` UI event, and set `strip_tools_next_iter` when
565→/// stage 2 fires. Shared by the streaming and non-streaming loops (issue
566→/// #658).
567→fn apply_loop_detector_intervention(
568→    loop_detector: &mut ToolLoopDetector,
569→    messages: &mut Vec<ChatMessage>,
570→    strip_tools_next_iter: &mut bool,
571→    on_event: Option<&OnEvent>,
572→) {
573→    if !loop_detector.is_enabled() {
574→        return;
575→    }
576→    match loop_detector.consume_pending_action() {
577→        LoopDetectorAction::None => {},
578→        LoopDetectorAction::InjectNudge => {
579→            let window = loop_detector.window_snapshot();
580→            let stuck_tool = window
581→                .first()
582→                .map(|fp| fp.tool_name.clone())
583→                .unwrap_or_default();
584→            let intervention = format_intervention_message(&window);
585→            info!(
586→                tool = %stuck_tool,
587→                "loop detector fired (stage 1): injecting directive intervention"
588→            );
589→            if let Some(cb) = on_event {
590→                cb(RunnerEvent::LoopInterventionFired {
591→                    stage: 1,
592→                    tool_name: stuck_tool,
593→                });
594→            }
595→            messages.push(ChatMessage::user(intervention));
596→        },
597→        LoopDetectorAction::StripTools => {
598→            let stuck_tool = loop_detector
599→                .window_snapshot()
600→                .first()
601→                .map(|fp| fp.tool_name.clone())
602→                .unwrap_or_default();
603→            info!(
604→                tool = %stuck_tool,
605→                "loop detector fired (stage 2): stripping tools for next iteration"
606→            );
607→            if let Some(cb) = on_event {
608→                cb(RunnerEvent::LoopInterventionFired {
609→                    stage: 2,
610→                    tool_name: stuck_tool,
611→                });
612→            }
613→            messages.push(ChatMessage::user(format_strip_tools_message()));
614→            *strip_tools_next_iter = true;
615→        },
616→    }
617→}
