195→pub(crate) async fn persist_tool_history_pair(
196→    session_store: &Arc<SessionStore>,
197→    session_key: &str,
198→    assistant_tool_call_msg: PersistedMessage,
199→    tool_result_msg: PersistedMessage,
200→    assistant_warn_context: &str,
201→    tool_result_warn_context: &str,
202→) {
203→    if let Err(e) = session_store
204→        .append(session_key, &assistant_tool_call_msg.to_value())
205→        .await
206→    {
207→        warn!("{assistant_warn_context}: {e}");
208→        warn!(
209→            session = %session_key,
210→            "skipping tool result persistence to avoid orphaned tool history"
211→        );
212→        return;
213→    }
214→
215→    if let Err(e) = session_store
216→        .append(session_key, &tool_result_msg.to_value())
217→        .await
218→    {
219→        warn!("{tool_result_warn_context}: {e}");
220→    }
221→}
