350→    async fn abort_run_handle(
351→        active_runs: &Arc<RwLock<HashMap<String, AbortHandle>>>,
352→        active_runs_by_session: &Arc<RwLock<HashMap<String, String>>>,
353→        terminal_runs: &Arc<RwLock<HashSet<String>>>,
354→        run_id: Option<&str>,
355→        session_key: Option<&str>,
356→    ) -> (Option<String>, bool) {
357→        let resolved_run_id = if let Some(id) = run_id {
358→            Some(id.to_string())
359→        } else if let Some(key) = session_key {
360→            active_runs_by_session.read().await.get(key).cloned()
361→        } else {
362→            None
363→        };
364→
365→        let Some(target_run_id) = resolved_run_id.clone() else {
366→            return (None, false);
367→        };
368→
369→        if terminal_runs.read().await.contains(&target_run_id) {
370→            return (resolved_run_id, false);
371→        }
372→
373→        let aborted = if let Some(handle) = active_runs.write().await.remove(&target_run_id) {
374→            handle.abort();
375→            true
376→        } else {
377→            false
378→        };
379→
380→        let mut by_session = active_runs_by_session.write().await;
381→        if let Some(key) = session_key
382→            && by_session.get(key).is_some_and(|id| id == &target_run_id)
383→        {
384→            by_session.remove(key);
385→        }
386→        by_session.retain(|_, id| id != &target_run_id);
387→
388→        (resolved_run_id, aborted)
389→    }
