498→    /// Resolve the effective session key for chat operations.
499→    ///
500→    /// Precedence is:
501→    /// 1. Internal `_session_key` overrides used by runtime-owned callers.
502→    /// 2. Public `sessionKey` / `session_key` request parameters.
503→    /// 3. Connection-scoped active session derived from `_conn_id`.
504→    /// 4. The default `"main"` session.
505→    async fn resolve_session_key_from_params(&self, params: &Value) -> String {
506→        if let Some(session_key) = params
507→            .get("_session_key")
508→            .and_then(|v| v.as_str())
509→            .filter(|v| !v.is_empty())
510→        {
511→            return session_key.to_string();
512→        }
513→        if let Some(session_key) = params
514→            .get("sessionKey")
515→            .or_else(|| params.get("session_key"))
516→            .and_then(|v| v.as_str())
517→            .filter(|v| !v.is_empty())
518→        {
519→            return session_key.to_string();
520→        }
521→        let conn_id = params.get("_conn_id").and_then(|v| v.as_str());
522→        self.session_key_for(conn_id).await
523→    }
