243→
244→    fn is_provider_configured(
245→        &self,
246→        provider: &KnownProvider,
247→        active_config: &ProvidersConfig,
248→    ) -> bool {
249→        // Disabled providers (by offered allowlist or explicit enabled=false)
250→        // should not show as configured, except subscription-backed OAuth
251→        // providers with valid local tokens.
252→        if !active_config.is_enabled(provider.name) {
253→            let subscription_with_tokens =
254→                matches!(provider.name, "openai-codex" | "github-copilot")
255→                    && active_config
256→                        .get(provider.name)
257→                        .is_none_or(|entry| entry.enabled)
258→                    && has_oauth_tokens(provider.name, &self.token_store);
259→            if !subscription_with_tokens {
260→                return false;
261→            }
262→        }
263→
264→        // Check if the provider has an API key set via env
265→        if let Some(env_key) = provider.env_key
266→            && env_value_with_overrides(&self.env_overrides, env_key).is_some()
267→        {
268→            return true;
269→        }
270→        if provider.auth_type == AuthType::ApiKey
271→            && moltis_config::generic_provider_api_key_from_env(provider.name, &self.env_overrides)
272→                .is_some()
273→        {
274→            return true;
275→        }
276→        // Check config file
277→        if let Some(entry) = active_config.get(provider.name)
278→            && entry
279→                .api_key
280→                .as_ref()
281→                .is_some_and(|k| !k.expose_secret().is_empty())
282→        {
283→            return true;
284→        }
285→        // Check home/global config file as fallback when using custom config dir.
286→        if home_provider_config()
287→            .as_ref()
288→            .and_then(|(cfg, _)| cfg.get(provider.name))
289→            .and_then(|entry| entry.api_key.as_ref())
290→            .is_some_and(|k| !k.expose_secret().is_empty())
291→        {
292→            return true;
293→        }
294→        // Check persisted key store
295→        if self.key_store.load(provider.name).is_some() {
296→            return true;
297→        }
298→        // Check persisted key store in user-global config dir.
299→        if home_key_store()
300→            .as_ref()
301→            .is_some_and(|(store, _)| store.load(provider.name).is_some())
302→        {
303→            return true;
304→        }
305→        // For OAuth providers, check token store
306→        if provider.auth_type == AuthType::Oauth || provider.name == "kimi-code" {
307→            if self.token_store.load(provider.name).is_some() {
308→                return true;
309→            }
310→            if home_token_store()
311→                .as_ref()
312→                .is_some_and(|(store, _)| store.load(provider.name).is_some())
313→            {
314→                return true;
315→            }
316→            // Match provider-registry behavior: openai-codex may be inferred from
317→            // Codex CLI auth at ~/.codex/auth.json.
318→            if provider.name == "openai-codex"
319→                && crate::oauth::codex_cli_auth_path()
320→                    .as_deref()
321→                    .is_some_and(crate::oauth::codex_cli_auth_has_access_token)
322→            {
323→                return true;
324→            }
325→            return false;
326→        }
327→        // For local providers, check if model is configured in local_llm config
328→        #[cfg(feature = "local-llm")]
329→        if provider.auth_type == AuthType::Local && provider.name == "local-llm" {
330→            // Check if local-llm model config file exists
331→            if let Some(config_dir) = moltis_config::config_dir() {
332→                let config_path = config_dir.join("local-llm.json");
333→                return config_path.exists();
334→            }
335→        }
336→        false
337→    }
