 33→            FsPathPolicy, FsState, MAX_READ_OUTPUT_BYTES, READ_LOOP_THRESHOLD,
 34→            compute_adaptive_read_cap, enforce_path_policy, format_numbered_lines_with_cap,
 35→            fs_error_payload, io_error_to_typed_payload, is_binary_extension, looks_binary,
