 43→
 44→struct TextReadPage {
 45→    content: String,
 46→    total_lines: usize,
 47→    start_line: usize,
 48→    rendered_lines: usize,
 49→    truncated: bool,
 50→}
 51→
 52→fn next_offset_for_text_read(
 53→    start_line: usize,
 54→    rendered_lines: usize,
 55→    total_lines: usize,
 56→    truncated: bool,
 57→) -> Option<usize> {
 58→    if !truncated || rendered_lines == 0 {
 59→        return None;
 60→    }
 61→
 62→    let next_offset = start_line.saturating_add(rendered_lines);
 63→    (next_offset <= total_lines).then_some(next_offset)
 64→}
 65→
 66→fn text_payload(
 67→    file_path: &str,
 68→    content: String,
 69→    total_lines: usize,
 70→    start_line: usize,
 71→    rendered_lines: usize,
 72→    truncated: bool,
 73→) -> Value {
 74→    let mut payload = Map::from_iter([
 75→        ("kind".to_string(), json!("text")),
 76→        ("file_path".to_string(), json!(file_path)),
 77→        ("content".to_string(), json!(content)),
 78→        ("total_lines".to_string(), json!(total_lines)),
 79→        ("start_line".to_string(), json!(start_line)),
 80→        ("rendered_lines".to_string(), json!(rendered_lines)),
 81→        ("truncated".to_string(), json!(truncated)),
 82→    ]);
 83→
 84→    if let Some(next_offset) =
 85→        next_offset_for_text_read(start_line, rendered_lines, total_lines, truncated)
 86→    {
 87→        payload.insert("next_offset".to_string(), json!(next_offset));
 88→        payload.insert(
 89→            "continuation_hint".to_string(),
 90→            json!(format!(
 91→                "File output was truncated. Re-run Read with offset={next_offset} to continue."
 92→            )),
 93→        );
 94→    }
 95→
 96→    Value::Object(payload)
 97→}
 98→
 99→fn maybe_add_loop_warning(
100→    fs_state: Option<&FsState>,
101→    payload: &mut Value,
102→    file_path: &str,
103→    offset: usize,
104→    limit: usize,
105→    session_key: &str,
106→) {
107→    let Some(state) = fs_state else {
108→        return;
109→    };
110→    let guard = state
111→        .lock()
112→        .unwrap_or_else(|poisoned| poisoned.into_inner());
113→    let n = guard.consecutive_reads(session_key);
114→    if n >= READ_LOOP_THRESHOLD
115→        && let Some(obj) = payload.as_object_mut()
116→    {
117→        obj.insert(
118→            "loop_warning".into(),
119→            json!(format!(
120→                "This exact read (file_path={file_path}, offset={offset}, limit={limit}) \
121→                 has been repeated {n} times with no intervening edit. The \
122→                 file hasn't changed — stop re-reading it and make progress on the task."
123→            )),
124→        );
125→    }
126→}
