128→/// Native `Read` tool implementation.
129→#[derive(Default)]
130→pub struct ReadTool {
131→    fs_state: Option<FsState>,
132→    path_policy: Option<FsPathPolicy>,
133→    binary_policy: BinaryPolicy,
134→    sandbox_router: Option<Arc<SandboxRouter>>,
135→    /// Override for the file-size gate. `None` → `DEFAULT_MAX_READ_BYTES`.
136→    max_read_bytes: Option<u64>,
137→    /// Optional context window in tokens. When set, Read's byte cap
138→    /// scales adaptively with the model's working set
139→    /// (`ctx * 4 chars * 0.2`, clamped to `[50 KB, 512 KB]`).
140→    context_window_tokens: Option<u64>,
141→}
142→
143→impl ReadTool {
144→    #[must_use]
145→    pub fn new() -> Self {
146→        Self::default()
147→    }
148→
149→    /// Attach a shared [`FsState`] for per-session read tracking and
150→    /// re-read loop detection.
151→    #[must_use]
152→    pub fn with_fs_state(mut self, state: FsState) -> Self {
153→        self.fs_state = Some(state);
154→        self
155→    }
156→
157→    /// Attach an allow/deny path policy.
158→    #[must_use]
159→    pub fn with_path_policy(mut self, policy: FsPathPolicy) -> Self {
160→        self.path_policy = Some(policy);
161→        self
162→    }
163→
164→    /// Override the binary-file handling policy. Default is
165→    /// [`BinaryPolicy::Reject`] which returns a typed marker without
166→    /// content.
167→    #[must_use]
168→    pub fn with_binary_policy(mut self, policy: BinaryPolicy) -> Self {
169→        self.binary_policy = policy;
170→        self
171→    }
172→
173→    /// Attach a shared [`SandboxRouter`]. When the router marks a
174→    /// session as sandboxed, Read dispatches through the bridge
175→    /// instead of touching the host filesystem.
176→    #[must_use]
177→    pub fn with_sandbox_router(mut self, router: Arc<SandboxRouter>) -> Self {
178→        self.sandbox_router = Some(router);
179→        self
180→    }
181→
182→    /// Override the maximum file size `Read` will accept. Larger files
183→    /// return a typed `too_large` payload. Wired from
184→    /// `[tools.fs].max_read_bytes`. Default: `DEFAULT_MAX_READ_BYTES`.
185→    #[must_use]
186→    pub fn with_max_read_bytes(mut self, max: u64) -> Self {
187→        self.max_read_bytes = Some(max);
188→        self
189→    }
190→
191→    /// Configure the model context window in tokens. Enables the
192→    /// adaptive byte cap so per-Read payloads scale with the model's
193→    /// working set instead of using a fixed ceiling.
194→    #[must_use]
195→    pub fn with_context_window_tokens(mut self, tokens: u64) -> Self {
196→        self.context_window_tokens = Some(tokens);
197→        self
198→    }
199→
200→    /// Effective file-size cap: config override or default.
201→    fn effective_max_read_bytes(&self) -> u64 {
202→        self.max_read_bytes.unwrap_or(DEFAULT_MAX_READ_BYTES)
203→    }
204→
205→    fn effective_render_byte_cap(&self) -> usize {
206→        self.context_window_tokens
207→            .map(compute_adaptive_read_cap)
208→            .unwrap_or(MAX_READ_OUTPUT_BYTES)
209→    }
210→
211→    #[instrument(skip(self), fields(file_path = %file_path))]
212→    async fn read_impl(
213→        &self,
214→        file_path: &str,
215→        offset: usize,
216→        limit: usize,
217→        session_key: &str,
218→    ) -> Result<Value> {
219→        require_absolute(file_path, "file_path")?;
220→
221→        // Sandbox dispatch: if the session is sandboxed, round-trip through
222→        // the bridge and render the resulting bytes with the same logic as
223→        // the host path. Path-policy and binary detection still run on
224→        // host-side types, so both paths look identical to the LLM.
225→        if let Some(ref router) = self.sandbox_router
226→            && router.is_sandboxed(session_key).await
227→        {
228→            if let Some(ref policy) = self.path_policy
229→                && let Some(payload) = enforce_path_policy(policy, Path::new(file_path))
230→            {
231→                return Ok(payload);
232→            }
233→            let max = self.effective_max_read_bytes();
234→            let sandbox_fs = sandbox_file_system_for_session(router, session_key).await?;
235→            let result = sandbox_fs.read_file(file_path, max).await?;
236→            match result {
237→                SandboxReadResult::Ok(bytes) => {
238→                    return Ok(self.render_bytes_to_payload(
239→                        file_path,
240→                        offset,
241→                        limit,
242→                        &bytes,
243→                        session_key,
244→                        true,
245→                        None, // sandbox mtime unavailable
246→                    ));
247→                },
248→                other => {
249→                    return Ok(other
250→                        .into_typed_payload(file_path, max)
251→                        .unwrap_or(json!({})));
252→                },
253→            }
254→        }
255→
256→        // Stat first so we can surface not_found / permission_denied as
257→        // typed Ok payloads rather than Err strings. The chat loop strips
258→        // Err detail via err.to_string(); typed payloads survive as JSON.
259→        let meta = match fs::metadata(file_path).await {
260→            Ok(m) => m,
261→            Err(e) => {
262→                if let Some(payload) = io_error_to_typed_payload(&e, file_path) {
263→                    return Ok(payload);
264→                }
265→                return Err(Error::message(format!("cannot stat '{file_path}': {e}")));
266→            },
267→        };
268→
269→        if !meta.is_file() {
270→            return Ok(fs_error_payload(
271→                FsErrorKind::NotRegularFile,
272→                file_path,
273→                "path is not a regular file",
274→                None,
275→            ));
276→        }
277→
278→        // Path policy check: canonicalize first so allowlist globs evaluate
279→        // against the resolved path, not whatever the LLM supplied.
280→        if let Some(ref policy) = self.path_policy {
281→            let canonical = fs::canonicalize(file_path)
282→                .await
283→                .unwrap_or_else(|_| std::path::PathBuf::from(file_path));
284→            if let Some(payload) = enforce_path_policy(policy, &canonical) {
285→                return Ok(payload);
286→            }
287→        }
288→
289→        let size = meta.len();
290→        let max_read = self.effective_max_read_bytes();
291→        if size > max_read {
292→            return Ok(json!({
293→                "kind": FsErrorKind::TooLarge.as_str(),
294→                "file_path": file_path,
295→                "error": format!(
296→                    "file is too large ({:.1} MB) — maximum is {:.0} MB",
297→                    size as f64 / (1024.0 * 1024.0),
298→                    max_read as f64 / (1024.0 * 1024.0),
299→                ),
300→                "bytes": size,
301→                "max_bytes": max_read,
302→            }));
303→        }
304→
305→        let bytes = match fs::read(file_path).await {
306→            Ok(b) => b,
307→            Err(e) => {
308→                if let Some(payload) = io_error_to_typed_payload(&e, file_path) {
309→                    return Ok(payload);
310→                }
311→                return Err(Error::message(format!("failed to read '{file_path}': {e}")));
312→            },
313→        };
314→
315→        let mtime = meta.modified().ok();
316→        Ok(self.render_bytes_to_payload(
317→            file_path,
318→            offset,
319→            limit,
320→            &bytes,
321→            session_key,
322→            false,
323→            mtime,
324→        ))
325→    }
326→
327→    fn parse_text_page(payload: &Value) -> Option<TextReadPage> {
328→        if payload.get("kind").and_then(Value::as_str) != Some("text") {
329→            return None;
330→        }
331→        Some(TextReadPage {
332→            content: payload.get("content")?.as_str()?.to_string(),
333→            total_lines: payload.get("total_lines")?.as_u64()? as usize,
334→            start_line: payload.get("start_line")?.as_u64()? as usize,
335→            rendered_lines: payload.get("rendered_lines")?.as_u64()? as usize,
336→            truncated: payload.get("truncated")?.as_bool()?,
337→        })
338→    }
339→
340→    async fn read_with_auto_paging(
341→        &self,
342→        file_path: &str,
343→        offset: usize,
344→        page_limit: usize,
345→        session_key: &str,
346→    ) -> Result<Value> {
347→        let max_bytes = self.effective_render_byte_cap();
348→        let mut next_offset = offset;
349→        let mut aggregated_content = String::new();
350→        let mut aggregated_bytes = 0usize;
351→        let mut rendered_lines_total = 0usize;
352→        let mut total_lines = 0usize;
353→        let mut start_line = offset;
354→        let mut truncated = false;
355→
356→        for page_index in 0..MAX_AUTO_PAGED_READS {
357→            let payload = self
358→                .read_impl(file_path, next_offset, page_limit, session_key)
359→                .await?;
360→            let Some(page) = Self::parse_text_page(&payload) else {
361→                return Ok(payload);
362→            };
363→
364→            if page_index == 0 {
365→                total_lines = page.total_lines;
366→                start_line = page.start_line;
367→            }
368→
369→            let page_bytes = page.content.len();
370→            if !aggregated_content.is_empty()
371→                && aggregated_bytes.saturating_add(page_bytes) > max_bytes
372→            {
373→                truncated = true;
374→                break;
375→            }
376→
377→            aggregated_bytes = aggregated_bytes.saturating_add(page_bytes);
378→            aggregated_content.push_str(&page.content);
379→            rendered_lines_total = rendered_lines_total.saturating_add(page.rendered_lines);
380→
381→            if !page.truncated {
382→                truncated = false;
383→                break;
384→            }
385→
386→            let candidate_next_offset = page.start_line.saturating_add(page.rendered_lines);
387→            if page.rendered_lines == 0
388→                || candidate_next_offset > page.total_lines
389→                || page_index == MAX_AUTO_PAGED_READS - 1
390→            {
391→                truncated = true;
392→                break;
393→            }
394→
395→            next_offset = candidate_next_offset;
396→
397→            if aggregated_bytes >= max_bytes {
398→                truncated = true;
399→                break;
400→            }
401→        }
402→
403→        let mut payload = text_payload(
404→            file_path,
405→            aggregated_content,
406→            total_lines,
407→            start_line,
408→            rendered_lines_total,
409→            truncated,
410→        );
411→        maybe_add_loop_warning(
412→            self.fs_state.as_ref(),
413→            &mut payload,
414→            file_path,
415→            offset,
416→            page_limit,
417→            session_key,
418→        );
419→        Ok(payload)
420→    }
421→
422→    /// Render raw file bytes into the typed Read payload.
423→    ///
424→    /// Shared by the host and sandbox branches so the LLM-facing shape
425→    /// is identical across routing modes. `from_sandbox` controls the
426→    /// loop-tracker key (canonicalize is a no-op against sandbox paths
427→    /// since the LLM-supplied string is already absolute and untouched).
428→    fn render_bytes_to_payload(
429→        &self,
430→        file_path: &str,
431→        offset: usize,
432→        limit: usize,
433→        bytes: &[u8],
434→        session_key: &str,
435→        from_sandbox: bool,
436→        mtime: Option<std::time::SystemTime>,
437→    ) -> Value {
438→        // Record the read in the tracker BEFORE any early return (including
439→        // binary). An operator with must_read_before_write + binary_policy=base64
440→        // needs binary Reads to count as "this session has read the file."
441→        if let Some(ref state) = self.fs_state {
442→            let tracker_path = if from_sandbox {
443→                std::path::PathBuf::from(file_path)
444→            } else {
445→                std::fs::canonicalize(file_path)
446→                    .unwrap_or_else(|_| std::path::PathBuf::from(file_path))
447→            };
448→            let mut guard = state
449→                .lock()
450→                .unwrap_or_else(|poisoned| poisoned.into_inner());
451→            let _consecutive = guard.record_read(session_key, tracker_path, offset, limit, mtime);
452→        }
453→
454→        if is_binary_extension(file_path) || looks_binary(bytes) {
455→            #[cfg(feature = "metrics")]
456→            counter!(
457→                tools_metrics::EXECUTIONS_TOTAL,
458→                labels::TOOL => "Read".to_string(),
459→                labels::SUCCESS => "binary".to_string()
460→            )
461→            .increment(1);
462→            return match self.binary_policy {
463→                BinaryPolicy::Reject => json!({
464→                    "kind": "binary",
465→                    "file_path": file_path,
466→                    "bytes": bytes.len(),
467→                    "message": "file appears to be binary; content not returned (binary_policy = reject)",
468→                }),
469→                BinaryPolicy::Base64 => {
470→                    use base64::{Engine as _, engine::general_purpose::STANDARD as BASE64};
471→                    json!({
472→                        "kind": "binary",
473→                        "file_path": file_path,
474→                        "bytes": bytes.len(),
475→                        "base64": BASE64.encode(bytes),
476→                    })
477→                },
478→            };
479→        }
480→
481→        // Lossy decode so we never fail on invalid UTF-8 — surface
482→        // whatever the LLM can see and let it decide.
483→        let text = String::from_utf8(bytes.to_vec()).unwrap_or_else(|e| {
484→            let bytes = e.into_bytes();
485→            String::from_utf8_lossy(&bytes).into_owned()
486→        });
487→
488→        // Adaptive byte cap: when the operator has told us the model's
489→        // context window, scale per-call output so Read can't consume
490→        // more than ~20% of the model's working set. Otherwise fall
491→        // back to the fixed default.
492→        let byte_cap = self.effective_render_byte_cap();
493→        let rendered = format_numbered_lines_with_cap(&text, offset, limit, byte_cap);
494→
495→        #[cfg(feature = "metrics")]
496→        counter!(
497→            tools_metrics::EXECUTIONS_TOTAL,
498→            labels::TOOL => "Read".to_string(),
499→            labels::SUCCESS => "true".to_string()
500→        )

