 529→#[async_trait]
 530→impl AgentTool for ReadTool {
 531→    fn name(&self) -> &str {
 532→        "Read"
 533→    }
 534→
 535→    fn description(&self) -> &str {
 536→        "Read a file from the local filesystem with line-numbered output. \
 537→         Supports `offset` (1-indexed line to start at) and `limit` (max lines \
 538→         to return) for paginating large files. Returns structured JSON with \
 539→         the file's content, total line count, and truncation flag. Binary \
 540→         files return a typed marker instead of garbage."
 541→    }
 542→
 543→    fn parameters_schema(&self) -> Value {
 544→        json!({
 545→            "type": "object",
 546→            "required": ["file_path"],
 547→            "properties": {
 548→                "file_path": {
 549→                    "type": "string",
 550→                    "description": "Absolute path to the file to read."
 551→                },
 552→                "offset": {
 553→                    "type": "integer",
 554→                    "minimum": 1,
 555→                    "description": "1-indexed line number to start reading from."
 556→                },
 557→                "limit": {
 558→                    "type": "integer",
 559→                    "minimum": 1,
 560→                    "description": "Maximum number of lines to return (default 2000)."
 561→                },
 562→                "pages": {
 563→                    "type": "string",
 564→                    "description": "Page range for PDF files (e.g. '1-5', '3', '10-20'). Only applicable to .pdf files. Maximum 20 pages per request."
 565→                }
 566→            }
 567→        })
 568→    }
 569→
 570→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
 571→        let file_path = params
 572→            .get("file_path")
 573→            .and_then(Value::as_str)
 574→            .ok_or_else(|| Error::message("missing 'file_path' parameter"))?;
 575→        let explicit_offset = params.get("offset").is_some();
 576→        let explicit_limit = params.get("limit").is_some();
 577→        let offset = params
 578→            .get("offset")
 579→            .and_then(Value::as_u64)
 580→            .map(|v| v as usize)
 581→            .unwrap_or(1)
 582→            .max(1);
 583→        let limit = params
 584→            .get("limit")
 585→            .and_then(Value::as_u64)
 586→            .map(|v| v as usize)
 587→            .unwrap_or(DEFAULT_READ_LINE_LIMIT)
 588→            .max(1);
 589→        let pages = params
 590→            .get("pages")
 591→            .and_then(Value::as_str)
 592→            .map(str::to_string);
 593→        let session_key = session_key_from(&params).to_string();
 594→
 595→        let lower = file_path.to_ascii_lowercase();
 596→        let is_special = lower.ends_with(".pdf") || is_image_extension(&lower);
 597→
 598→        // PDF and image dispatches bypass read_impl, so the three
 599→        // gates that live inside read_impl must run here first:
 600→        //  1. Path policy
 601→        //  2. Sandbox routing (PDF/image extraction is host-only for
 602→        //     now — return a typed payload if sandboxed)
 603→        //  3. FsState read recording (so must-read-before-write works)
 604→        if is_special {
 605→            if let Some(ref policy) = self.path_policy {
 606→                let p = Path::new(file_path);
 607→                let canonical = fs::canonicalize(p)
 608→                    .await
 609→                    .unwrap_or_else(|_| p.to_path_buf());
 610→                if let Some(payload) = enforce_path_policy(policy, &canonical) {
 611→                    return Ok(payload);
 612→                }
 613→            }
 614→            if let Some(ref router) = self.sandbox_router
 615→                && router.is_sandboxed(&session_key).await
 616→            {
 617→                // PDF extraction and image resize run host-side; we
 618→                // can't invoke them inside a container. Return a clear
 619→                // typed payload so the LLM knows to fall back to the
 620→                // raw binary Read path.
 621→                return Ok(json!({
 622→                    "kind": "unsupported_in_sandbox",
 623→                    "file_path": file_path,
 624→                    "error": "PDF and image processing is not available for sandboxed sessions. \
 625→                              Use Read without a .pdf/.png/.jpg extension or access the file \
 626→                              from a non-sandboxed session.",
 627→                }));
 628→            }
 629→            // Record in FsState so must-read-before-write passes for
 630→            // subsequent writes to this path.
 631→            if let Some(ref state) = self.fs_state {
 632→                let canonical = fs::canonicalize(file_path)
 633→                    .await
 634→                    .unwrap_or_else(|_| std::path::PathBuf::from(file_path));
 635→                let mtime = fs::metadata(file_path)
 636→                    .await
 637→                    .ok()
 638→                    .and_then(|m| m.modified().ok());
 639→                let mut guard = state
 640→                    .lock()
 641→                    .unwrap_or_else(|poisoned| poisoned.into_inner());
 642→                guard.record_read(&session_key, canonical, offset, limit, mtime);
 643→            }
 644→        }
 645→
 646→        // PDF dispatch.
 647→        if lower.ends_with(".pdf") {
 648→            return match read_pdf(file_path, pages.as_deref()).await {
 649→                Ok(value) => Ok(value),
 650→                Err(e) => {
 651→                    #[cfg(feature = "metrics")]
 652→                    counter!(
 653→                        tools_metrics::EXECUTION_ERRORS_TOTAL,
 654→                        labels::TOOL => "Read".to_string()
 655→                    )
 656→                    .increment(1);
 657→                    Err(e.into())
 658→                },
 659→            };
 660→        }
 661→
 662→        // Image dispatch.
 663→        if is_image_extension(&lower) {
 664→            return match image::read_image(file_path).await {
 665→                Ok(value) => Ok(value),
 666→                Err(e) => {
 667→                    #[cfg(feature = "metrics")]
 668→                    counter!(
 669→                        tools_metrics::EXECUTION_ERRORS_TOTAL,
 670→                        labels::TOOL => "Read".to_string()
 671→                    )
 672→                    .increment(1);
 673→                    Err(e.into())
 674→                },
 675→            };
 676→        }
 677→
 678→        let should_auto_page = !explicit_limit && !explicit_offset;
 679→        let result = if should_auto_page {
 680→            self.read_with_auto_paging(file_path, offset, limit, &session_key)
 681→                .await
 682→        } else {
 683→            self.read_impl(file_path, offset, limit, &session_key).await
 684→        };
 685→
 686→        match result {
