            ),
            channel: None,
        };
        let rt = tokio::runtime::Builder::new_current_thread()
            .build()
            .expect("runtime");
        let resp = rt.block_on(reg.dispatch(ctx));
        assert!(!resp.ok);
        assert_eq!(
            resp.error.as_ref().map(|e| e.message.as_str()),
            Some("invalid 'request_timeout_secs' parameter: expected a positive integer")
        );
    }

